{
  "name": "Korea University Contract Dashboard",
  "description": "A high-end data visualization dashboard mapping university educational contracts across South Korea using Google Maps API."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface UniversityData {
  school_id: string;
  school_name: string;
  region: string;
  address: string;
  lat: number;
  lng: number;
  amount_sum: number;
}

export enum Region {
  SUDO = '수도권',
  CHUNGCHEONG = '충청권',
  DAEGYEONG = '대경권',
  HONAM = '호남권',
  DONGNAM = '동남권',
  GANGWON = '강원권',
  JEJU = '제주권',
  ETC = '기타/미정'
}

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { MOCK_DATA, REGION_COLORS } from './constants';
import { UniversityData } from './types';

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const googleMap = useRef<google.maps.Map | null>(null);
  const [selectedUniversity, setSelectedUniversity] = useState<UniversityData | null>(null);

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency',
      currency: 'KRW',
    }).format(amount);
  };

  const calculateRadius = (amount: number) => {
    const logValue = Math.log10(amount);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const initMap = useCallback(() => {
    if (!mapRef.current) return;

    const center = { lat: 36.3504, lng: 127.3845 }; // Daejeon center
    const map = new google.maps.Map(mapRef.current, {
      center: center,
      zoom: 7.5,
      mapId: 'DEMO_MAP_ID',
      disableDefaultUI: false,
      zoomControl: true,
      mapTypeControl: false,
      streetViewControl: false,
      styles: [
        {
          featureType: "all",
          elementType: "labels.text.fill",
          stylers: [{ color: "#616161" }]
        }
      ]
    });

    googleMap.current = map;

    const infoWindow = new google.maps.InfoWindow();

    MOCK_DATA.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS['기타/미정'];
      const radius = calculateRadius(univ.amount_sum);

      const marker = new google.maps.Circle({
        strokeColor: color,
        strokeOpacity: 0.8,
        strokeWeight: 2,
        fillColor: color,
        fillOpacity: 0.35,
        map: map,
        center: { lat: univ.lat, lng: univ.lng },
        radius: radius * 500, // Multiplied for geographic scale visualization
        clickable: true
      });

      marker.addListener('click', () => {
        const content = `
          <div class="p-2">
            <h3 class="text-lg font-bold text-slate-800">${univ.school_name}</h3>
            <p class="text-sm text-slate-500 mb-2">${univ.region} | ${univ.address}</p>
            <div class="mt-2 pt-2 border-t border-slate-100">
              <span class="text-xs text-slate-400 block">총 계약금액</span>
              <span class="text-md font-semibold text-blue-600">${formatCurrency(univ.amount_sum)}</span>
            </div>
          </div>
        `;
        infoWindow.setContent(content);
        infoWindow.setPosition({ lat: univ.lat, lng: univ.lng });
        infoWindow.open(map);
        setSelectedUniversity(univ);
      });
    });
  }, []);

  useEffect(() => {
    initMap();
  }, [initMap]);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50">
      {/* Header */}
      <header className="h-16 flex items-center px-6 bg-white border-b border-slate-200 shadow-sm z-10">
        <div className="flex items-center gap-3">
          <div className="bg-blue-600 p-2 rounded-lg text-white">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path d="M12 14l9-5-9-5-9 5 9 5z" />
              <path d="M12 14l6.16-3.422a12.083 12.083 0 01.665 6.479A11.952 11.952 0 0012 20.055a11.952 11.952 0 00-6.824-2.998 12.078 12.078 0 01.665-6.479L12 14z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 14l9-5-9-5-9 5 9 5zm0 0l6.16-3.422a12.083 12.083 0 01.665 6.479A11.952 11.952 0 0012 20.055a11.952 11.952 0 00-6.824-2.998 12.078 12.078 0 01.665-6.479L12 14zm0 0V20" />
            </svg>
          </div>
          <h1 className="text-xl font-bold text-slate-800">전국 대학교 교육 계약 현황 대시보드</h1>
        </div>
      </header>

      {/* Map Container */}
      <main className="flex-1 relative">
        <div id="map" ref={mapRef} className="h-full w-full" />

        {/* Floating Sidebar (Optional stats) */}
        <div className="absolute top-4 left-4 bg-white/90 backdrop-blur-md p-4 rounded-xl shadow-xl border border-white/20 w-64 hidden md:block">
          <h2 className="text-sm font-semibold text-slate-500 uppercase tracking-wider mb-3">전체 통계</h2>
          <div className="space-y-4">
            <div>
              <p className="text-2xl font-bold text-slate-900">{MOCK_DATA.length}</p>
              <p className="text-xs text-slate-500">계약 체결 대학교 수</p>
            </div>
            <div>
              <p className="text-2xl font-bold text-blue-600">
                {formatCurrency(MOCK_DATA.reduce((acc, cur) => acc + cur.amount_sum, 0))}
              </p>
              <p className="text-xs text-slate-500">전체 계약 규모</p>
            </div>
          </div>
        </div>

        {/* Legend */}
        <div className="absolute bottom-6 right-6 flex flex-col gap-4">
          {/* Region Legend */}
          <div className="bg-white/95 backdrop-blur-md p-4 rounded-xl shadow-2xl border border-slate-200 min-w-[180px]">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-tight mb-3">권역별 구분</h3>
            <div className="space-y-2">
              {Object.entries(REGION_COLORS).map(([region, color]) => (
                <div key={region} className="flex items-center gap-2">
                  <span className="w-3 h-3 rounded-full" style={{ backgroundColor: color }}></span>
                  <span className="text-sm font-medium text-slate-700">{region}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Size Legend */}
          <div className="bg-white/95 backdrop-blur-md p-4 rounded-xl shadow-2xl border border-slate-200 min-w-[180px]">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-tight mb-3">계약 금액 규모</h3>
            <div className="space-y-3 mt-2">
              <div className="flex items-center gap-3">
                <div className="rounded-full border border-slate-300 flex items-center justify-center" style={{ width: '12px', height: '12px' }}></div>
                <span className="text-xs text-slate-600">~ 1억 미만</span>
              </div>
              <div className="flex items-center gap-3">
                <div className="rounded-full border border-slate-300 flex items-center justify-center" style={{ width: '22px', height: '22px' }}></div>
                <span className="text-xs text-slate-600">5억 규모</span>
              </div>
              <div className="flex items-center gap-3">
                <div className="rounded-full border border-slate-300 flex items-center justify-center" style={{ width: '35px', height: '35px' }}></div>
                <span className="text-xs text-slate-600">10억 이상</span>
              </div>
              <p className="text-[10px] text-slate-400 mt-2 leading-tight">
                * 반지름 = 8 + log10(금액) × 6<br/>
                (최소 10px, 최대 45px 기준)
              </p>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

