import React, { useEffect, useRef, useState, useCallback } from 'react';
import { MOCK_DATA, REGION_COLORS } from './constants';
import { UniversityData } from './types';

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const googleMap = useRef<any>(null);
  const [mapLoaded, setMapLoaded] = useState(false);

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency',
      currency: 'KRW',
      maximumFractionDigits: 0
    }).format(amount);
  };

  const calculateRadiusPx = (amount: number) => {
    const logValue = Math.log10(amount);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const initMap = useCallback(() => {
    if (!mapRef.current || !window.google || !window.google.maps) {
      console.warn("Google Maps API not yet loaded.");
      return;
    }

    const center = { lat: 36.3504, lng: 127.3845 }; // 대전 중심

    const map = new google.maps.Map(mapRef.current, {
      center: center,
      zoom: 7.5,
      disableDefaultUI: false,
      zoomControl: true,
      mapTypeControl: false,
      scaleControl: true,
      streetViewControl: false,
      rotateControl: false,
      fullscreenControl: true,
      styles: [
        {
          featureType: "administrative",
          elementType: "labels.text.fill",
          stylers: [{ color: "#444444" }]
        },
        {
          featureType: "landscape",
          elementType: "all",
          stylers: [{ color: "#f2f2f2" }]
        }
      ]
    });

    googleMap.current = map;
    const infoWindow = new google.maps.InfoWindow();

    MOCK_DATA.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS['기타/미정'];
      const radiusPx = calculateRadiusPx(univ.amount_sum);

      // Circle radius is in meters. To simulate pixels on zoom 7-8:
      // Approx 1 pixel at zoom 8 is ~600 meters in Korea latitude.
      const radiusMeters = radiusPx * 450; 

      const circle = new google.maps.Circle({
        strokeColor: color,
        strokeOpacity: 0.8,
        strokeWeight: 1.5,
        fillColor: color,
        fillOpacity: 0.4,
        map: map,
        center: { lat: univ.lat, lng: univ.lng },
        radius: radiusMeters,
        clickable: true
      });

      circle.addListener('click', () => {
        const content = `
          <div style="padding: 8px; font-family: 'Pretendard', sans-serif;">
            <div style="font-size: 12px; color: ${color}; font-weight: bold; margin-bottom: 2px;">${univ.region}</div>
            <div style="font-size: 16px; font-weight: 700; color: #1e293b; margin-bottom: 4px;">${univ.school_name}</div>
            <div style="font-size: 13px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
            <div style="border-top: 1px solid #f1f5f9; pt: 8px; margin-top: 4px;">
              <div style="font-size: 11px; color: #94a3b8; margin-top: 6px;">총 계약금액</div>
              <div style="font-size: 15px; font-weight: 600; color: #2563eb;">${formatCurrency(univ.amount_sum)}</div>
            </div>
          </div>
        `;
        infoWindow.setContent(content);
        infoWindow.setPosition({ lat: univ.lat, lng: univ.lng });
        infoWindow.open(map);
      });
    });

    setMapLoaded(true);
  }, []);

  useEffect(() => {
    // API가 로드될 때까지 반복 확인 (또는 스크립트 onload 활용)
    const checkGoogle = setInterval(() => {
      if (window.google && window.google.maps) {
        initMap();
        clearInterval(checkGoogle);
      }
    }, 100);

    return () => clearInterval(checkGoogle);
  }, [initMap]);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans">
      {/* Header */}
      <header className="h-16 flex items-center justify-between px-6 bg-white border-b border-slate-200 shadow-sm z-10">
        <div className="flex items-center gap-3">
          <div className="bg-blue-600 p-2 rounded-lg text-white shadow-md shadow-blue-100">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
            </svg>
          </div>
          <div>
            <h1 className="text-lg font-bold text-slate-800 leading-tight">전국 대학교 교육 계약 현황</h1>
            <p className="text-xs text-slate-500 font-medium">University Contract Dashboard</p>
          </div>
        </div>
        <div className="hidden sm:flex items-center gap-6">
          <div className="text-right">
            <p className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">Total Contract</p>
            <p className="text-sm font-bold text-blue-600">
              {formatCurrency(MOCK_DATA.reduce((acc, cur) => acc + cur.amount_sum, 0))}
            </p>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 relative overflow-hidden">
        {/* Map Container */}
        <div 
          id="map" 
          ref={mapRef} 
          className="h-full w-full bg-slate-100"
          style={{ minHeight: '400px' }}
        />

        {!mapLoaded && (
          <div className="absolute inset-0 flex items-center justify-center bg-slate-50/80 z-20 backdrop-blur-sm">
            <div className="flex flex-col items-center">
              <div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
              <p className="text-slate-600 font-medium text-sm">지도를 불러오는 중입니다...</p>
            </div>
          </div>
        )}

        {/* Legend Panel */}
        <div className="absolute bottom-8 right-8 flex flex-col gap-4 pointer-events-none">
          {/* Region Color Legend */}
          <div className="bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-xl border border-slate-200 w-48 pointer-events-auto transition-all hover:shadow-2xl">
            <h3 className="text-[11px] font-black text-slate-400 uppercase mb-3 tracking-widest border-b border-slate-100 pb-2">Regions</h3>
            <div className="grid grid-cols-1 gap-2.5">
              {Object.entries(REGION_COLORS).map(([region, color]) => (
                <div key={region} className="flex items-center gap-3 group">
                  <span className="w-2.5 h-2.5 rounded-full ring-2 ring-offset-1 ring-transparent group-hover:ring-slate-200 transition-all" style={{ backgroundColor: color }}></span>
                  <span className="text-xs font-semibold text-slate-600">{region}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Amount Size Legend */}
          <div className="bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-xl border border-slate-200 w-48 pointer-events-auto transition-all hover:shadow-2xl">
            <h3 className="text-[11px] font-black text-slate-400 uppercase mb-3 tracking-widest border-b border-slate-100 pb-2">Contract Scale</h3>
