// Define the global window interface to include google
declare global {
  interface Window {
    google: any;
  }
}

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const googleMap = useRef<any>(null);
  const [mapLoaded, setMapLoaded] = useState(false);

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency',
      currency: 'KRW',
      maximumFractionDigits: 0
    }).format(amount);
  };

  const calculateRadiusPx = (amount: number) => {
    const logValue = Math.log10(amount);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const initMap = useCallback(() => {
    // Accessing google from window to avoid TS errors
    if (!mapRef.current || !window.google || !window.google.maps) {
      console.warn("Google Maps API not yet loaded.");
      return;
    }

    const google = window.google;
    const center = { lat: 36.3504, lng: 127.3845 }; // 대전 중심

    const map = new google.maps.Map(mapRef.current, {
      center: center,
      zoom: 7.5,
      disableDefaultUI: false,
