declare global {
  interface Window {
    google: any;
    initMapCallback: () => void;
  }
}

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const [apiKey, setApiKey] = useState<string>(localStorage.getItem('GMAP_API_KEY') || '');
  const [isKeySubmitted, setIsKeySubmitted] = useState<boolean>(!!localStorage.getItem('GMAP_API_KEY'));
  const [mapLoaded, setMapLoaded] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency',
      currency: 'KRW',
      maximumFractionDigits: 0
    }).format(amount);
  };

  const calculateRadiusPx = (amount: number) => {
    const logValue = Math.log10(amount);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const loadGoogleMaps = useCallback((key: string) => {
    if (window.google && window.google.maps) {
      initMap();
      return;
    }

    const script = document.createElement('script');
    script.src = `https://maps.googleapis.com/maps/api/js?key=${key}&callback=initMapCallback`;
    script.async = true;
    script.defer = true;
    script.onerror = () => setError('Google Maps SDK를 로드하는 데 실패했습니다. 키를 확인해주세요.');

    window.initMapCallback = () => {
      initMap();
    };

    document.head.appendChild(script);
  }, []);

  const initMap = () => {
    if (!mapRef.current || !window.google || !window.google.maps) return;

    const google = window.google;
    const center = { lat: 36.3504, lng: 127.3845 };

    const map = new google.maps.Map(mapRef.current, {
      center: center,
      zoom: 7.5,
      disableDefaultUI: false,
      zoomControl: true,
      mapTypeControl: false,
      streetViewControl: false,
    });

    const infoWindow = new google.maps.InfoWindow();

