        center: { lat: univ.lat, lng: univ.lng },
        radius: radiusMeters,
        clickable: true
      });

      circle.addListener('click', () => {
        const content = `
          <div style="padding: 10px; min-width: 200px;">
            <div style="font-size: 11px; color: ${color}; font-weight: bold;">${univ.region}</div>
            <div style="font-size: 15px; font-weight: 700; margin: 4px 0;">${univ.school_name}</div>
            <div style="font-size: 12px; color: #666;">${univ.address}</div>
            <div style="margin-top: 8px; padding-top: 8px; border-top: 1px solid #eee;">
               <div style="font-size: 10px; color: #999;">계약금액</div>
               <div style="font-size: 14px; font-weight: 600; color: #2563eb;">${formatCurrency(univ.amount_sum)}</div>
            </div>
          </div>
        `;
        infoWindow.setContent(content);
        infoWindow.setPosition({ lat: univ.lat, lng: univ.lng });
        infoWindow.open(map);
      });
    });

    setMapLoaded(true);
  };

  const handleKeySubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (apiKey.trim()) {
      localStorage.setItem('GMAP_API_KEY', apiKey);
      setIsKeySubmitted(true);
      loadGoogleMaps(apiKey);
    }
  };

  const resetApiKey = () => {
    localStorage.removeItem('GMAP_API_KEY');
    window.location.reload();
  };

  useEffect(() => {
    if (isKeySubmitted && apiKey) {
      loadGoogleMaps(apiKey);
    }
  }, [isKeySubmitted, apiKey, loadGoogleMaps]);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden">
      {/* API Key Modal */}
      {!isKeySubmitted && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white p-8 rounded-3xl shadow-2xl w-full max-w-md border border-white/20">
            <div className="flex flex-col items-center mb-6">
