import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS } from './constants';
import { UniversityData } from './types';

// Leaflet is available via global L variable from script tag
declare const L: any;

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const [isLoaded, setIsLoaded] = useState(false);

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency',
      currency: 'KRW',
      maximumFractionDigits: 0
    }).format(amount);
  };

  // 시각적 반지름 계산 (픽셀 단위 기반)
  const calculateRadius = (amount: number) => {
    const logValue = Math.log10(amount);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  useEffect(() => {
    if (!mapContainerRef.current || mapInstance.current) return;

    // 1. 지도 초기화 (대한민국 중심)
    const map = L.map(mapContainerRef.current, {
      center: [36.3504, 127.3845],
      zoom: 7.5,
      zoomControl: false // 커스텀 위치를 위해 기본 컨트롤 제거
    });

    // 2. 타일 레이어 추가 (CartoDB Positron - 깔끔한 라이트 테마)
    L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
      attribution: '&copy; OpenStreetMap &copy; CARTO'
    }).addTo(map);

    // 3. 줌 컨트롤 우측 하단 배치
    L.control.zoom({ position: 'bottomright' }).addTo(map);

    // 4. 데이터 마커 추가
    MOCK_DATA.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS['기타/미정'];
      const radius = calculateRadius(univ.amount_sum);

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: color,
        weight: 1.5,
        opacity: 0.8,
        fillOpacity: 0.4
      }).addTo(map);

      // 팝업 내용 구성
      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif;">
          <div style="font-size: 10px; color: ${color}; font-weight: 800; text-transform: uppercase; letter-spacing: 0.05em; margin-bottom: 2px;">${univ.region}</div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 4px;">${univ.school_name}</div>
          <div style="font-size: 11px; color: #64748b; margin-bottom: 10px;">${univ.address}</div>
          <div style="border-top: 1px solid #f1f5f9; padding-top: 8px;">
            <div style="font-size: 9px; color: #94a3b8; font-weight: 600;">총 계약금액</div>
            <div style="font-size: 14px; font-weight: 700; color: #2563eb;">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, {
        className: 'custom-popup',
        closeButton: false
      });

      // 호버 효과
      circle.on('mouseover', function(e: any) {
        this.setStyle({ fillOpacity: 0.7, weight: 3 });
      });
      circle.on('mouseout', function(e: any) {
        this.setStyle({ fillOpacity: 0.4, weight: 1.5 });
      });
    });

    mapInstance.current = map;
    setIsLoaded(true);

    return () => {
      if (mapInstance.current) {
        mapInstance.current.remove();
        mapInstance.current = null;
      }
    };
  }, []);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden text-slate-900">
      {/* Header */}
      <header className="h-16 flex items-center justify-between px-6 bg-white border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-blue-600 p-2 rounded-lg text-white shadow-lg shadow-blue-100">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 3.055A9.001 9.001 0 1020.945 13H11V3.055z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.488 9H15V3.512A9.025 9.025 0 0120.488 9z" />
            </svg>
          </div>
          <div>
            <h1 className="text-lg font-bold text-slate-800 leading-tight">전국 대학교 교육 계약 현황</h1>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">Education Contract Data Map</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="hidden sm:block text-right">
            <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.1em]">Total Contract Sum</p>
            <p className="text-base font-black text-blue-600">
              {formatCurrency(MOCK_DATA.reduce((acc, cur) => acc + cur.amount_sum, 0))}
            </p>
          </div>
        </div>
      </header>

      {/* Map Content */}
      <main className="flex-1 relative">
        <div ref={mapContainerRef} id="map" />

        {/* Statistics Overlay (Top Left) */}
        <div className="absolute top-6 left-6 z-[1000] pointer-events-none">
          <div className="glass p-5 rounded-2xl shadow-xl w-56 pointer-events-auto">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Dashboard Overview</h3>
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <span className="text-xs font-bold text-slate-500">기관 수</span>
                <span className="text-sm font-black text-slate-800">{MOCK_DATA.length}개교</span>
              </div>
              <div className="h-1 bg-slate-100 rounded-full overflow-hidden">
                <div className="h-full bg-blue-500 w-[75%]"></div>
              </div>
              <div className="pt-2">
                <p className="text-[10px] text-slate-400 leading-relaxed font-medium">
                  본 대시보드는 오픈소스 라이브러리(Leaflet)를 사용하여 별도의 API 키 없이 구동됩니다.
                </p>
              </div>
            </div>
          </div>
        </div>

        {/* Legend Overlay (Bottom Right) */}
        <div className="absolute bottom-8 right-16 z-[1000] flex flex-col gap-4 pointer-events-none">
          {/* Region Color Legend */}
          <div className="glass p-4 rounded-2xl shadow-xl w-44 pointer-events-auto">
            <h3 className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-3 border-b border-slate-100 pb-2">Regions</h3>
            <div className="grid grid-cols-1 gap-1.5">
              {Object.entries(REGION_COLORS).map(([name, color]) => (
                <div key={name} className="flex items-center gap-2.5">
                  <span className="w-2 h-2 rounded-full" style={{ backgroundColor: color }}></span>
                  <span className="text-[11px] font-bold text-slate-600">{name}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Scale Legend */}
          <div className="glass p-4 rounded-2xl shadow-xl w-44 pointer-events-auto">
            <h3 className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-3 border-b border-slate-100 pb-2">Contract Scale</h3>
            <div className="flex flex-col gap-3 py-1 items-center">
              <div className="flex items-center w-full gap-3">
                <div className="w-3 h-3 rounded-full border-2 border-slate-300 bg-white"></div>
                <span className="text-[10px] text-slate-500 font-bold">~ 1억</span>
              </div>
              <div className="flex items-center w-full gap-3">
                <div className="w-6 h-6 rounded-full border-2 border-slate-300 bg-white"></div>
                <span className="text-[10px] text-slate-500 font-bold">~ 5억</span>
              </div>
              <div className="flex items-center w-full gap-3">
                <div className="w-9 h-9 rounded-full border-2 border-slate-300 bg-white"></div>
                <span className="text-[10px] text-slate-500 font-bold">10억 이상</span>
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

