import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  const [data, setData] = useState<UniversityData[]>(MOCK_DATA);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SUDO,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'NEW' as 'NEW' | 'EXISTING',
    proposal_range: ''
  });

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const calculateRadius = (amount: number) => {
    const logValue = Math.log10(amount || 1);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const renderMarkers = () => {
    if (!mapInstance.current || !markersLayer.current) return;

    markersLayer.current.clearLayers();

    data.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS[Region.ETC];
      const radius = calculateRadius(univ.amount_sum);
      const isNew = univ.status === 'NEW';

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: isNew ? '#ffffff' : color, // 신규 학교는 흰색 테두리로 강조
        weight: isNew ? 3 : 1.5,
        dashArray: isNew ? '5, 5' : null, // 신규 학교는 점선 처리
        opacity: 1,
        fillOpacity: 0.5
      });

      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
            <span style="font-size: 9px; color: ${color}; font-weight: 800; border: 1px solid ${color}; padding: 1px 4px; border-radius: 4px;">${univ.region}</span>
            <span style="font-size: 9px; font-weight: 800; background: ${isNew ? '#EF4444' : '#64748b'}; color: white; padding: 1px 4px; border-radius: 4px;">${isNew ? '신규참여예정' : '기존학교'}</span>
          </div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 2px;">${univ.school_name}</div>
          <div style="font-size: 11px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
          <div style="background: #f8fafc; padding: 8px; border-radius: 6px; margin-bottom: 8px;">
            <div style="font-size: 9px; color: #94a3b8; font-weight: 600;">제안 범위</div>
            <div style="font-size: 11px; color: #334155; font-weight: 600;">${univ.proposal_range}</div>
          </div>
          <div style="border-top: 1px solid #f1f5f9; padding-top: 6px;">
            <div style="font-size: 9px; color: #94a3b8; font-weight: 600;">예상 제안 금액</div>
            <div style="font-size: 14px; font-weight: 700; color: #2563eb;">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, { closeButton: false }).addTo(markersLayer.current);
    });
  };

  useEffect(() => {
    if (!mapContainerRef.current) return;

    const map = L.map(mapContainerRef.current, {
      center: [36.3504, 127.3845],
      zoom: 7.5,
      zoomControl: false
    });

    L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
      attribution: '&copy; CARTO'
    }).addTo(map);

    L.control.zoom({ position: 'bottomright' }).addTo(map);

    markersLayer.current = L.layerGroup().addTo(map);
    mapInstance.current = map;
    renderMarkers();

    return () => { map.remove(); };
  }, []);

  useEffect(() => {
    renderMarkers();
  }, [data]);

  const handleAddData = (e: React.FormEvent) => {
    e.preventDefault();
    const newEntry: UniversityData = {
      school_id: `S${Date.now()}`,
      school_name: formData.school_name,
      region: formData.region,
      address: formData.address,
      lat: parseFloat(formData.lat),
