      amount_sum: parseInt(formData.amount_sum),
      status: formData.status,
      proposal_range: formData.proposal_range
    };
    setData(prev => [...prev, newEntry]);
    setFormData({
      school_name: '', region: Region.SUDO, address: '', lat: '', lng: '', amount_sum: '', status: 'NEW', proposal_range: ''
    });
    setIsAdminOpen(false);
  };

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden text-slate-900">
      {/* Header */}
      <header className="h-16 flex items-center justify-between px-6 bg-white border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-lg text-white shadow-lg">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
            </svg>
          </div>
          <div>
            <h1 className="text-lg font-bold text-slate-800 leading-tight">2026 부트캠프 교육/세미나 제안</h1>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">Education Proposal Status Dashboard</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="text-right">
            <p className="text-[9px] text-slate-400 font-black uppercase">Total Expected Amount</p>
            <p className="text-base font-black text-indigo-600">{formatCurrency(data.reduce((acc, cur) => acc + cur.amount_sum, 0))}</p>
