          <button 
            onClick={() => setIsAdminOpen(!isAdminOpen)}
            className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${isAdminOpen ? 'bg-slate-800 text-white' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'}`}
          >
            {isAdminOpen ? '닫기' : '데이터 관리'}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 relative">
        <div ref={mapContainerRef} id="map" />

        {/* Admin Panel */}
        {isAdminOpen && (
          <div className="absolute top-6 left-6 z-[2000] w-80">
            <div className="glass p-5 rounded-2xl shadow-2xl border border-indigo-100 animate-in slide-in-from-left-4 duration-300">
              <h3 className="text-sm font-bold text-slate-800 mb-4 flex items-center gap-2">
                <span className="w-1.5 h-4 bg-indigo-600 rounded-full"></span>
                제안 데이터 추가
              </h3>
              <form onSubmit={handleAddData} className="space-y-3">
