import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  const [data, setData] = useState<UniversityData[]>(MOCK_DATA);
  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SUDO,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'NEW' as 'NEW' | 'EXISTING',
    proposal_range: ''
  });

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const calculateRadius = (amount: number) => {
    const logValue = Math.log10(amount || 1);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const renderMarkers = () => {
    if (!mapInstance.current || !markersLayer.current || viewMode !== 'map') return;

    markersLayer.current.clearLayers();

    data.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS[Region.ETC];
      const radius = calculateRadius(univ.amount_sum);
      const isNew = univ.status === 'NEW';

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: isNew ? '#ffffff' : color,
        weight: isNew ? 3 : 1.5,
        dashArray: isNew ? '5, 5' : null,
        opacity: 1,
        fillOpacity: 0.5
      });

      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
            <span style="font-size: 9px; color: ${color}; font-weight: 800; border: 1px solid ${color}; padding: 1px 4px; border-radius: 4px;">${univ.region}</span>
            <span style="font-size: 9px; font-weight: 800; background: ${isNew ? '#EF4444' : '#64748b'}; color: white; padding: 1px 4px; border-radius: 4px;">${isNew ? '신규참여예정' : '기존학교'}</span>
          </div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 2px;">${univ.school_name}</div>
          <div style="font-size: 11px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
          <div style="background: #f8fafc; padding: 8px; border-radius: 6px; margin-bottom: 8px;">
            <div style="font-size: 9px; color: #94a3b8; font-weight: 600;">제안 범위</div>
            <div style="font-size: 11px; color: #334155; font-weight: 600;">${univ.proposal_range}</div>
          </div>
          <div style="border-top: 1px solid #f1f5f9; padding-top: 6px;">
            <div style="font-size: 9px; color: #94a3b8; font-weight: 600;">예상 제안 금액</div>
            <div style="font-size: 14px; font-weight: 700; color: #2563eb;">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, { closeButton: false }).addTo(markersLayer.current);
    });
  };

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current && !mapInstance.current) {
      const map = L.map(mapContainerRef.current, {
        center: [36.3504, 127.3845],
        zoom: 7.5,
        zoomControl: false
      });

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; CARTO'
      }).addTo(map);

      L.control.zoom({ position: 'bottomright' }).addTo(map);

      markersLayer.current = L.layerGroup().addTo(map);
      mapInstance.current = map;
      renderMarkers();
    }

    return () => {
      if (mapInstance.current) {
        mapInstance.current.remove();
        mapInstance.current = null;
      }
    };
  }, [viewMode]);

  useEffect(() => {
    if (viewMode === 'map') renderMarkers();
  }, [data, viewMode]);

  const handleAddData = (e: React.FormEvent) => {
    e.preventDefault();
    const newEntry: UniversityData = {
      school_id: `S${Date.now()}`,
      school_name: formData.school_name,
      region: formData.region,
      address: formData.address,
      lat: parseFloat(formData.lat),
      lng: parseFloat(formData.lng),
      amount_sum: parseInt(formData.amount_sum),
      status: formData.status,
      proposal_range: formData.proposal_range
    };
    setData(prev => [...prev, newEntry]);
    setFormData({
      school_name: '', region: Region.SUDO, address: '', lat: '', lng: '', amount_sum: '', status: 'NEW', proposal_range: ''
    });
    setIsAdminOpen(false);
  };

  const totalAmount = data.reduce((acc, cur) => acc + cur.amount_sum, 0);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden text-slate-900">
      {/* Header */}
      <header className="h-16 flex items-center justify-between px-6 bg-white border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-lg text-white shadow-lg">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
            </svg>
          </div>
          <div>
            <h1 className="text-lg font-bold text-slate-800 leading-tight">2026 부트캠프 교육/세미나 제안</h1>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">Education Proposal Status Dashboard</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          {/* Tab Switcher */}
          <div className="bg-slate-100 p-1 rounded-xl flex items-center">
            <button 
              onClick={() => setViewMode('map')}
              className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 20l-5.447-2.724A1 1 0 013 16.382V5.618a1 1 0 011.447-.894L9 7m0 13l6-3m-6 3V7m6 10l4.553 2.276A1 1 0 0021 18.382V7.618a1 1 0 00-1.447-.894L15 7m0 10V7" />
              </svg>
              현황 지도
            </button>
            <button 
              onClick={() => setViewMode('list')}
              className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 10h16M4 14h16M4 18h16" />
              </svg>
              학교 리스트
            </button>
          </div>

          <div className="hidden md:block text-right">
            <p className="text-[9px] text-slate-400 font-black uppercase">Total Expected Amount</p>
            <p className="text-base font-black text-indigo-600">{formatCurrency(totalAmount)}</p>
          </div>

          <button 
            onClick={() => setIsAdminOpen(!isAdminOpen)}
            className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${isAdminOpen ? 'bg-slate-800 text-white' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'}`}
          >
            {isAdminOpen ? '닫기' : '데이터 관리'}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 relative overflow-hidden">
        {/* Map View */}
        <div className={`absolute inset-0 transition-opacity duration-300 ${viewMode === 'map' ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}>
          <div ref={mapContainerRef} id="map" />
        </div>

        {/* List View */}
        <div className={`absolute inset-0 bg-slate-50 overflow-auto p-8 transition-opacity duration-300 ${viewMode === 'list' ? 'opacity-100 z-20' : 'opacity-0 z-0'}`}>
          <div className="max-w-6xl mx-auto">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-bold text-slate-800">학교별 제안 상세 현황</h2>
              <div className="flex gap-4">
                <div className="bg-white px-4 py-2 rounded-xl shadow-sm border border-slate-200">
                  <span className="text-xs text-slate-400 font-bold mr-2 uppercase">Total Schools</span>
                  <span className="text-sm font-bold text-slate-700">{data.length}개교</span>
                </div>
              </div>
            </div>

            <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-slate-50 border-b border-slate-200">
                    <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-wider">구분</th>
                    <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-wider">지역</th>
                    <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-wider">학교명</th>
                    <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-wider">제안 범위</th>
                    <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-wider text-right">예상 제안 금액</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {data.map((univ) => {
                    const isNew = univ.status === 'NEW';
                    return (
                      <tr key={univ.school_id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4">
                          <span className={`inline-block px-2 py-1 rounded-md text-[10px] font-bold ${isNew ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-600'}`}>
                            {isNew ? '신규참여' : '기존학교'}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-2">
                            <span className="w-2 h-2 rounded-full" style={{ backgroundColor: REGION_COLORS[univ.region] }}></span>
                            <span className="text-xs font-bold text-slate-600">{univ.region}</span>
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <span className="text-sm font-bold text-slate-800">{univ.school_name}</span>
                          <p className="text-[10px] text-slate-400 mt-0.5">{univ.address}</p>
                        </td>
                        <td className="px-6 py-4">
                          <span className="text-xs text-slate-600 font-medium">{univ.proposal_range}</span>
                        </td>
                        <td className="px-6 py-4 text-right">
                          <span className="text-sm font-black text-indigo-600">{formatCurrency(univ.amount_sum)}</span>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
                <tfoot>
                  <tr className="bg-indigo-50/50 font-bold border-t border-indigo-100">
                    <td colSpan={4} className="px-6 py-5 text-sm text-indigo-900 text-right uppercase tracking-wider font-black">합계 금액</td>
                    <td className="px-6 py-5 text-lg text-indigo-600 text-right font-black">{formatCurrency(totalAmount)}</td>
                  </tr>
                </tfoot>
              </table>
            </div>
          </div>
        </div>

        {/* Admin Panel (Floating) */}
        {isAdminOpen && (
          <div className="absolute top-6 left-6 z-[2000] w-80">
            <div className="glass p-5 rounded-2xl shadow-2xl border border-indigo-100 animate-in slide-in-from-left-4 duration-300">
              <h3 className="text-sm font-bold text-slate-800 mb-4 flex items-center gap-2">
                <span className="w-1.5 h-4 bg-indigo-600 rounded-full"></span>
                제안 데이터 추가
              </h3>
              <form onSubmit={handleAddData} className="space-y-3">
                <div className="grid grid-cols-2 gap-2">
                  <button 
                    type="button"
                    onClick={() => setFormData({...formData, status: 'NEW'})}
                    className={`py-2 rounded-lg text-xs font-bold border transition-all ${formData.status === 'NEW' ? 'bg-red-50 border-red-200 text-red-600' : 'bg-white border-slate-200 text-slate-400'}`}
                  >
                    신규참여예정
                  </button>
                  <button 
                    type="button"
                    onClick={() => setFormData({...formData, status: 'EXISTING'})}
                    className={`py-2 rounded-lg text-xs font-bold border transition-all ${formData.status === 'EXISTING' ? 'bg-slate-800 border-slate-800 text-white' : 'bg-white border-slate-200 text-slate-400'}`}
                  >
                    기존학교
                  </button>
                </div>
                <input required placeholder="학교명" className="w-full p-2 text-xs bg-white border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-indigo-500" value={formData.school_name} onChange={e => setFormData({...formData, school_name: e.target.value})} />
                <select className="w-full p-2 text-xs bg-white border border-slate-200 rounded-lg outline-none" value={formData.region} onChange={e => setFormData({...formData, region: e.target.value as Region})}>
                  {Object.keys(Region).map(k => <option key={k} value={(Region as any)[k]}>{(Region as any)[k]}</option>)}
                </select>
                <input required placeholder="주소" className="w-full p-2 text-xs bg-white border border-slate-200 rounded-lg outline-none" value={formData.address} onChange={e => setFormData({...formData, address: e.target.value})} />
                <div className="grid grid-cols-2 gap-2">
                  <input required type="number" step="any" placeholder="위도" className="w-full p-2 text-xs bg-white border border-slate-200 rounded-lg outline-none" value={formData.lat} onChange={e => setFormData({...formData, lat: e.target.value})} />
                  <input required type="number" step="any" placeholder="경도" className="w-full p-2 text-xs bg-white border border-slate-200 rounded-lg outline-none" value={formData.lng} onChange={e => setFormData({...formData, lng: e.target.value})} />
                </div>
                <input required placeholder="제안 범위 (예: AI 기초 교육)" className="w-full p-2 text-xs bg-white border border-slate-200 rounded-lg outline-none" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
                <input required type="number" placeholder="예상금액 (원)" className="w-full p-2 text-xs bg-white border border-slate-200 rounded-lg outline-none" value={formData.amount_sum} onChange={e => setFormData({...formData, amount_sum: e.target.value})} />
                <button type="submit" className="w-full bg-indigo-600 text-white py-2.5 rounded-lg text-xs font-bold shadow-lg shadow-indigo-100 mt-2 transition-transform active:scale-95">맵/리스트에 추가하기</button>
              </form>
            </div>
          </div>
        )}

        {/* Legend Overlay (Only on Map) */}
        {viewMode === 'map' && (
          <div className="absolute bottom-8 right-16 z-[1000] flex flex-col gap-4 pointer-events-none animate-in fade-in slide-in-from-bottom-4 duration-500">
