                <div className="flex items-center gap-2">
                  <span className="w-3 h-3 rounded-full border-2 border-dashed border-red-500 bg-red-100"></span>
                  <span className="text-[11px] font-bold text-slate-600">신규참여예정</span>
                </div>
                <div className="flex items-center gap-2">
                  <span className="w-3 h-3 rounded-full border border-slate-400 bg-slate-400"></span>
                  <span className="text-[11px] font-bold text-slate-600">기존학교</span>
                </div>
              </div>
            </div>

            <div className="glass p-4 rounded-2xl shadow-xl w-44 pointer-events-auto">
              <h3 className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-3 border-b border-slate-100 pb-2">Regions</h3>
              <div className="grid grid-cols-1 gap-1.5">
                {Object.entries(REGION_COLORS).map(([name, color]) => (
                  <div key={name} className="flex items-center gap-2.5">
