import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS, UNIVERSITY_PRESETS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  const [data, setData] = useState<UniversityData[]>(MOCK_DATA);
  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [industryFilter, setIndustryFilter] = useState<string>('전체');

  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SUDO,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'EXISTING' as 'NEW' | 'EXISTING',
    proposal_range: '',
    industry: '반도체'
  });

  const industries = ['전체', '반도체', '이차전지', '바이오', '디스플레이', '항공우주', '미래차', '인공지능'];

  // 학교명 입력 시 프리셋 자동 적용
  const handleSchoolNameChange = (name: string) => {
    setFormData(prev => ({ ...prev, school_name: name }));
    const preset = UNIVERSITY_PRESETS[name];
    if (preset) {
      setFormData(prev => ({
        ...prev,
        school_name: name,
        region: preset.region,
        lat: preset.lat.toString(),
        lng: preset.lng.toString(),
        address: preset.address
      }));
    }
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const filteredData = data.filter(item => 
    industryFilter === '전체' || item.industry === industryFilter
  );

  const calculateRadius = (amount: number) => {
    const logValue = Math.log10(amount || 1);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const renderMarkers = () => {
    if (!mapInstance.current || !markersLayer.current || viewMode !== 'map') return;

    markersLayer.current.clearLayers();

    filteredData.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS[Region.ETC];
      const radius = calculateRadius(univ.amount_sum);
      const isNew = univ.status === 'NEW';

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: isNew ? '#ffffff' : color,
        weight: isNew ? 3 : 1.5,
        dashArray: isNew ? '5, 5' : null,
        opacity: 1,
        fillOpacity: 0.5
      });

      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
            <span style="font-size: 9px; color: ${color}; font-weight: 800; border: 1px solid ${color}; padding: 1px 4px; border-radius: 4px;">${univ.industry} | ${univ.region}</span>
            <span style="font-size: 9px; font-weight: 800; background: ${isNew ? '#EF4444' : '#64748b'}; color: white; padding: 1px 4px; border-radius: 4px;">${isNew ? '신규참여' : '기존학교'}</span>
          </div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 2px;">${univ.school_name}</div>
          <div style="font-size: 11px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
          <div style="background: #f8fafc; padding: 8px; border-radius: 6px; margin-bottom: 8px;">
            <div style="font-size: 9px; color: #94a3b8; font-weight: 600;">제안 범위(협력)</div>
            <div style="font-size: 11px; color: #334155; font-weight: 600;">${univ.proposal_range}</div>
          </div>
          <div style="border-top: 1px solid #f1f5f9; padding-top: 6px;">
            <div style="font-size: 9px; color: #94a3b8; font-weight: 600;">예상 제안 금액</div>
            <div style="font-size: 14px; font-weight: 700; color: #2563eb;">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, { closeButton: false }).addTo(markersLayer.current);
    });
  };

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current && !mapInstance.current) {
      const map = L.map(mapContainerRef.current, {
        center: [36.3504, 127.3845],
        zoom: 7.5,
        zoomControl: false
      });

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; CARTO'
      }).addTo(map);

      L.control.zoom({ position: 'bottomright' }).addTo(map);

      markersLayer.current = L.layerGroup().addTo(map);
      mapInstance.current = map;
      renderMarkers();
    }
  }, [viewMode]);

  useEffect(() => {
    if (viewMode === 'map') renderMarkers();
  }, [filteredData, viewMode]);

  const handleAddData = (e: React.FormEvent) => {
    e.preventDefault();
    const newEntry: UniversityData = {
      school_id: `S${Date.now()}`,
      school_name: formData.school_name,
      region: formData.region,
      address: formData.address,
      lat: parseFloat(formData.lat),
      lng: parseFloat(formData.lng),
      amount_sum: parseInt(formData.amount_sum),
      status: formData.status,
      proposal_range: formData.proposal_range,
      industry: formData.industry
    };
    setData(prev => [...prev, newEntry]);
    setFormData({
      school_name: '', region: Region.SUDO, address: '', lat: '', lng: '', amount_sum: '', status: 'EXISTING', proposal_range: '', industry: '반도체'
    });
    setIsAdminOpen(false);
  };

  const totalAmount = filteredData.reduce((acc, cur) => acc + cur.amount_sum, 0);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden text-slate-900">
      {/* Header */}
      <header className="h-16 flex items-center justify-between px-6 bg-white border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-lg text-white shadow-lg">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
            </svg>
          </div>
          <div>
            <h1 className="text-lg font-bold text-slate-800 leading-tight">2026 부트캠프 교육 제안 (특화산업)</h1>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">High-Tech Industry Bootcamp Dashboard</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {/* Industry Filter */}
          <select 
            className="bg-slate-100 px-3 py-1.5 rounded-lg text-xs font-bold text-slate-600 outline-none border border-transparent focus:border-indigo-300 transition-all"
            value={industryFilter}
            onChange={(e) => setIndustryFilter(e.target.value)}
          >
            {industries.map(ind => <option key={ind} value={ind}>{ind} 분야</option>)}
          </select>

          <div className="bg-slate-100 p-1 rounded-xl flex items-center">
            <button onClick={() => setViewMode('map')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${viewMode === 'map' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>지도</button>
            <button onClick={() => setViewMode('list')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${viewMode === 'list' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>리스트</button>
          </div>

          <button onClick={() => setIsAdminOpen(!isAdminOpen)} className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${isAdminOpen ? 'bg-slate-800 text-white' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'}`}>
            {isAdminOpen ? '닫기' : '학교 추가'}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 relative overflow-hidden">
        {/* Map View */}
        <div className={`absolute inset-0 transition-opacity duration-300 ${viewMode === 'map' ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}>
          <div ref={mapContainerRef} id="map" />
        </div>

        {/* List View */}
        <div className={`absolute inset-0 bg-slate-50 overflow-auto p-8 transition-opacity duration-300 ${viewMode === 'list' ? 'opacity-100 z-20' : 'opacity-0 z-0'}`}>
          <div className="max-w-6xl mx-auto">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-bold text-slate-800 tracking-tight">{industryFilter} 분야 제안 현황 <span className="text-indigo-600 ml-2">{formatCurrency(totalAmount)}</span></h2>
            </div>

            <div className="bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50 border-b border-slate-200 text-[11px] font-black text-slate-400 uppercase tracking-wider">
                  <tr>
                    <th className="px-6 py-4">분야</th>
                    <th className="px-6 py-4">구분</th>
                    <th className="px-6 py-4">학교명(지역)</th>
                    <th className="px-6 py-4">제안/협력 내용</th>
                    <th className="px-6 py-4 text-right">예상 금액</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {filteredData.map((univ) => (
                    <tr key={univ.school_id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-6 py-4"><span className="text-xs font-bold text-slate-500 bg-slate-100 px-2 py-1 rounded-md">{univ.industry}</span></td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded-md text-[10px] font-bold ${univ.status === 'NEW' ? 'bg-red-50 text-red-600' : 'bg-indigo-50 text-indigo-600'}`}>
                          {univ.status === 'NEW' ? '신규' : '기존'}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="text-sm font-bold text-slate-800">{univ.school_name}</div>
                        <div className="text-[10px] text-slate-400 font-semibold flex items-center gap-1">
                          <span className="w-1.5 h-1.5 rounded-full" style={{backgroundColor: REGION_COLORS[univ.region]}}></span>
                          {univ.region}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-xs font-medium text-slate-600">{univ.proposal_range}</td>
                      <td className="px-6 py-4 text-right text-sm font-black text-indigo-600">{formatCurrency(univ.amount_sum)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Admin Panel */}
        {isAdminOpen && (
          <div className="absolute top-6 left-6 z-[2000] w-80">
            <div className="glass p-5 rounded-2xl shadow-2xl border border-indigo-100">
              <h3 className="text-sm font-bold text-slate-800 mb-4 flex items-center gap-2">
                <span className="w-1.5 h-4 bg-indigo-600 rounded-full"></span>
                데이터 빠른 등록
              </h3>
              <form onSubmit={handleAddData} className="space-y-3">
                <input 
                  required 
                  placeholder="학교명 (예: 한양대, 경북대)" 
                  className="w-full p-2 text-xs bg-white border border-slate-200 rounded-lg focus:ring-1 focus:ring-indigo-500 outline-none" 
                  value={formData.school_name} 
                  onChange={e => handleSchoolNameChange(e.target.value)} 
                />
                <div className="grid grid-cols-2 gap-2">
                  <select className="w-full p-2 text-xs bg-white border border-slate-200 rounded-lg outline-none" value={formData.industry} onChange={e => setFormData({...formData, industry: e.target.value})}>
                    {industries.filter(i => i !== '전체').map(i => <option key={i} value={i}>{i}</option>)}
                  </select>
                  <select className="w-full p-2 text-xs bg-white border border-slate-200 rounded-lg outline-none" value={formData.region} onChange={e => setFormData({...formData, region: e.target.value as Region})}>
                    {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                  </select>
                </div>
                <input required placeholder="제안 범위 (예: 기업명 협력)" className="w-full p-2 text-xs bg-white border border-slate-200 rounded-lg outline-none" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
                <input required type="number" placeholder="예상금액 (원)" className="w-full p-2 text-xs bg-white border border-slate-200 rounded-lg outline-none" value={formData.amount_sum} onChange={e => setFormData({...formData, amount_sum: e.target.value})} />

                <div className="text-[10px] text-slate-400 bg-slate-50 p-2 rounded-lg italic">
                  * 프리셋 학교명 입력 시 위경도/권역이 자동 입력됩니다.
                </div>

                <div className="grid grid-cols-2 gap-2 pt-2">
                  <button type="button" onClick={() => setFormData({...formData, status: 'NEW'})} className={`py-2 rounded-lg text-[10px] font-bold border ${formData.status === 'NEW' ? 'bg-red-50 border-red-200 text-red-600' : 'bg-white text-slate-400'}`}>신규</button>
                  <button type="button" onClick={() => setFormData({...formData, status: 'EXISTING'})} className={`py-2 rounded-lg text-[10px] font-bold border ${formData.status === 'EXISTING' ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-400'}`}>기존</button>
                </div>

                <button type="submit" className="w-full bg-indigo-600 text-white py-2.5 rounded-xl text-xs font-bold shadow-lg shadow-indigo-100 transition-transform active:scale-95">제안 정보 등록</button>
              </form>
            </div>
          </div>
        )}

        {/* Legend */}
        {viewMode === 'map' && (
          <div className="absolute bottom-8 right-16 z-[1000] flex flex-col gap-4">
            <div className="glass p-4 rounded-2xl shadow-xl w-44">
              <h3 className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-3 border-b border-slate-100 pb-2">Industry Categories</h3>
              <div className="grid grid-cols-1 gap-1.5">
                {industries.filter(i => i !== '전체').map(ind => (
                  <div key={ind} className="flex items-center gap-2">
                    <span className="text-[10px] font-bold text-slate-600">{ind}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

export interface UniversityData {
  school_id: string;
  school_name: string;
  region: string;
  address: string;
  lat: number;
  lng: number;
  amount_sum: number;
  status: 'NEW' | 'EXISTING';
  proposal_range: string;
  industry: string;
}

export enum Region {
  SEOUL = '서울',
  GYEONGGI_INCHEON = '경기/인천',
  DAEGYEONG = '대경권',
  DONGNAM = '동남권',
  CHUNGCHEONG = '충청권',
  HONAM = '호남권',
  GANGWON_JEONBUK_JEJU = '강원/전북/제주',
  ETC = '기타/미정'
}

import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS, UNIVERSITY_PRESETS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  const [data, setData] = useState<UniversityData[]>(MOCK_DATA);
  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [industryFilter, setIndustryFilter] = useState<string>('전체');

  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SEOUL,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'EXISTING' as 'NEW' | 'EXISTING',
    proposal_range: '',
    industry: '반도체'
  });

  const industries = ['전체', '반도체', '이차전지', '바이오', '디스플레이', '항공우주', '미래차', '인공지능'];

  const handleSchoolNameChange = (name: string) => {
    setFormData(prev => ({ ...prev, school_name: name }));
    const preset = UNIVERSITY_PRESETS[name];
    if (preset) {
      setFormData(prev => ({
        ...prev,
        school_name: name,
        region: preset.region,
        lat: preset.lat.toString(),
        lng: preset.lng.toString(),
        address: preset.address
      }));
    }
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const filteredData = data.filter(item => 
    industryFilter === '전체' || item.industry === industryFilter
  );

