                      <td className="px-6 py-4">
                        <span className="text-[10px] font-bold text-slate-500 bg-slate-100 px-2 py-1 rounded-md">{univ.industry}</span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                          <span className="w-2 h-2 rounded-full" style={{backgroundColor: REGION_COLORS[univ.region]}}></span>
                          <span className="text-xs font-bold text-slate-600">{univ.region}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="text-sm font-bold text-slate-800 flex items-center gap-2">
                          {univ.school_name}
                          <span className={`px-1.5 py-0.5 rounded text-[8px] font-bold ${univ.status === 'NEW' ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-400'}`}>
                            {univ.status === 'NEW' ? 'NEW' : 'EXIST'}
                          </span>
                        </div>
                        <div className="text-[10px] text-slate-400">{univ.address}</div>
                      </td>
                      <td className="px-6 py-4 text-xs font-medium text-slate-600">{univ.proposal_range}</td>
                      <td className="px-6 py-4 text-right text-sm font-black text-indigo-600">{formatCurrency(univ.amount_sum)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Admin Panel */}
        {isAdminOpen && (
          <div className="absolute top-6 left-6 z-[2000] w-80">
            <div className="glass p-5 rounded-2xl shadow-2xl border border-indigo-100">
              <h3 className="text-sm font-bold text-slate-800 mb-4 flex items-center gap-2">
                <span className="w-1.5 h-4 bg-indigo-600 rounded-full"></span>
                제안 학교 등록
              </h3>
              <form onSubmit={handleAddData} className="space-y-3">
                <input 
                  required 
                  placeholder="학교명 (예: 한양대, 서울대)" 
                  className="w-full p-2.5 text-xs bg-white border border-slate-200 rounded-xl focus:ring-1 focus:ring-indigo-500 outline-none" 
                  value={formData.school_name} 
                  onChange={e => handleSchoolNameChange(e.target.value)} 
                />
                <div className="grid grid-cols-2 gap-2">
                  <select className="w-full p-2.5 text-xs bg-white border border-slate-200 rounded-xl outline-none" value={formData.industry} onChange={e => setFormData({...formData, industry: e.target.value})}>
                    {industries.filter(i => i !== '전체').map(i => <option key={i} value={i}>{i}</option>)}
                  </select>
                  <select className="w-full p-2.5 text-xs bg-white border border-slate-200 rounded-xl outline-none" value={formData.region} onChange={e => setFormData({...formData, region: e.target.value as Region})}>
                    {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                  </select>
                </div>
                <input required placeholder="제안 내용 (예: 반도체 인재 양성)" className="w-full p-2.5 text-xs bg-white border border-slate-200 rounded-xl outline-none" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
                <input required type="number" placeholder="예상금액 (원)" className="w-full p-2.5 text-xs bg-white border border-slate-200 rounded-xl outline-none" value={formData.amount_sum} onChange={e => setFormData({...formData, amount_sum: e.target.value})} />

                <div className="grid grid-cols-2 gap-2 pt-2">
                  <button type="button" onClick={() => setFormData({...formData, status: 'NEW'})} className={`py-2 rounded-xl text-xs font-bold border transition-all ${formData.status === 'NEW' ? 'bg-red-50 border-red-200 text-red-600' : 'bg-white text-slate-400 border-slate-200'}`}>신규 참여</button>
                  <button type="button" onClick={() => setFormData({...formData, status: 'EXISTING'})} className={`py-2 rounded-xl text-xs font-bold border transition-all ${formData.status === 'EXISTING' ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-400 border-slate-200'}`}>기존 운영</button>
                </div>

                <button type="submit" className="w-full bg-indigo-600 text-white py-3 rounded-xl text-sm font-bold shadow-lg shadow-indigo-100 transition-transform active:scale-95">제안서 데이터 저장</button>
              </form>
            </div>
          </div>
        )}

        {/* Legend */}
        {viewMode === 'map' && (
          <div className="absolute bottom-8 right-16 z-[1000] flex flex-col gap-4">
            <div className="glass p-4 rounded-2xl shadow-xl w-48">
              <h3 className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-3 border-b border-slate-100 pb-2">Region Colors</h3>
              <div className="grid grid-cols-1 gap-1.5">
                {Object.entries(REGION_COLORS).map(([name, color]) => (
                  <div key={name} className="flex items-center gap-2.5">
                    <span className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: color }}></span>
                    <span className="text-[11px] font-bold text-slate-600">{name}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS, UNIVERSITY_PRESETS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  const [data, setData] = useState<UniversityData[]>(MOCK_DATA);
  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [industryFilter, setIndustryFilter] = useState<string>('전체');

  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SEOUL,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'EXISTING' as 'NEW' | 'EXISTING',
    proposal_range: '',
    industry: '반도체'
  });

  const industries = ['전체', '반도체', '이차전지', '바이오', '디스플레이', '항공우주', '미래차', '인공지능'];

  const handleSchoolNameChange = (name: string) => {
    setFormData(prev => ({ ...prev, school_name: name }));
    const preset = UNIVERSITY_PRESETS[name];
    if (preset) {
      setFormData(prev => ({
        ...prev,
        school_name: name,
        region: preset.region,
        lat: preset.lat.toString(),
        lng: preset.lng.toString(),
        address: preset.address
      }));
    }
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const filteredData = data.filter(item => 
    industryFilter === '전체' || item.industry === industryFilter
  );

  const calculateRadius = (amount: number) => {
    const logValue = Math.log10(amount || 1);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const renderMarkers = () => {
    if (!mapInstance.current || !markersLayer.current || viewMode !== 'map') return;

    markersLayer.current.clearLayers();

    filteredData.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS[Region.ETC];
      const radius = calculateRadius(univ.amount_sum);
      const isNew = univ.status === 'NEW';

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: isNew ? '#ffffff' : color,
        weight: isNew ? 3 : 1.5,
        dashArray: isNew ? '5, 5' : null,
        opacity: 1,
        fillOpacity: 0.6
      });

      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
            <span style="font-size: 9px; color: ${color}; font-weight: 800; border: 1px solid ${color}; padding: 1px 4px; border-radius: 4px;">${univ.industry} | ${univ.region}</span>
            <span style="font-size: 9px; font-weight: 800; background: ${isNew ? '#EF4444' : '#475569'}; color: white; padding: 1px 4px; border-radius: 4px;">${isNew ? '신규참여' : '기존학교'}</span>
          </div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 2px;">${univ.school_name}</div>
          <div style="font-size: 10px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
          <div style="background: #f8fafc; padding: 8px; border-radius: 6px; margin-bottom: 8px;">
            <div style="font-size: 8px; color: #94a3b8; font-weight: 800; text-transform: uppercase;">제안 범위</div>
            <div style="font-size: 11px; color: #334155; font-weight: 600;">${univ.proposal_range}</div>
          </div>
          <div style="border-top: 1px solid #f1f5f9; padding-top: 6px;">
            <div style="font-size: 14px; font-weight: 800; color: ${color};">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, { closeButton: false }).addTo(markersLayer.current);
    });
  };

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current && !mapInstance.current) {
      const map = L.map(mapContainerRef.current, {
        center: [36.2, 127.8],
        zoom: 7.5,
        zoomControl: false
      });

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; CARTO'
      }).addTo(map);

      L.control.zoom({ position: 'bottomright' }).addTo(map);

      markersLayer.current = L.layerGroup().addTo(map);
      mapInstance.current = map;
      renderMarkers();
    }
  }, [viewMode]);

  useEffect(() => {
    if (viewMode === 'map') renderMarkers();
  }, [filteredData, viewMode]);

  const resetForm = () => {
    setFormData({
      school_name: '', region: Region.SEOUL, address: '', lat: '', lng: '', amount_sum: '', status: 'EXISTING', proposal_range: '', industry: '반도체'
    });
    setEditingId(null);
  };

  const handleAddOrUpdateData = (e: React.FormEvent) => {
    e.preventDefault();
    const payload: UniversityData = {
      school_id: editingId || `S${Date.now()}`,
      school_name: formData.school_name,
      region: formData.region,
      address: formData.address,
      lat: parseFloat(formData.lat) || 0,
      lng: parseFloat(formData.lng) || 0,
      amount_sum: parseInt(formData.amount_sum) || 0,
      status: formData.status,
      proposal_range: formData.proposal_range,
      industry: formData.industry
    };

    if (editingId) {
      setData(prev => prev.map(item => item.school_id === editingId ? payload : item));
    } else {
      setData(prev => [...prev, payload]);
    }

    resetForm();
    setIsAdminOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('정말로 이 학교의 제안 데이터를 삭제하시겠습니까?')) {
      setData(prev => prev.filter(item => item.school_id !== id));
    }
  };

  const startEdit = (univ: UniversityData) => {
    setEditingId(univ.school_id);
    setFormData({
      school_name: univ.school_name,
      region: univ.region as Region,
      address: univ.address,
      lat: univ.lat.toString(),
      lng: univ.lng.toString(),
      amount_sum: univ.amount_sum.toString(),
      status: univ.status,
      proposal_range: univ.proposal_range,
      industry: univ.industry
    });
    setIsAdminOpen(true);
  };

  const totalAmount = filteredData.reduce((acc, cur) => acc + cur.amount_sum, 0);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden text-slate-900">
      {/* Header */}
      <header className="h-16 flex items-center justify-between px-6 bg-white border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-lg text-white shadow-lg">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
            </svg>
          </div>
          <div>
            <h1 className="text-lg font-bold text-slate-800 leading-tight">2026 부트캠프 교육/세미나 제안</h1>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">National University Proposal Status</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <select 
            className="bg-slate-100 px-3 py-1.5 rounded-lg text-xs font-bold text-slate-600 outline-none border border-transparent focus:border-indigo-300 transition-all"
            value={industryFilter}
            onChange={(e) => setIndustryFilter(e.target.value)}
          >
            {industries.map(ind => <option key={ind} value={ind}>{ind} 분야</option>)}
          </select>

          <div className="bg-slate-100 p-1 rounded-xl flex items-center">
            <button onClick={() => setViewMode('map')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${viewMode === 'map' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>현황 지도</button>
            <button onClick={() => setViewMode('list')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${viewMode === 'list' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>학교 리스트</button>
          </div>

          <button 
            onClick={() => {
              if (isAdminOpen) resetForm();
              setIsAdminOpen(!isAdminOpen);
            }} 
            className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${isAdminOpen ? 'bg-slate-800 text-white' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-md shadow-indigo-100'}`}
          >
            {isAdminOpen ? '닫기' : '신규 등록'}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 relative overflow-hidden">
        {/* Map View */}
        <div className={`absolute inset-0 transition-opacity duration-300 ${viewMode === 'map' ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}>
          <div ref={mapContainerRef} id="map" />
        </div>

        {/* List View */}
        <div className={`absolute inset-0 bg-slate-50 overflow-auto p-8 transition-opacity duration-300 ${viewMode === 'list' ? 'opacity-100 z-20' : 'opacity-0 z-0'}`}>
          <div className="max-w-6xl mx-auto">
            <div className="flex items-center justify-between mb-8">
              <div>
                <h2 className="text-2xl font-black text-slate-800 tracking-tight">{industryFilter} 분야 상세 리스트</h2>
                <p className="text-sm text-slate-500 font-medium">총 {filteredData.length}개 학교의 제안 데이터가 관리되고 있습니다.</p>
              </div>
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-200 text-right">
                <span className="text-[10px] text-slate-400 font-black block uppercase tracking-widest mb-1">Total Estimated Amount</span>
                <span className="text-2xl font-black text-indigo-600">{formatCurrency(totalAmount)}</span>
              </div>
            </div>

            <div className="bg-white rounded-[2rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50/80 border-b border-slate-100 text-[11px] font-black text-slate-400 uppercase tracking-widest">
                  <tr>
                    <th className="px-8 py-5">산업분야</th>
                    <th className="px-6 py-5">권역</th>
                    <th className="px-6 py-5">학교명</th>
                    <th className="px-6 py-5">제안 내용</th>
                    <th className="px-6 py-5 text-right">예상 금액</th>
                    <th className="px-8 py-5 text-center">관리</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredData.map((univ) => (
                    <tr key={univ.school_id} className="hover:bg-indigo-50/30 transition-colors group">
                      <td className="px-8 py-5">
                        <span className="text-[10px] font-black text-slate-500 bg-white border border-slate-200 px-2 py-1 rounded-md shadow-sm">{univ.industry}</span>
                      </td>
                      <td className="px-6 py-5">
                        <div className="flex items-center gap-2.5">
                          <span className="w-2.5 h-2.5 rounded-full shadow-sm" style={{backgroundColor: REGION_COLORS[univ.region]}}></span>
                          <span className="text-xs font-bold text-slate-600">{univ.region}</span>
                        </div>
                      </td>
                      <td className="px-6 py-5">
                        <div className="text-sm font-black text-slate-800 flex items-center gap-2">
                          {univ.school_name}
                          {univ.status === 'NEW' && (
                            <span className="bg-red-500 text-white text-[8px] font-black px-1.5 py-0.5 rounded shadow-sm shadow-red-100">NEW</span>
                          )}
                        </div>
                        <div className="text-[10px] text-slate-400 font-semibold">{univ.address}</div>
                      </td>
                      <td className="px-6 py-5 text-xs font-bold text-slate-500 max-w-[200px] truncate">{univ.proposal_range}</td>
                      <td className="px-6 py-5 text-right text-sm font-black text-indigo-600">{formatCurrency(univ.amount_sum)}</td>
                      <td className="px-8 py-5 text-center">
                        <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button 
                            onClick={() => startEdit(univ)}
                            className="p-2 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-600 hover:text-white transition-all shadow-sm"
                            title="수정"
                          >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                            </svg>
                          </button>
                          <button 
                            onClick={() => handleDelete(univ.school_id)}
                            className="p-2 bg-red-50 text-red-600 rounded-lg hover:bg-red-600 hover:text-white transition-all shadow-sm"
                            title="삭제"
                          >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                            </svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Admin Panel Overlay */}
        {isAdminOpen && (
          <div className="absolute inset-0 z-[2000] flex items-center justify-center p-6 pointer-events-none">
            <div className="glass p-8 rounded-[2.5rem] shadow-2xl border border-white/60 w-[420px] pointer-events-auto animate-in zoom-in-95 duration-200">
              <div className="flex items-center justify-between mb-6">
                <h3 className="text-xl font-black text-slate-800 flex items-center gap-3">
                  <span className="w-2 h-6 bg-indigo-600 rounded-full"></span>
                  {editingId ? '학교 정보 수정' : '신규 학교 등록'}
                </h3>
                <button onClick={() => resetForm() || setIsAdminOpen(false)} className="text-slate-400 hover:text-slate-600">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>

              <form onSubmit={handleAddOrUpdateData} className="space-y-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">학교 정보</label>
                  <input 
                    required 
                    placeholder="학교명 (예: 한양대, 서울대)" 
                    className="w-full p-3 text-sm bg-white border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none transition-all shadow-sm" 
                    value={formData.school_name} 
                    onChange={e => handleSchoolNameChange(e.target.value)} 
                  />
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-1">산업 분야</label>
                    <select className="w-full p-3 text-sm bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500/20" value={formData.industry} onChange={e => setFormData({...formData, industry: e.target.value})}>
                      {industries.filter(i => i !== '전체').map(i => <option key={i} value={i}>{i}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-1">권역</label>
                    <select className="w-full p-3 text-sm bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500/20" value={formData.region} onChange={e => setFormData({...formData, region: e.target.value as Region})}>
                      {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                    </select>
                  </div>
                </div>

                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">제안 상세 내역</label>
                  <input required placeholder="제안 내용 (예: 반도체 인재 양성 특화)" className="w-full p-3 text-sm bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500/20 shadow-sm" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
                </div>

                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">예상 제안 금액 (KRW)</label>
                  <input required type="number" placeholder="금액 입력" className="w-full p-3 text-sm bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500/20 shadow-sm" value={formData.amount_sum} onChange={e => setFormData({...formData, amount_sum: e.target.value})} />
                </div>

                <div className="space-y-2 pt-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">운영 상태</label>
                  <div className="grid grid-cols-2 gap-3">
                    <button type="button" onClick={() => setFormData({...formData, status: 'NEW'})} className={`py-3 rounded-2xl text-xs font-black border transition-all shadow-sm ${formData.status === 'NEW' ? 'bg-red-500 text-white border-red-500 ring-4 ring-red-500/10' : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'}`}>신규 참여</button>
                    <button type="button" onClick={() => setFormData({...formData, status: 'EXISTING'})} className={`py-3 rounded-2xl text-xs font-black border transition-all shadow-sm ${formData.status === 'EXISTING' ? 'bg-indigo-600 text-white border-indigo-600 ring-4 ring-indigo-500/10' : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'}`}>기존 운영</button>
                  </div>
                </div>

                <div className="pt-4 flex gap-3">
                  <button type="button" onClick={() => resetForm() || setIsAdminOpen(false)} className="flex-1 bg-slate-100 text-slate-600 py-4 rounded-2xl text-sm font-black hover:bg-slate-200 transition-all">취소</button>
                  <button type="submit" className="flex-[2] bg-indigo-600 text-white py-4 rounded-2xl text-sm font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95">
                    {editingId ? '수정 사항 저장' : '데이터 등록 완료'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}

        {/* Legend */}
        {viewMode === 'map' && (
          <div className="absolute bottom-8 right-16 z-[1000] flex flex-col gap-4">
            <div className="glass p-5 rounded-3xl shadow-2xl w-52 border border-white/60">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4 border-b border-slate-100/50 pb-2">Region Matrix</h3>
              <div className="grid grid-cols-1 gap-2.5">
                {Object.entries(REGION_COLORS).map(([name, color]) => (
                  <div key={name} className="flex items-center gap-3">
                    <span className="w-3 h-3 rounded-full shadow-sm ring-2 ring-white" style={{ backgroundColor: color }}></span>
                    <span className="text-[11px] font-black text-slate-600">{name}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS, UNIVERSITY_PRESETS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  const [data, setData] = useState<UniversityData[]>(MOCK_DATA);
  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [industryFilter, setIndustryFilter] = useState<string>('전체');

  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SEOUL,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'EXISTING' as 'NEW' | 'EXISTING',
    proposal_range: '',
    industry: '반도체'
  });

  const industries = ['전체', '반도체', '이차전지', '바이오', '디스플레이', '항공우주', '미래차', '인공지능'];

  const handleSchoolNameChange = (name: string) => {
    setFormData(prev => ({ ...prev, school_name: name }));
    const preset = UNIVERSITY_PRESETS[name];
    if (preset) {
      setFormData(prev => ({
        ...prev,
        school_name: name,
        region: preset.region,
        lat: preset.lat.toString(),
        lng: preset.lng.toString(),
        address: preset.address
      }));
    }
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const filteredData = data.filter(item => 
    industryFilter === '전체' || item.industry === industryFilter
  );

  const calculateRadius = (amount: number) => {
    const logValue = Math.log10(amount || 1);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const renderMarkers = () => {
    if (!mapInstance.current || !markersLayer.current || viewMode !== 'map') return;

    markersLayer.current.clearLayers();

    filteredData.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS[Region.ETC];
      const radius = calculateRadius(univ.amount_sum);
      const isNew = univ.status === 'NEW';

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: isNew ? '#ffffff' : color,
        weight: isNew ? 3 : 1.5,
        dashArray: isNew ? '5, 5' : null,
        opacity: 1,
        fillOpacity: 0.6
      });

      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
            <span style="font-size: 9px; color: ${color}; font-weight: 800; border: 1px solid ${color}; padding: 1px 4px; border-radius: 4px;">${univ.industry} | ${univ.region}</span>
            <span style="font-size: 9px; font-weight: 800; background: ${isNew ? '#EF4444' : '#475569'}; color: white; padding: 1px 4px; border-radius: 4px;">${isNew ? '신규참여' : '기존학교'}</span>
          </div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 2px;">${univ.school_name}</div>
          <div style="font-size: 10px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
          <div style="background: #f8fafc; padding: 8px; border-radius: 6px; margin-bottom: 8px;">
            <div style="font-size: 8px; color: #94a3b8; font-weight: 800; text-transform: uppercase;">제안 범위</div>
            <div style="font-size: 11px; color: #334155; font-weight: 600;">${univ.proposal_range}</div>
          </div>
          <div style="border-top: 1px solid #f1f5f9; padding-top: 6px;">
            <div style="font-size: 14px; font-weight: 800; color: ${color};">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, { closeButton: false }).addTo(markersLayer.current);
    });
  };

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current && !mapInstance.current) {
      const map = L.map(mapContainerRef.current, {
        center: [36.2, 127.8],
        zoom: 7.5,
        zoomControl: false
      });

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; CARTO'
      }).addTo(map);

      L.control.zoom({ position: 'bottomright' }).addTo(map);

      markersLayer.current = L.layerGroup().addTo(map);
      mapInstance.current = map;
      renderMarkers();
    }
  }, [viewMode]);

  useEffect(() => {
    if (viewMode === 'map') renderMarkers();
  }, [filteredData, viewMode]);

  const resetForm = () => {
    setFormData({
      school_name: '', region: Region.SEOUL, address: '', lat: '', lng: '', amount_sum: '', status: 'EXISTING', proposal_range: '', industry: '반도체'
    });
    setEditingId(null);
  };

  const handleAddOrUpdateData = (e: React.FormEvent) => {
    e.preventDefault();
    const payload: UniversityData = {
      school_id: editingId || `S${Date.now()}`,
      school_name: formData.school_name,
      region: formData.region,
      address: formData.address,
      lat: parseFloat(formData.lat) || 0,
      lng: parseFloat(formData.lng) || 0,
      amount_sum: parseInt(formData.amount_sum) || 0,
      status: formData.status,
      proposal_range: formData.proposal_range,
      industry: formData.industry
    };

    if (editingId) {
      setData(prev => prev.map(item => item.school_id === editingId ? payload : item));
    } else {
      setData(prev => [...prev, payload]);
    }

    resetForm();
    setIsAdminOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('정말로 이 학교의 제안 데이터를 삭제하시겠습니까?')) {
      setData(prev => prev.filter(item => item.school_id !== id));
    }
  };

  const startEdit = (univ: UniversityData) => {
    setEditingId(univ.school_id);
    setFormData({
      school_name: univ.school_name,
      region: univ.region as Region,
      address: univ.address,
      lat: univ.lat.toString(),
      lng: univ.lng.toString(),
      amount_sum: univ.amount_sum.toString(),
      status: univ.status,
      proposal_range: univ.proposal_range,
      industry: univ.industry
    });
    setIsAdminOpen(true);
  };

  const totalAmount = filteredData.reduce((acc, cur) => acc + cur.amount_sum, 0);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden text-slate-900">
      {/* Header */}
      <header className="h-16 flex items-center justify-between px-6 bg-white border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-lg text-white shadow-lg">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
            </svg>
          </div>
          <div>
            <h1 className="text-lg font-bold text-slate-800 leading-tight">2026 부트캠프 교육/세미나 제안</h1>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">National University Proposal Status</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <select 
            className="bg-slate-100 px-3 py-1.5 rounded-lg text-xs font-bold text-slate-600 outline-none border border-transparent focus:border-indigo-300 transition-all"
            value={industryFilter}
            onChange={(e) => setIndustryFilter(e.target.value)}
          >
            {industries.map(ind => <option key={ind} value={ind}>{ind} 분야</option>)}
          </select>

          <div className="bg-slate-100 p-1 rounded-xl flex items-center">
            <button onClick={() => setViewMode('map')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${viewMode === 'map' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>현황 지도</button>
            <button onClick={() => setViewMode('list')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${viewMode === 'list' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>학교 리스트</button>
          </div>

          <button 
            onClick={() => {
              if (isAdminOpen) resetForm();
              setIsAdminOpen(!isAdminOpen);
            }} 
            className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${isAdminOpen ? 'bg-slate-800 text-white' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-md shadow-indigo-100'}`}
          >
            {isAdminOpen ? '닫기' : '신규 등록'}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 relative overflow-hidden">
        {/* Map View */}
        <div className={`absolute inset-0 transition-opacity duration-300 ${viewMode === 'map' ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}>
          <div ref={mapContainerRef} id="map" />
        </div>

        {/* List View */}
        <div className={`absolute inset-0 bg-slate-50 overflow-auto p-8 transition-opacity duration-300 ${viewMode === 'list' ? 'opacity-100 z-20' : 'opacity-0 z-0'}`}>
          <div className="max-w-6xl mx-auto">
            <div className="flex items-center justify-between mb-8">
              <div>
                <h2 className="text-2xl font-black text-slate-800 tracking-tight">{industryFilter} 분야 상세 리스트</h2>
                <p className="text-sm text-slate-500 font-medium">총 {filteredData.length}개 학교의 제안 데이터가 관리되고 있습니다.</p>
              </div>
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-200 text-right">
                <span className="text-[10px] text-slate-400 font-black block uppercase tracking-widest mb-1">Total Estimated Amount</span>
                <span className="text-2xl font-black text-indigo-600">{formatCurrency(totalAmount)}</span>
              </div>
            </div>

            <div className="bg-white rounded-[2rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50/80 border-b border-slate-100 text-[11px] font-black text-slate-400 uppercase tracking-widest">
                  <tr>
                    <th className="px-8 py-5">산업분야</th>
                    <th className="px-6 py-5">권역</th>
                    <th className="px-6 py-5">학교명</th>
                    <th className="px-6 py-5">제안 내용</th>
                    <th className="px-6 py-5 text-right">예상 금액</th>
                    <th className="px-8 py-5 text-center">관리</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredData.map((univ) => (
                    <tr key={univ.school_id} className="hover:bg-indigo-50/30 transition-colors group">
                      <td className="px-8 py-5">
                        <span className="text-[10px] font-black text-slate-500 bg-white border border-slate-200 px-2 py-1 rounded-md shadow-sm">{univ.industry}</span>
                      </td>
                      <td className="px-6 py-5">
                        <div className="flex items-center gap-2.5">
                          <span className="w-2.5 h-2.5 rounded-full shadow-sm" style={{backgroundColor: REGION_COLORS[univ.region]}}></span>
                          <span className="text-xs font-bold text-slate-600">{univ.region}</span>
                        </div>
                      </td>
                      <td className="px-6 py-5">
                        <div className="text-sm font-black text-slate-800 flex items-center gap-2">
                          {univ.school_name}
                          {univ.status === 'NEW' && (
                            <span className="bg-red-500 text-white text-[8px] font-black px-1.5 py-0.5 rounded shadow-sm shadow-red-100">NEW</span>
                          )}
                        </div>
                        <div className="text-[10px] text-slate-400 font-semibold">{univ.address}</div>
                      </td>
                      <td className="px-6 py-5 text-xs font-bold text-slate-500 max-w-[200px] truncate">{univ.proposal_range}</td>
                      <td className="px-6 py-5 text-right text-sm font-black text-indigo-600">{formatCurrency(univ.amount_sum)}</td>
                      <td className="px-8 py-5 text-center">
                        <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button 
                            onClick={() => startEdit(univ)}
                            className="p-2 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-600 hover:text-white transition-all shadow-sm"
                            title="수정"
                          >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                            </svg>
                          </button>
                          <button 
                            onClick={() => handleDelete(univ.school_id)}
                            className="p-2 bg-red-50 text-red-600 rounded-lg hover:bg-red-600 hover:text-white transition-all shadow-sm"
                            title="삭제"
                          >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                            </svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Admin Panel Overlay */}
        {isAdminOpen && (
          <div className="absolute inset-0 z-[2000] flex items-center justify-center p-6 pointer-events-none">
            <div className="glass p-8 rounded-[2.5rem] shadow-2xl border border-white/60 w-[420px] pointer-events-auto animate-in zoom-in-95 duration-200">
              <div className="flex items-center justify-between mb-6">
                <h3 className="text-xl font-black text-slate-800 flex items-center gap-3">
                  <span className="w-2 h-6 bg-indigo-600 rounded-full"></span>
                  {editingId ? '학교 정보 수정' : '신규 학교 등록'}
                </h3>
                {/* FIX: Avoid testing void return for truthiness */}
                <button onClick={() => { resetForm(); setIsAdminOpen(false); }} className="text-slate-400 hover:text-slate-600">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>

              <form onSubmit={handleAddOrUpdateData} className="space-y-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">학교 정보</label>
                  <input 
                    required 
                    placeholder="학교명 (예: 한양대, 서울대)" 
                    className="w-full p-3 text-sm bg-white border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none transition-all shadow-sm" 
                    value={formData.school_name} 
                    onChange={e => handleSchoolNameChange(e.target.value)} 
                  />
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-1">산업 분야</label>
                    <select className="w-full p-3 text-sm bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500/20" value={formData.industry} onChange={e => setFormData({...formData, industry: e.target.value})}>
                      {industries.filter(i => i !== '전체').map(i => <option key={i} value={i}>{i}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-1">권역</label>
                    <select className="w-full p-3 text-sm bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500/20" value={formData.region} onChange={e => setFormData({...formData, region: e.target.value as Region})}>
                      {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                    </select>
                  </div>
                </div>

                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">제안 상세 내역</label>
                  <input required placeholder="제안 내용 (예: 반도체 인재 양성 특화)" className="w-full p-3 text-sm bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500/20 shadow-sm" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
                </div>

                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">예상 제안 금액 (KRW)</label>
                  <input required type="number" placeholder="금액 입력" className="w-full p-3 text-sm bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500/20 shadow-sm" value={formData.amount_sum} onChange={e => setFormData({...formData, amount_sum: e.target.value})} />
                </div>

                <div className="space-y-2 pt-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">운영 상태</label>
                  <div className="grid grid-cols-2 gap-3">
                    <button type="button" onClick={() => setFormData({...formData, status: 'NEW'})} className={`py-3 rounded-2xl text-xs font-black border transition-all shadow-sm ${formData.status === 'NEW' ? 'bg-red-500 text-white border-red-500 ring-4 ring-red-500/10' : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'}`}>신규 참여</button>
                    <button type="button" onClick={() => setFormData({...formData, status: 'EXISTING'})} className={`py-3 rounded-2xl text-xs font-black border transition-all shadow-sm ${formData.status === 'EXISTING' ? 'bg-indigo-600 text-white border-indigo-600 ring-4 ring-indigo-500/10' : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'}`}>기존 운영</button>
                  </div>
                </div>

                <div className="pt-4 flex gap-3">
                  {/* FIX: Avoid testing void return for truthiness */}
                  <button type="button" onClick={() => { resetForm(); setIsAdminOpen(false); }} className="flex-1 bg-slate-100 text-slate-600 py-4 rounded-2xl text-sm font-black hover:bg-slate-200 transition-all">취소</button>
                  <button type="submit" className="flex-[2] bg-indigo-600 text-white py-4 rounded-2xl text-sm font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95">
                    {editingId ? '수정 사항 저장' : '데이터 등록 완료'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}

        {/* Legend */}
        {viewMode === 'map' && (
          <div className="absolute bottom-8 right-16 z-[1000] flex flex-col gap-4">
            <div className="glass p-5 rounded-3xl shadow-2xl w-52 border border-white/60">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4 border-b border-slate-100/50 pb-2">Region Matrix</h3>
              <div className="grid grid-cols-1 gap-2.5">
                {Object.entries(REGION_COLORS).map(([name, color]) => (
                  <div key={name} className="flex items-center gap-3">
                    <span className="w-3 h-3 rounded-full shadow-sm ring-2 ring-white" style={{ backgroundColor: color }}></span>
                    <span className="text-[11px] font-black text-slate-600">{name}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

export interface UniversityData {
  school_id: string;
  school_name: string;
  region: string;
  address: string;
  lat: number;
  lng: number;
  amount_sum: number;
  status: 'NEW' | 'EXISTING';
  proposal_range: string;
  industry: string;
  proposal_type: '교육 제안' | '세미나 제안'; // 추가: 제안 유형 구분
}

export enum Region {
  SEOUL = '서울',
  GYEONGGI_INCHEON = '경기/인천',
  DAEGYEONG = '대경권',
  DONGNAM = '동남권',
  CHUNGCHEONG = '충청권',
  HONAM = '호남권',
  GANGWON_JEONBUK_JEJU = '강원/전북/제주',
  ETC = '기타/미정'
}

import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS, UNIVERSITY_PRESETS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  const [data, setData] = useState<UniversityData[]>(MOCK_DATA);
  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [industryFilter, setIndustryFilter] = useState<string>('전체');
  const [typeFilter, setTypeFilter] = useState<string>('전체');

  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SEOUL,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'EXISTING' as 'NEW' | 'EXISTING',
    proposal_range: '',
    industry: '반도체',
    proposal_type: '교육 제안' as '교육 제안' | '세미나 제안'
  });

  const industries = ['전체', '반도체', '이차전지', '바이오', '디스플레이', '항공우주', '미래차', '인공지능'];
  const proposalTypes = ['전체', '교육 제안', '세미나 제안'];

  const handleSchoolNameChange = (name: string) => {
    setFormData(prev => ({ ...prev, school_name: name }));
    const preset = UNIVERSITY_PRESETS[name];
    if (preset) {
      setFormData(prev => ({
        ...prev,
        school_name: name,
        region: preset.region,
        lat: preset.lat.toString(),
        lng: preset.lng.toString(),
        address: preset.address
      }));
    }
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const filteredData = data.filter(item => 
    (industryFilter === '전체' || item.industry === industryFilter) &&
    (typeFilter === '전체' || item.proposal_type === typeFilter)
  );

  const calculateRadius = (amount: number) => {
    const logValue = Math.log10(amount || 1);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const renderMarkers = () => {
    if (!mapInstance.current || !markersLayer.current || viewMode !== 'map') return;

    markersLayer.current.clearLayers();

    filteredData.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS[Region.ETC];
      const radius = calculateRadius(univ.amount_sum);
      const isNew = univ.status === 'NEW';

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: isNew ? '#ffffff' : color,
        weight: isNew ? 3 : 1.5,
        dashArray: isNew ? '5, 5' : null,
        opacity: 1,
        fillOpacity: 0.6
      });

      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
            <span style="font-size: 9px; color: ${color}; font-weight: 800; border: 1px solid ${color}; padding: 1px 4px; border-radius: 4px;">${univ.industry} | ${univ.region}</span>
            <span style="font-size: 9px; font-weight: 800; background: ${univ.proposal_type === '교육 제안' ? '#2563EB' : '#7C3AED'}; color: white; padding: 1px 4px; border-radius: 4px;">${univ.proposal_type}</span>
          </div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 2px;">${univ.school_name}</div>
          <div style="font-size: 10px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
          <div style="background: #f8fafc; padding: 8px; border-radius: 6px; margin-bottom: 8px;">
            <div style="font-size: 8px; color: #94a3b8; font-weight: 800; text-transform: uppercase;">제안 범위</div>
            <div style="font-size: 11px; color: #334155; font-weight: 600;">${univ.proposal_range}</div>
          </div>
          <div style="border-top: 1px solid #f1f5f9; padding-top: 6px;">
            <div style="font-size: 14px; font-weight: 800; color: ${color};">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, { closeButton: false }).addTo(markersLayer.current);
    });
  };

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current && !mapInstance.current) {
      const map = L.map(mapContainerRef.current, {
        center: [36.2, 127.8],
        zoom: 7.5,
        zoomControl: false
      });

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; CARTO'
      }).addTo(map);

      L.control.zoom({ position: 'bottomright' }).addTo(map);

      markersLayer.current = L.layerGroup().addTo(map);
      mapInstance.current = map;
      renderMarkers();
    }
  }, [viewMode]);

  useEffect(() => {
    if (viewMode === 'map') renderMarkers();
  }, [filteredData, viewMode]);

  const resetForm = () => {
    setFormData({
      school_name: '', region: Region.SEOUL, address: '', lat: '', lng: '', amount_sum: '', status: 'EXISTING', proposal_range: '', industry: '반도체', proposal_type: '교육 제안'
    });
    setEditingId(null);
  };

  const handleAddOrUpdateData = (e: React.FormEvent) => {
    e.preventDefault();
    const payload: UniversityData = {
      school_id: editingId || `S${Date.now()}`,
      school_name: formData.school_name,
      region: formData.region,
      address: formData.address,
      lat: parseFloat(formData.lat) || 0,
      lng: parseFloat(formData.lng) || 0,
      amount_sum: parseInt(formData.amount_sum) || 0,
      status: formData.status,
      proposal_range: formData.proposal_range,
      industry: formData.industry,
      proposal_type: formData.proposal_type
    };

    if (editingId) {
      setData(prev => prev.map(item => item.school_id === editingId ? payload : item));
    } else {
      setData(prev => [...prev, payload]);
    }

    resetForm();
    setIsAdminOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('정말로 이 학교의 제안 데이터를 삭제하시겠습니까?')) {
      setData(prev => prev.filter(item => item.school_id !== id));
    }
  };

  const startEdit = (univ: UniversityData) => {
    setEditingId(univ.school_id);
    setFormData({
      school_name: univ.school_name,
      region: univ.region as Region,
      address: univ.address,
      lat: univ.lat.toString(),
      lng: univ.lng.toString(),
      amount_sum: univ.amount_sum.toString(),
      status: univ.status,
      proposal_range: univ.proposal_range,
      industry: univ.industry,
      proposal_type: univ.proposal_type
    });
    setIsAdminOpen(true);
  };

  const totalAmount = filteredData.reduce((acc, cur) => acc + cur.amount_sum, 0);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden text-slate-900">
      {/* Header */}
      <header className="h-20 flex items-center justify-between px-6 bg-white border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2.5 rounded-xl text-white shadow-lg">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" />
            </svg>
          </div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight leading-tight">2026 부트캠프 교육/세미나 제안</h1>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">National High-Tech Bootcamp Strategy</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {/* Filters Group */}
          <div className="flex items-center gap-2 bg-slate-100/80 p-1.5 rounded-2xl border border-slate-200/50 shadow-inner">
            <div className="flex flex-col px-2">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Industry</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={industryFilter}
                    onChange={(e) => setIndustryFilter(e.target.value)}
                >
                    {industries.map(ind => <option key={ind} value={ind}>{ind}</option>)}
                </select>
            </div>
            <div className="w-px h-6 bg-slate-300 mx-1"></div>
            <div className="flex flex-col px-2">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Proposal Type</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={typeFilter}
                    onChange={(e) => setTypeFilter(e.target.value)}
                >
                    {proposalTypes.map(type => <option key={type} value={type}>{type}</option>)}
                </select>
            </div>
          </div>

          <div className="bg-slate-100 p-1 rounded-2xl flex items-center shadow-inner">
            <button onClick={() => setViewMode('map')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'map' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}>Map</button>
            <button onClick={() => setViewMode('list')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'list' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}>List</button>
          </div>

          <button 
            onClick={() => {
              if (isAdminOpen) resetForm();
              setIsAdminOpen(!isAdminOpen);
            }} 
            className={`px-6 py-2.5 rounded-2xl text-xs font-black transition-all ${isAdminOpen ? 'bg-slate-800 text-white shadow-lg' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-xl shadow-indigo-200'}`}
          >
            {isAdminOpen ? '닫기' : '신규 등록'}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 relative overflow-hidden">
        {/* Map View */}
        <div className={`absolute inset-0 transition-opacity duration-500 ${viewMode === 'map' ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}>
          <div ref={mapContainerRef} id="map" />
        </div>

        {/* List View */}
        <div className={`absolute inset-0 bg-slate-50 overflow-auto p-10 transition-opacity duration-500 ${viewMode === 'list' ? 'opacity-100 z-20' : 'opacity-0 z-0'}`}>
          <div className="max-w-7xl mx-auto">
            <div className="flex items-end justify-between mb-10">
              <div>
                <div className="flex items-center gap-3 mb-2">
                   <span className="bg-indigo-600 text-white text-[10px] font-black px-2 py-1 rounded-lg shadow-sm tracking-widest uppercase">Dashboard</span>
                   <h2 className="text-3xl font-black text-slate-800 tracking-tighter">제안 상세 리스트</h2>
                </div>
                <p className="text-sm text-slate-400 font-bold uppercase tracking-wide">
                  {industryFilter} 산업 / {typeFilter} / 총 {filteredData.length}개 학교
                </p>
              </div>

              <div className="flex gap-4">
                <div className="bg-white p-6 rounded-[2rem] shadow-xl shadow-slate-200/50 border border-slate-100 text-right min-w-[240px]">
                  <span className="text-[10px] text-slate-400 font-black block uppercase tracking-[0.2em] mb-2">Selected Total</span>
                  <div className="flex items-baseline justify-end gap-1">
                    <span className="text-xs font-black text-indigo-400">₩</span>
                    <span className="text-3xl font-black text-indigo-600 tracking-tighter">{new Intl.NumberFormat('ko-KR').format(totalAmount)}</span>
                  </div>
                </div>
              </div>
            </div>

            <div className="bg-white rounded-[3rem] shadow-2xl shadow-slate-200/80 border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50/50 border-b border-slate-100 text-[11px] font-black text-slate-400 uppercase tracking-[0.15em]">
                  <tr>
                    <th className="px-10 py-6">유형</th>
                    <th className="px-6 py-6">산업분야</th>
                    <th className="px-6 py-6">권역</th>
                    <th className="px-6 py-6">학교명</th>
                    <th className="px-6 py-6">제안 내용</th>
                    <th className="px-6 py-6 text-right">예상 금액</th>
                    <th className="px-10 py-6 text-center">관리</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredData.map((univ) => (
                    <tr key={univ.school_id} className="hover:bg-indigo-50/40 transition-all group">
                      <td className="px-10 py-6">
                        <span className={`text-[9px] font-black px-2.5 py-1.5 rounded-xl shadow-sm border ${
                            univ.proposal_type === '교육 제안' 
                            ? 'bg-blue-50 text-blue-600 border-blue-100' 
                            : 'bg-purple-50 text-purple-600 border-purple-100'
                        }`}>
                            {univ.proposal_type}
                        </span>
                      </td>
                      <td className="px-6 py-6">
                        <span className="text-[10px] font-black text-slate-500 bg-white border border-slate-200 px-2 py-1.5 rounded-lg shadow-sm">{univ.industry}</span>
                      </td>
                      <td className="px-6 py-6">
                        <div className="flex items-center gap-3">
                          <span className="w-3 h-3 rounded-full shadow-inner ring-2 ring-white" style={{backgroundColor: REGION_COLORS[univ.region]}}></span>
                          <span className="text-xs font-black text-slate-600">{univ.region}</span>
                        </div>
                      </td>
                      <td className="px-6 py-6">
                        <div className="text-sm font-black text-slate-800 flex items-center gap-2">
                          {univ.school_name}
                          {univ.status === 'NEW' && (
                            <div className="flex h-2 w-2 relative">
                                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                                <span className="relative inline-flex rounded-full h-2 w-2 bg-red-500"></span>
                            </div>
                          )}
                        </div>
                        <div className="text-[10px] text-slate-400 font-bold uppercase">{univ.address}</div>
                      </td>
                      <td className="px-6 py-6 text-xs font-bold text-slate-500 max-w-[200px] truncate leading-relaxed">{univ.proposal_range}</td>
                      <td className="px-6 py-6 text-right">
                         <div className="text-sm font-black text-indigo-600">{formatCurrency(univ.amount_sum)}</div>
                         <div className="text-[9px] text-indigo-300 font-black uppercase">{univ.amount_sum > 1000000000 ? 'High Scale' : 'Mid Scale'}</div>
                      </td>
                      <td className="px-10 py-6 text-center">
                        <div className="flex items-center justify-center gap-3 opacity-0 group-hover:opacity-100 transition-all translate-x-4 group-hover:translate-x-0">
                          <button 
                            onClick={() => startEdit(univ)}
                            className="p-2.5 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-600 hover:text-white transition-all shadow-sm"
                            title="수정"
                          >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                            </svg>
                          </button>
                          <button 
                            onClick={() => handleDelete(univ.school_id)}
                            className="p-2.5 bg-red-50 text-red-600 rounded-xl hover:bg-red-600 hover:text-white transition-all shadow-sm"
                            title="삭제"
                          >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                            </svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Admin Panel Overlay */}
        {isAdminOpen && (
          <div className="absolute inset-0 z-[2000] flex items-center justify-center p-6 bg-slate-900/10 backdrop-blur-sm pointer-events-none">
            <div className="glass p-10 rounded-[3rem] shadow-2xl border border-white/80 w-[480px] pointer-events-auto animate-in fade-in zoom-in-95 duration-300">
              <div className="flex items-center justify-between mb-8">
                <div className="flex flex-col">
                    <span className="text-[10px] font-black text-indigo-500 uppercase tracking-widest mb-1">Proposal Entry</span>
                    <h3 className="text-2xl font-black text-slate-800 flex items-center gap-3">
                        {editingId ? '학교 정보 수정' : '신규 학교 등록'}
                    </h3>
                </div>
                <button onClick={() => { resetForm(); setIsAdminOpen(false); }} className="p-2 bg-slate-100 rounded-xl text-slate-400 hover:text-slate-600 hover:bg-slate-200 transition-all">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>

              <form onSubmit={handleAddOrUpdateData} className="space-y-6">
                <div className="space-y-4">
                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">학교명 및 위치</label>
                        <input 
                            required 
                            placeholder="학교명을 입력하세요" 
                            className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all shadow-sm" 
                            value={formData.school_name} 
                            onChange={e => handleSchoolNameChange(e.target.value)} 
                        />
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">산업 분야</label>
                            <select className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none focus:ring-4 focus:ring-indigo-500/10 shadow-sm" value={formData.industry} onChange={e => setFormData({...formData, industry: e.target.value})}>
                                {industries.filter(i => i !== '전체').map(i => <option key={i} value={i}>{i}</option>)}
                            </select>
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">제안 유형</label>
                            <select className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none focus:ring-4 focus:ring-indigo-500/10 shadow-sm" value={formData.proposal_type} onChange={e => setFormData({...formData, proposal_type: e.target.value as any})}>
                                <option value="교육 제안">교육 제안</option>
                                <option value="세미나 제안">세미나 제안</option>
                            </select>
                        </div>
                    </div>

                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">상세 제안 내용</label>
                        <input required placeholder="제안의 핵심 내용을 요약하세요" className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none focus:ring-4 focus:ring-indigo-500/10 shadow-sm" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
                    </div>

                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">예상 금액 (₩)</label>
                        <input required type="number" placeholder="금액 입력" className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none focus:ring-4 focus:ring-indigo-500/10 shadow-sm" value={formData.amount_sum} onChange={e => setFormData({...formData, amount_sum: e.target.value})} />
                    </div>
                </div>

                <div className="space-y-3 pt-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">운영 구분</label>
                  <div className="grid grid-cols-2 gap-4">
                    <button type="button" onClick={() => setFormData({...formData, status: 'NEW'})} className={`py-4 rounded-[1.25rem] text-xs font-black border transition-all shadow-sm ${formData.status === 'NEW' ? 'bg-red-500 text-white border-red-500 ring-4 ring-red-500/10 shadow-red-200' : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'}`}>신규 참여</button>
                    <button type="button" onClick={() => setFormData({...formData, status: 'EXISTING'})} className={`py-4 rounded-[1.25rem] text-xs font-black border transition-all shadow-sm ${formData.status === 'EXISTING' ? 'bg-indigo-600 text-white border-indigo-600 ring-4 ring-indigo-500/10 shadow-indigo-200' : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'}`}>기존 운영</button>
                  </div>
                </div>

                <div className="pt-6 flex gap-4">
                  <button type="button" onClick={() => { resetForm(); setIsAdminOpen(false); }} className="flex-1 bg-slate-100 text-slate-600 py-4.5 rounded-[1.5rem] text-sm font-black hover:bg-slate-200 transition-all">취소</button>
                  <button type="submit" className="flex-[2] bg-indigo-600 text-white py-4.5 rounded-[1.5rem] text-sm font-black shadow-2xl shadow-indigo-200 hover:bg-indigo-700 transition-all active:scale-95">
                    {editingId ? '수정 사항 저장' : '데이터 등록 완료'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}

        {/* Legend */}
        {viewMode === 'map' && (
          <div className="absolute bottom-10 right-10 z-[1000] flex flex-col gap-5">
            <div className="glass p-6 rounded-[2.5rem] shadow-2xl w-60 border border-white/80">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.25em] mb-5 border-b border-slate-100/60 pb-3">Regional Scale</h3>
              <div className="grid grid-cols-1 gap-3.5">
                {Object.entries(REGION_COLORS).map(([name, color]) => (
                  <div key={name} className="flex items-center gap-4 group cursor-default">
                    <span className="w-3.5 h-3.5 rounded-full shadow-inner ring-4 ring-white group-hover:scale-125 transition-transform" style={{ backgroundColor: color }}></span>
                    <span className="text-[11px] font-black text-slate-600 group-hover:text-indigo-600 transition-colors">{name}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

export interface UniversityData {
  school_id: string;
  school_name: string;
  region: string;
  address: string;
  lat: number;
  lng: number;
  amount_sum: number;
  status: 'NEW' | 'EXISTING';
  proposal_range: string;
  industry: string;
  proposal_types: ('교육 제안' | '세미나 제안')[]; // 배열로 변경하여 중복 지원
}

export enum Region {
  SEOUL = '서울',
  GYEONGGI_INCHEON = '경기/인천',
  DAEGYEONG = '대경권',
  DONGNAM = '동남권',
  CHUNGCHEONG = '충청권',
  HONAM = '호남권',
  GANGWON_JEONBUK_JEJU = '강원/전북/제주',
  ETC = '기타/미정'
}

import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS, UNIVERSITY_PRESETS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  const [data, setData] = useState<UniversityData[]>(MOCK_DATA);
  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [industryFilter, setIndustryFilter] = useState<string>('전체');
  const [typeFilter, setTypeFilter] = useState<string>('전체');

  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SEOUL,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'EXISTING' as 'NEW' | 'EXISTING',
    proposal_range: '',
    industry: '반도체',
    proposal_types: [] as ('교육 제안' | '세미나 제안')[]
  });

  const industries = ['전체', '반도체', '이차전지', '바이오', '디스플레이', '항공우주', '미래차', '인공지능'];
  const proposalTypesOptions = ['교육 제안', '세미나 제안'] as const;

  const handleSchoolNameChange = (name: string) => {
    setFormData(prev => ({ ...prev, school_name: name }));
    const preset = UNIVERSITY_PRESETS[name];
    if (preset) {
      setFormData(prev => ({
        ...prev,
        school_name: name,
        region: preset.region,
        lat: preset.lat.toString(),
        lng: preset.lng.toString(),
        address: preset.address
      }));
    }
  };

  const toggleProposalType = (type: '교육 제안' | '세미나 제안') => {
    setFormData(prev => {
      const isExist = prev.proposal_types.includes(type);
      if (isExist) {
        return { ...prev, proposal_types: prev.proposal_types.filter(t => t !== type) };
      } else {
        return { ...prev, proposal_types: [...prev.proposal_types, type] };
      }
    });
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const filteredData = data.filter(item => 
    (industryFilter === '전체' || item.industry === industryFilter) &&
    (typeFilter === '전체' || item.proposal_types.includes(typeFilter as any))
  );

  const calculateRadius = (amount: number) => {
    const logValue = Math.log10(amount || 1);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const renderMarkers = () => {
    if (!mapInstance.current || !markersLayer.current || viewMode !== 'map') return;

    markersLayer.current.clearLayers();

    filteredData.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS[Region.ETC];
      const radius = calculateRadius(univ.amount_sum);
      const isNew = univ.status === 'NEW';

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: isNew ? '#ffffff' : color,
        weight: isNew ? 3 : 1.5,
        dashArray: isNew ? '5, 5' : null,
        opacity: 1,
        fillOpacity: 0.6
      });

      const typeBadges = univ.proposal_types.map(t => 
        `<span style="font-size: 8px; font-weight: 800; background: ${t === '교육 제안' ? '#2563EB' : '#7C3AED'}; color: white; padding: 1px 4px; border-radius: 4px; margin-left: 2px;">${t}</span>`
      ).join('');

      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
            <span style="font-size: 9px; color: ${color}; font-weight: 800; border: 1px solid ${color}; padding: 1px 4px; border-radius: 4px;">${univ.industry}</span>
            <div style="display: flex;">${typeBadges}</div>
          </div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 2px;">${univ.school_name}</div>
          <div style="font-size: 10px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
          <div style="background: #f8fafc; padding: 8px; border-radius: 6px; margin-bottom: 8px;">
            <div style="font-size: 8px; color: #94a3b8; font-weight: 800; text-transform: uppercase;">제안 범위</div>
            <div style="font-size: 11px; color: #334155; font-weight: 600;">${univ.proposal_range}</div>
          </div>
          <div style="border-top: 1px solid #f1f5f9; padding-top: 6px;">
            <div style="font-size: 14px; font-weight: 800; color: ${color};">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, { closeButton: false }).addTo(markersLayer.current);
    });
  };

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current && !mapInstance.current) {
      const map = L.map(mapContainerRef.current, {
        center: [36.2, 127.8],
        zoom: 7.5,
        zoomControl: false
      });

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; CARTO'
      }).addTo(map);

      L.control.zoom({ position: 'bottomright' }).addTo(map);

      markersLayer.current = L.layerGroup().addTo(map);
      mapInstance.current = map;
      renderMarkers();
    }
  }, [viewMode]);

  useEffect(() => {
    if (viewMode === 'map') renderMarkers();
  }, [filteredData, viewMode]);

  const resetForm = () => {
    setFormData({
      school_name: '', region: Region.SEOUL, address: '', lat: '', lng: '', amount_sum: '', status: 'EXISTING', proposal_range: '', industry: '반도체', proposal_types: []
    });
    setEditingId(null);
  };

  const handleAddOrUpdateData = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.proposal_types.length === 0) {
      alert('제안 유형을 최소 하나 이상 선택해주세요.');
      return;
    }

    const payload: UniversityData = {
      school_id: editingId || `S${Date.now()}`,
      school_name: formData.school_name,
      region: formData.region,
      address: formData.address,
      lat: parseFloat(formData.lat) || 0,
      lng: parseFloat(formData.lng) || 0,
      amount_sum: parseInt(formData.amount_sum) || 0,
      status: formData.status,
      proposal_range: formData.proposal_range,
      industry: formData.industry,
      proposal_types: formData.proposal_types
    };

    if (editingId) {
      setData(prev => prev.map(item => item.school_id === editingId ? payload : item));
    } else {
      setData(prev => [...prev, payload]);
    }

    resetForm();
    setIsAdminOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('정말로 이 학교의 제안 데이터를 삭제하시겠습니까?')) {
      setData(prev => prev.filter(item => item.school_id !== id));
    }
  };

  const startEdit = (univ: UniversityData) => {
    setEditingId(univ.school_id);
    setFormData({
      school_name: univ.school_name,
      region: univ.region as Region,
      address: univ.address,
      lat: univ.lat.toString(),
      lng: univ.lng.toString(),
      amount_sum: univ.amount_sum.toString(),
      status: univ.status,
      proposal_range: univ.proposal_range,
      industry: univ.industry,
      proposal_types: [...univ.proposal_types]
    });
    setIsAdminOpen(true);
  };

  const totalAmount = filteredData.reduce((acc, cur) => acc + cur.amount_sum, 0);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden text-slate-900">
      {/* Header */}
      <header className="h-20 flex items-center justify-between px-6 bg-white border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2.5 rounded-xl text-white shadow-lg">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" />
            </svg>
          </div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight leading-tight">2026 부트캠프 교육/세미나 제안</h1>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">National High-Tech Bootcamp Strategy</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {/* Filters Group */}
          <div className="flex items-center gap-2 bg-slate-100/80 p-1.5 rounded-2xl border border-slate-200/50 shadow-inner">
            <div className="flex flex-col px-2">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Industry</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={industryFilter}
                    onChange={(e) => setIndustryFilter(e.target.value)}
                >
                    {industries.map(ind => <option key={ind} value={ind}>{ind}</option>)}
                </select>
            </div>
            <div className="w-px h-6 bg-slate-300 mx-1"></div>
            <div className="flex flex-col px-2">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Filter Type</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={typeFilter}
                    onChange={(e) => setTypeFilter(e.target.value)}
                >
                    <option value="전체">전체 보기</option>
                    <option value="교육 제안">교육 제안 포함</option>
                    <option value="세미나 제안">세미나 제안 포함</option>
                </select>
            </div>
          </div>

          <div className="bg-slate-100 p-1 rounded-2xl flex items-center shadow-inner">
            <button onClick={() => setViewMode('map')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'map' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}>Map</button>
            <button onClick={() => setViewMode('list')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'list' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}>List</button>
          </div>

          <button 
            onClick={() => {
              if (isAdminOpen) resetForm();
              setIsAdminOpen(!isAdminOpen);
            }} 
            className={`px-6 py-2.5 rounded-2xl text-xs font-black transition-all ${isAdminOpen ? 'bg-slate-800 text-white shadow-lg' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-xl shadow-indigo-200'}`}
          >
            {isAdminOpen ? '닫기' : '신규 등록'}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 relative overflow-hidden">
        {/* Map View */}
        <div className={`absolute inset-0 transition-opacity duration-500 ${viewMode === 'map' ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}>
          <div ref={mapContainerRef} id="map" />
        </div>

        {/* List View */}
        <div className={`absolute inset-0 bg-slate-50 overflow-auto p-10 transition-opacity duration-500 ${viewMode === 'list' ? 'opacity-100 z-20' : 'opacity-0 z-0'}`}>
          <div className="max-w-7xl mx-auto">
            <div className="flex items-end justify-between mb-10">
              <div>
                <div className="flex items-center gap-3 mb-2">
                   <span className="bg-indigo-600 text-white text-[10px] font-black px-2 py-1 rounded-lg shadow-sm tracking-widest uppercase">Dashboard</span>
                   <h2 className="text-3xl font-black text-slate-800 tracking-tighter">제안 상세 리스트</h2>
                </div>
                <p className="text-sm text-slate-400 font-bold uppercase tracking-wide">
                  {industryFilter} 산업 / {typeFilter} / 총 {filteredData.length}개 학교
                </p>
              </div>

              <div className="flex gap-4">
                <div className="bg-white p-6 rounded-[2rem] shadow-xl shadow-slate-200/50 border border-slate-100 text-right min-w-[240px]">
                  <span className="text-[10px] text-slate-400 font-black block uppercase tracking-[0.2em] mb-2">Selected Total</span>
                  <div className="flex items-baseline justify-end gap-1">
                    <span className="text-xs font-black text-indigo-400">₩</span>
                    <span className="text-3xl font-black text-indigo-600 tracking-tighter">{new Intl.NumberFormat('ko-KR').format(totalAmount)}</span>
                  </div>
                </div>
              </div>
            </div>

            <div className="bg-white rounded-[3rem] shadow-2xl shadow-slate-200/80 border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50/50 border-b border-slate-100 text-[11px] font-black text-slate-400 uppercase tracking-[0.15em]">
                  <tr>
                    <th className="px-10 py-6">제안 유형</th>
                    <th className="px-6 py-6">산업분야</th>
                    <th className="px-6 py-6">권역</th>
                    <th className="px-6 py-6">학교명</th>
                    <th className="px-6 py-6">제안 내용</th>
                    <th className="px-6 py-6 text-right">예상 금액</th>
                    <th className="px-10 py-6 text-center">관리</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredData.map((univ) => (
                    <tr key={univ.school_id} className="hover:bg-indigo-50/40 transition-all group">
                      <td className="px-10 py-6">
                        <div className="flex flex-wrap gap-1">
                          {univ.proposal_types.map(t => (
                            <span key={t} className={`text-[9px] font-black px-2 py-1 rounded-lg shadow-sm border ${
                                t === '교육 제안' 
                                ? 'bg-blue-50 text-blue-600 border-blue-100' 
                                : 'bg-purple-50 text-purple-600 border-purple-100'
                            }`}>
                                {t}
                            </span>
                          ))}
                        </div>
                      </td>
                      <td className="px-6 py-6">
                        <span className="text-[10px] font-black text-slate-500 bg-white border border-slate-200 px-2 py-1.5 rounded-lg shadow-sm">{univ.industry}</span>
                      </td>
                      <td className="px-6 py-6">
                        <div className="flex items-center gap-3">
                          <span className="w-3 h-3 rounded-full shadow-inner ring-2 ring-white" style={{backgroundColor: REGION_COLORS[univ.region]}}></span>
                          <span className="text-xs font-black text-slate-600">{univ.region}</span>
                        </div>
                      </td>
                      <td className="px-6 py-6">
                        <div className="text-sm font-black text-slate-800 flex items-center gap-2">
                          {univ.school_name}
                          {univ.status === 'NEW' && (
                            <div className="flex h-2 w-2 relative">
                                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                                <span className="relative inline-flex rounded-full h-2 w-2 bg-red-500"></span>
                            </div>
                          )}
                        </div>
                        <div className="text-[10px] text-slate-400 font-bold uppercase">{univ.address}</div>
                      </td>
                      <td className="px-6 py-6 text-xs font-bold text-slate-500 max-w-[200px] truncate leading-relaxed">{univ.proposal_range}</td>
                      <td className="px-6 py-6 text-right">
                         <div className="text-sm font-black text-indigo-600">{formatCurrency(univ.amount_sum)}</div>
                         <div className="text-[9px] text-indigo-300 font-black uppercase">{univ.amount_sum > 1000000000 ? 'High Scale' : 'Mid Scale'}</div>
                      </td>
                      <td className="px-10 py-6 text-center">
                        <div className="flex items-center justify-center gap-3 opacity-0 group-hover:opacity-100 transition-all translate-x-4 group-hover:translate-x-0">
                          <button 
                            onClick={() => startEdit(univ)}
                            className="p-2.5 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-600 hover:text-white transition-all shadow-sm"
                            title="수정"
                          >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                            </svg>
                          </button>
                          <button 
                            onClick={() => handleDelete(univ.school_id)}
                            className="p-2.5 bg-red-50 text-red-600 rounded-xl hover:bg-red-600 hover:text-white transition-all shadow-sm"
                            title="삭제"
                          >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                            </svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Admin Panel Overlay */}
        {isAdminOpen && (
          <div className="absolute inset-0 z-[2000] flex items-center justify-center p-6 bg-slate-900/10 backdrop-blur-sm pointer-events-none">
            <div className="glass p-10 rounded-[3rem] shadow-2xl border border-white/80 w-[480px] pointer-events-auto animate-in fade-in zoom-in-95 duration-300">
              <div className="flex items-center justify-between mb-8">
                <div className="flex flex-col">
                    <span className="text-[10px] font-black text-indigo-500 uppercase tracking-widest mb-1">Proposal Entry</span>
                    <h3 className="text-2xl font-black text-slate-800 flex items-center gap-3">
                        {editingId ? '학교 정보 수정' : '신규 학교 등록'}
                    </h3>
                </div>
                <button onClick={() => { resetForm(); setIsAdminOpen(false); }} className="p-2 bg-slate-100 rounded-xl text-slate-400 hover:text-slate-600 hover:bg-slate-200 transition-all">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>

              <form onSubmit={handleAddOrUpdateData} className="space-y-6">
                <div className="space-y-4">
                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">학교명 및 위치</label>
                        <input 
                            required 
                            placeholder="학교명을 입력하세요" 
                            className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all shadow-sm" 
                            value={formData.school_name} 
                            onChange={e => handleSchoolNameChange(e.target.value)} 
                        />
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">산업 분야</label>
                            <select className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none focus:ring-4 focus:ring-indigo-500/10 shadow-sm" value={formData.industry} onChange={e => setFormData({...formData, industry: e.target.value})}>
                                {industries.filter(i => i !== '전체').map(i => <option key={i} value={i}>{i}</option>)}
                            </select>
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">권역</label>
                            <select className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none focus:ring-4 focus:ring-indigo-500/10 shadow-sm" value={formData.region} onChange={e => setFormData({...formData, region: e.target.value as Region})}>
                                {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                            </select>
                        </div>
                    </div>

                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">제안 유형 (중복 선택 가능)</label>
                        <div className="flex gap-2 pt-1">
                          {proposalTypesOptions.map(t => (
                            <button
                              key={t}
                              type="button"
                              onClick={() => toggleProposalType(t)}
                              className={`flex-1 py-3 rounded-xl text-xs font-black border transition-all ${
                                formData.proposal_types.includes(t)
                                ? 'bg-indigo-600 text-white border-indigo-600 shadow-md'
                                : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'
                              }`}
                            >
                              {t}
                            </button>
                          ))}
                        </div>
                    </div>

                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">상세 제안 내용</label>
                        <input required placeholder="제안의 핵심 내용을 요약하세요" className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none focus:ring-4 focus:ring-indigo-500/10 shadow-sm" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
                    </div>

                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">예상 금액 (₩)</label>
                        <input required type="number" placeholder="금액 입력" className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none focus:ring-4 focus:ring-indigo-500/10 shadow-sm" value={formData.amount_sum} onChange={e => setFormData({...formData, amount_sum: e.target.value})} />
                    </div>
                </div>

                <div className="space-y-3 pt-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">운영 구분</label>
                  <div className="grid grid-cols-2 gap-4">
                    <button type="button" onClick={() => setFormData({...formData, status: 'NEW'})} className={`py-4 rounded-[1.25rem] text-xs font-black border transition-all shadow-sm ${formData.status === 'NEW' ? 'bg-red-500 text-white border-red-500 ring-4 ring-red-500/10 shadow-red-200' : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'}`}>신규 참여</button>
                    <button type="button" onClick={() => setFormData({...formData, status: 'EXISTING'})} className={`py-4 rounded-[1.25rem] text-xs font-black border transition-all shadow-sm ${formData.status === 'EXISTING' ? 'bg-indigo-600 text-white border-indigo-600 ring-4 ring-indigo-500/10 shadow-indigo-200' : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'}`}>기존 운영</button>
                  </div>
                </div>

                <div className="pt-6 flex gap-4">
                  <button type="button" onClick={() => { resetForm(); setIsAdminOpen(false); }} className="flex-1 bg-slate-100 text-slate-600 py-4.5 rounded-[1.5rem] text-sm font-black hover:bg-slate-200 transition-all">취소</button>
                  <button type="submit" className="flex-[2] bg-indigo-600 text-white py-4.5 rounded-[1.5rem] text-sm font-black shadow-2xl shadow-indigo-200 hover:bg-indigo-700 transition-all active:scale-95">
                    {editingId ? '수정 사항 저장' : '데이터 등록 완료'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}

        {/* Legend */}
        {viewMode === 'map' && (
          <div className="absolute bottom-10 right-10 z-[1000] flex flex-col gap-5">
            <div className="glass p-6 rounded-[2.5rem] shadow-2xl w-60 border border-white/80">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.25em] mb-5 border-b border-slate-100/60 pb-3">Regional Scale</h3>
              <div className="grid grid-cols-1 gap-3.5">
                {Object.entries(REGION_COLORS).map(([name, color]) => (
                  <div key={name} className="flex items-center gap-4 group cursor-default">
                    <span className="w-3.5 h-3.5 rounded-full shadow-inner ring-4 ring-white group-hover:scale-125 transition-transform" style={{ backgroundColor: color }}></span>
                    <span className="text-[11px] font-black text-slate-600 group-hover:text-indigo-600 transition-colors">{name}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS, UNIVERSITY_PRESETS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  const [data, setData] = useState<UniversityData[]>(MOCK_DATA);
  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [industryFilter, setIndustryFilter] = useState<string>('전체');
  const [typeFilter, setTypeFilter] = useState<string>('전체');

  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SEOUL,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'EXISTING' as 'NEW' | 'EXISTING',
    proposal_range: '',
    industry: '반도체',
    proposal_types: [] as ('교육 제안' | '세미나 제안')[]
  });

  const industries = ['전체', '반도체', '이차전지', '바이오', '디스플레이', '항공우주', '미래차', '인공지능'];
  const proposalTypesOptions = ['교육 제안', '세미나 제안'] as const;

  const handleSchoolNameChange = (name: string) => {
    setFormData(prev => ({ ...prev, school_name: name }));
    const preset = UNIVERSITY_PRESETS[name];
    if (preset) {
      setFormData(prev => ({
        ...prev,
        school_name: name,
        region: preset.region,
        lat: preset.lat.toString(),
        lng: preset.lng.toString(),
        address: preset.address
      }));
    }
  };

  const toggleProposalType = (type: '교육 제안' | '세미나 제안') => {
    setFormData(prev => {
      const isExist = prev.proposal_types.includes(type);
      if (isExist) {
        return { ...prev, proposal_types: prev.proposal_types.filter(t => t !== type) };
      } else {
        return { ...prev, proposal_types: [...prev.proposal_types, type] };
      }
    });
  };

  const formatCurrency = (amount: number) => {
    if (amount === 0) return "금액 미정";
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const filteredData = data.filter(item => 
    (industryFilter === '전체' || item.industry === industryFilter) &&
    (typeFilter === '전체' || (item.proposal_types && item.proposal_types.includes(typeFilter as any)))
  );

  const calculateRadius = (amount: number) => {
    if (amount === 0) return 12; // 미정일 경우 기본 크기
    const logValue = Math.log10(amount || 1);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const renderMarkers = () => {
    if (!mapInstance.current || !markersLayer.current || viewMode !== 'map') return;

    markersLayer.current.clearLayers();

    filteredData.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS[Region.ETC];
      const radius = calculateRadius(univ.amount_sum);
      const isNew = univ.status === 'NEW';

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: isNew ? '#ffffff' : color,
        weight: isNew ? 3 : 1.5,
        dashArray: isNew ? '5, 5' : null,
        opacity: 1,
        fillOpacity: 0.6
      });

      const typeBadges = univ.proposal_types && univ.proposal_types.length > 0 
        ? univ.proposal_types.map(t => 
            `<span style="font-size: 8px; font-weight: 800; background: ${t === '교육 제안' ? '#2563EB' : '#7C3AED'}; color: white; padding: 1px 4px; border-radius: 4px; margin-left: 2px;">${t}</span>`
          ).join('')
        : `<span style="font-size: 8px; font-weight: 800; background: #94a3b8; color: white; padding: 1px 4px; border-radius: 4px;">유형 미정</span>`;

      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
            <span style="font-size: 9px; color: ${color}; font-weight: 800; border: 1px solid ${color}; padding: 1px 4px; border-radius: 4px;">${univ.industry}</span>
            <div style="display: flex;">${typeBadges}</div>
          </div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 2px;">${univ.school_name}</div>
          <div style="font-size: 10px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
          <div style="background: #f8fafc; padding: 8px; border-radius: 6px; margin-bottom: 8px;">
            <div style="font-size: 8px; color: #94a3b8; font-weight: 800; text-transform: uppercase;">참여 기업 / 범위</div>
            <div style="font-size: 11px; color: #334155; font-weight: 600;">${univ.proposal_range}</div>
          </div>
          <div style="border-top: 1px solid #f1f5f9; padding-top: 6px;">
            <div style="font-size: 14px; font-weight: 800; color: ${univ.amount_sum === 0 ? '#94a3b8' : color};">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, { closeButton: false }).addTo(markersLayer.current);
    });
  };

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current && !mapInstance.current) {
      const map = L.map(mapContainerRef.current, {
        center: [36.2, 127.8],
        zoom: 7.5,
        zoomControl: false
      });

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; CARTO'
      }).addTo(map);

      L.control.zoom({ position: 'bottomright' }).addTo(map);

      markersLayer.current = L.layerGroup().addTo(map);
      mapInstance.current = map;
      renderMarkers();
    }
  }, [viewMode]);

  useEffect(() => {
    if (viewMode === 'map') renderMarkers();
  }, [filteredData, viewMode]);

  const resetForm = () => {
    setFormData({
      school_name: '', region: Region.SEOUL, address: '', lat: '', lng: '', amount_sum: '', status: 'EXISTING', proposal_range: '', industry: '반도체', proposal_types: []
    });
    setEditingId(null);
  };

  const handleAddOrUpdateData = (e: React.FormEvent) => {
    e.preventDefault();
    const payload: UniversityData = {
      school_id: editingId || `S${Date.now()}`,
      school_name: formData.school_name,
      region: formData.region,
      address: formData.address,
      lat: parseFloat(formData.lat) || 0,
      lng: parseFloat(formData.lng) || 0,
      amount_sum: parseInt(formData.amount_sum) || 0,
      status: formData.status,
      proposal_range: formData.proposal_range,
      industry: formData.industry,
      proposal_types: formData.proposal_types
    };

    if (editingId) {
      setData(prev => prev.map(item => item.school_id === editingId ? payload : item));
    } else {
      setData(prev => [...prev, payload]);
    }

    resetForm();
    setIsAdminOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('정말로 이 학교의 제안 데이터를 삭제하시겠습니까?')) {
      setData(prev => prev.filter(item => item.school_id !== id));
    }
  };

  const startEdit = (univ: UniversityData) => {
    setEditingId(univ.school_id);
    setFormData({
      school_name: univ.school_name,
      region: univ.region as Region,
      address: univ.address,
      lat: univ.lat.toString(),
      lng: univ.lng.toString(),
      amount_sum: univ.amount_sum.toString(),
      status: univ.status,
      proposal_range: univ.proposal_range,
      industry: univ.industry,
      proposal_types: [...univ.proposal_types]
    });
    setIsAdminOpen(true);
  };

  const totalAmount = filteredData.reduce((acc, cur) => acc + cur.amount_sum, 0);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden text-slate-900">
      {/* Header */}
      <header className="h-20 flex items-center justify-between px-6 bg-white border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2.5 rounded-xl text-white shadow-lg">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" />
            </svg>
          </div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight leading-tight">2026 부트캠프 교육/세미나 제안</h1>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">National High-Tech Bootcamp Strategy</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {/* Filters Group */}
          <div className="flex items-center gap-2 bg-slate-100/80 p-1.5 rounded-2xl border border-slate-200/50 shadow-inner">
            <div className="flex flex-col px-2">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Industry</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={industryFilter}
                    onChange={(e) => setIndustryFilter(e.target.value)}
                >
                    {industries.map(ind => <option key={ind} value={ind}>{ind}</option>)}
                </select>
            </div>
            <div className="w-px h-6 bg-slate-300 mx-1"></div>
            <div className="flex flex-col px-2">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Filter Type</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={typeFilter}
                    onChange={(e) => setTypeFilter(e.target.value)}
                >
                    <option value="전체">전체 보기</option>
                    <option value="교육 제안">교육 제안 포함</option>
                    <option value="세미나 제안">세미나 제안 포함</option>
                </select>
            </div>
          </div>

          <div className="bg-slate-100 p-1 rounded-2xl flex items-center shadow-inner">
            <button onClick={() => setViewMode('map')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'map' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}>Map</button>
            <button onClick={() => setViewMode('list')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'list' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}>List</button>
          </div>

          <button 
            onClick={() => {
              if (isAdminOpen) resetForm();
              setIsAdminOpen(!isAdminOpen);
            }} 
            className={`px-6 py-2.5 rounded-2xl text-xs font-black transition-all ${isAdminOpen ? 'bg-slate-800 text-white shadow-lg' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-xl shadow-indigo-200'}`}
          >
            {isAdminOpen ? '닫기' : '신규 등록'}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 relative overflow-hidden">
        {/* Map View */}
        <div className={`absolute inset-0 transition-opacity duration-500 ${viewMode === 'map' ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}>
          <div ref={mapContainerRef} id="map" />
        </div>

        {/* List View */}
        <div className={`absolute inset-0 bg-slate-50 overflow-auto p-10 transition-opacity duration-500 ${viewMode === 'list' ? 'opacity-100 z-20' : 'opacity-0 z-0'}`}>
          <div className="max-w-7xl mx-auto">
            <div className="flex items-end justify-between mb-10">
              <div>
                <div className="flex items-center gap-3 mb-2">
                   <span className="bg-indigo-600 text-white text-[10px] font-black px-2 py-1 rounded-lg shadow-sm tracking-widest uppercase">Dashboard</span>
                   <h2 className="text-3xl font-black text-slate-800 tracking-tighter">제안 상세 리스트</h2>
                </div>
                <p className="text-sm text-slate-400 font-bold uppercase tracking-wide">
                  {industryFilter} 산업 / {typeFilter} / 총 {filteredData.length}개 학교
                </p>
              </div>

              <div className="flex gap-4">
                <div className="bg-white p-6 rounded-[2rem] shadow-xl shadow-slate-200/50 border border-slate-100 text-right min-w-[240px]">
                  <span className="text-[10px] text-slate-400 font-black block uppercase tracking-[0.2em] mb-2">Selected Total</span>
                  <div className="flex items-baseline justify-end gap-1">
                    <span className="text-xs font-black text-indigo-400">₩</span>
                    <span className="text-3xl font-black text-indigo-600 tracking-tighter">{new Intl.NumberFormat('ko-KR').format(totalAmount)}</span>
                  </div>
                </div>
              </div>
            </div>

            <div className="bg-white rounded-[3rem] shadow-2xl shadow-slate-200/80 border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50/50 border-b border-slate-100 text-[11px] font-black text-slate-400 uppercase tracking-[0.15em]">
                  <tr>
                    <th className="px-10 py-6">제안 유형</th>
                    <th className="px-6 py-6">산업분야</th>
                    <th className="px-6 py-6">권역</th>
                    <th className="px-6 py-6">학교명</th>
                    <th className="px-6 py-6">참여 기업</th>
                    <th className="px-6 py-6 text-right">예상 금액</th>
                    <th className="px-10 py-6 text-center">관리</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredData.map((univ) => (
                    <tr key={univ.school_id} className="hover:bg-indigo-50/40 transition-all group">
                      <td className="px-10 py-6">
                        <div className="flex flex-wrap gap-1">
                          {univ.proposal_types && univ.proposal_types.length > 0 ? (
                            univ.proposal_types.map(t => (
                              <span key={t} className={`text-[9px] font-black px-2 py-1 rounded-lg shadow-sm border ${
                                  t === '교육 제안' 
                                  ? 'bg-blue-50 text-blue-600 border-blue-100' 
                                  : 'bg-purple-50 text-purple-600 border-purple-100'
                              }`}>
                                  {t}
                              </span>
                            ))
                          ) : (
                            <span className="text-[9px] font-black px-2 py-1 rounded-lg shadow-sm border bg-slate-100 text-slate-400 border-slate-200 italic">미정</span>
                          )}
                        </div>
                      </td>
                      <td className="px-6 py-6">
                        <span className="text-[10px] font-black text-slate-500 bg-white border border-slate-200 px-2 py-1.5 rounded-lg shadow-sm">{univ.industry}</span>
                      </td>
                      <td className="px-6 py-6">
                        <div className="flex items-center gap-3">
                          <span className="w-3 h-3 rounded-full shadow-inner ring-2 ring-white" style={{backgroundColor: REGION_COLORS[univ.region] || '#94a3b8'}}></span>
                          <span className="text-xs font-black text-slate-600">{univ.region}</span>
                        </div>
                      </td>
                      <td className="px-6 py-6">
                        <div className="text-sm font-black text-slate-800 flex items-center gap-2">
                          {univ.school_name}
                          {univ.status === 'NEW' && (
                            <div className="flex h-2 w-2 relative">
                                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                                <span className="relative inline-flex rounded-full h-2 w-2 bg-red-500"></span>
                            </div>
                          )}
                        </div>
                        <div className="text-[10px] text-slate-400 font-bold uppercase">{univ.address}</div>
                      </td>
                      <td className="px-6 py-6 text-xs font-bold text-slate-500 max-w-[200px] truncate leading-relaxed">{univ.proposal_range}</td>
                      <td className="px-6 py-6 text-right">
                         <div className={`text-sm font-black ${univ.amount_sum === 0 ? 'text-slate-300 italic' : 'text-indigo-600'}`}>
                           {formatCurrency(univ.amount_sum)}
                         </div>
                         {univ.amount_sum > 0 && (
                            <div className="text-[9px] text-indigo-300 font-black uppercase">{univ.amount_sum > 1000000000 ? 'High Scale' : 'Mid Scale'}</div>
                         )}
                      </td>
                      <td className="px-10 py-6 text-center">
                        <div className="flex items-center justify-center gap-3 opacity-0 group-hover:opacity-100 transition-all translate-x-4 group-hover:translate-x-0">
                          <button 
                            onClick={() => startEdit(univ)}
                            className="p-2.5 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-600 hover:text-white transition-all shadow-sm"
                            title="수정"
                          >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                            </svg>
                          </button>
                          <button 
                            onClick={() => handleDelete(univ.school_id)}
                            className="p-2.5 bg-red-50 text-red-600 rounded-xl hover:bg-red-600 hover:text-white transition-all shadow-sm"
                            title="삭제"
                          >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                            </svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Admin Panel Overlay */}
        {isAdminOpen && (
          <div className="absolute inset-0 z-[2000] flex items-center justify-center p-6 bg-slate-900/10 backdrop-blur-sm pointer-events-none">
            <div className="glass p-10 rounded-[3rem] shadow-2xl border border-white/80 w-[480px] pointer-events-auto animate-in fade-in zoom-in-95 duration-300">
              <div className="flex items-center justify-between mb-8">
                <div className="flex flex-col">
                    <span className="text-[10px] font-black text-indigo-500 uppercase tracking-widest mb-1">Proposal Entry</span>
                    <h3 className="text-2xl font-black text-slate-800 flex items-center gap-3">
                        {editingId ? '학교 정보 수정' : '신규 학교 등록'}
                    </h3>
                </div>
                <button onClick={() => { resetForm(); setIsAdminOpen(false); }} className="p-2 bg-slate-100 rounded-xl text-slate-400 hover:text-slate-600 hover:bg-slate-200 transition-all">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>

              <form onSubmit={handleAddOrUpdateData} className="space-y-6">
                <div className="space-y-4">
                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">학교명 및 위치</label>
                        <input 
                            required 
                            placeholder="학교명을 입력하세요" 
                            className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all shadow-sm" 
                            value={formData.school_name} 
                            onChange={e => handleSchoolNameChange(e.target.value)} 
                        />
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">산업 분야</label>
                            <select className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none focus:ring-4 focus:ring-indigo-500/10 shadow-sm" value={formData.industry} onChange={e => setFormData({...formData, industry: e.target.value})}>
                                {industries.filter(i => i !== '전체').map(i => <option key={i} value={i}>{i}</option>)}
                            </select>
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">권역</label>
                            <select className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none focus:ring-4 focus:ring-indigo-500/10 shadow-sm" value={formData.region} onChange={e => setFormData({...formData, region: e.target.value as Region})}>
                                {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                            </select>
                        </div>
                    </div>

                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">제안 유형 (중복 선택 가능)</label>
                        <div className="flex gap-2 pt-1">
                          {proposalTypesOptions.map(t => (
                            <button
                              key={t}
                              type="button"
                              onClick={() => toggleProposalType(t)}
                              className={`flex-1 py-3 rounded-xl text-xs font-black border transition-all ${
                                formData.proposal_types.includes(t)
                                ? 'bg-indigo-600 text-white border-indigo-600 shadow-md'
                                : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'
                              }`}
                            >
                              {t}
                            </button>
                          ))}
                        </div>
                    </div>

                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">참여 기업 / 상세 내용</label>
                        <input required placeholder="기업명 또는 제안 내용을 입력하세요" className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none focus:ring-4 focus:ring-indigo-500/10 shadow-sm" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
                    </div>

                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">예상 금액 (₩) - '0'이면 미정 처리</label>
                        <input required type="number" placeholder="금액 입력" className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none focus:ring-4 focus:ring-indigo-500/10 shadow-sm" value={formData.amount_sum} onChange={e => setFormData({...formData, amount_sum: e.target.value})} />
                    </div>
                </div>

                <div className="space-y-3 pt-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">운영 구분</label>
                  <div className="grid grid-cols-2 gap-4">
                    <button type="button" onClick={() => setFormData({...formData, status: 'NEW'})} className={`py-4 rounded-[1.25rem] text-xs font-black border transition-all shadow-sm ${formData.status === 'NEW' ? 'bg-red-500 text-white border-red-500 ring-4 ring-red-500/10 shadow-red-200' : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'}`}>신규 참여</button>
                    <button type="button" onClick={() => setFormData({...formData, status: 'EXISTING'})} className={`py-4 rounded-[1.25rem] text-xs font-black border transition-all shadow-sm ${formData.status === 'EXISTING' ? 'bg-indigo-600 text-white border-indigo-600 ring-4 ring-indigo-500/10 shadow-indigo-200' : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50'}`}>기존 운영</button>
                  </div>
                </div>

                <div className="pt-6 flex gap-4">
                  <button type="button" onClick={() => { resetForm(); setIsAdminOpen(false); }} className="flex-1 bg-slate-100 text-slate-600 py-4.5 rounded-[1.5rem] text-sm font-black hover:bg-slate-200 transition-all">취소</button>
                  <button type="submit" className="flex-[2] bg-indigo-600 text-white py-4.5 rounded-[1.5rem] text-sm font-black shadow-2xl shadow-indigo-200 hover:bg-indigo-700 transition-all active:scale-95">
                    {editingId ? '수정 사항 저장' : '데이터 등록 완료'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}

        {/* Legend */}
        {viewMode === 'map' && (
          <div className="absolute bottom-10 right-10 z-[1000] flex flex-col gap-5">
            <div className="glass p-6 rounded-[2.5rem] shadow-2xl w-60 border border-white/80">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.25em] mb-5 border-b border-slate-100/60 pb-3">Regional Scale</h3>
              <div className="grid grid-cols-1 gap-3.5">
                {Object.entries(REGION_COLORS).map(([name, color]) => (
                  <div key={name} className="flex items-center gap-4 group cursor-default">
                    <span className="w-3.5 h-3.5 rounded-full shadow-inner ring-4 ring-white group-hover:scale-125 transition-transform" style={{ backgroundColor: color }}></span>
                    <span className="text-[11px] font-black text-slate-600 group-hover:text-indigo-600 transition-colors">{name}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS, UNIVERSITY_PRESETS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  const [data, setData] = useState<UniversityData[]>(MOCK_DATA);
  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [industryFilter, setIndustryFilter] = useState<string>('전체');
  const [typeFilter, setTypeFilter] = useState<string>('전체');

  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SEOUL,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'EXISTING' as 'NEW' | 'EXISTING',
    proposal_range: '',
    industry: '반도체',
    proposal_types: [] as ('교육 제안' | '세미나 제안')[]
  });

  const industries = ['전체', '반도체', '이차전지', '바이오', '디스플레이', '항공우주', '미래차', '인공지능'];
  const proposalTypesOptions = ['교육 제안', '세미나 제안'] as const;

  const handleSchoolNameChange = (name: string) => {
    setFormData(prev => ({ ...prev, school_name: name }));
    const preset = UNIVERSITY_PRESETS[name];
    if (preset) {
      setFormData(prev => ({
        ...prev,
        school_name: name,
        region: preset.region,
        lat: preset.lat.toString(),
        lng: preset.lng.toString(),
        address: preset.address
      }));
    }
  };

  const toggleProposalType = (type: '교육 제안' | '세미나 제안') => {
    setFormData(prev => {
      const isExist = prev.proposal_types.includes(type);
      if (isExist) {
        return { ...prev, proposal_types: prev.proposal_types.filter(t => t !== type) };
      } else {
        return { ...prev, proposal_types: [...prev.proposal_types, type] };
      }
    });
  };

  const formatCurrency = (amount: number) => {
    if (amount === 0) return "금액 미정";
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const filteredData = data.filter(item => 
    (industryFilter === '전체' || item.industry === industryFilter) &&
    (typeFilter === '전체' || (item.proposal_types && item.proposal_types.includes(typeFilter as any)))
  );

  const calculateRadius = (amount: number) => {
    if (amount === 0) return 12;
    const logValue = Math.log10(amount || 1);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const renderMarkers = () => {
    if (!mapInstance.current || !markersLayer.current || viewMode !== 'map') return;

    markersLayer.current.clearLayers();

    filteredData.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS[Region.ETC];
      const radius = calculateRadius(univ.amount_sum);
      const isNew = univ.status === 'NEW';

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: isNew ? '#ffffff' : color,
        weight: isNew ? 3 : 1.5,
        dashArray: isNew ? '5, 5' : null,
        opacity: 1,
        fillOpacity: 0.6
      });

      const typeBadges = univ.proposal_types && univ.proposal_types.length > 0 
        ? univ.proposal_types.map(t => 
            `<span style="font-size: 8px; font-weight: 800; background: ${t === '교육 제안' ? '#2563EB' : '#7C3AED'}; color: white; padding: 1px 4px; border-radius: 4px; margin-left: 2px;">${t}</span>`
          ).join('')
        : `<span style="font-size: 8px; font-weight: 800; background: #94a3b8; color: white; padding: 1px 4px; border-radius: 4px;">유형 미정</span>`;

      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
            <span style="font-size: 9px; color: ${color}; font-weight: 800; border: 1px solid ${color}; padding: 1px 4px; border-radius: 4px;">${univ.industry}</span>
            <div style="display: flex;">${typeBadges}</div>
          </div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 2px;">${univ.school_name}</div>
          <div style="font-size: 10px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
          <div style="background: #f8fafc; padding: 8px; border-radius: 6px; margin-bottom: 8px;">
            <div style="font-size: 8px; color: #94a3b8; font-weight: 800; text-transform: uppercase;">참여 기업 / 범위</div>
            <div style="font-size: 11px; color: #334155; font-weight: 600;">${univ.proposal_range}</div>
          </div>
          <div style="border-top: 1px solid #f1f5f9; padding-top: 6px;">
            <div style="font-size: 14px; font-weight: 800; color: ${univ.amount_sum === 0 ? '#94a3b8' : color};">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, { closeButton: false }).addTo(markersLayer.current);
    });
  };

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current && !mapInstance.current) {
      const map = L.map(mapContainerRef.current, {
        center: [36.2, 127.8],
        zoom: 7.5,
        zoomControl: false
      });

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; CARTO'
      }).addTo(map);

      L.control.zoom({ position: 'bottomright' }).addTo(map);

      markersLayer.current = L.layerGroup().addTo(map);
      mapInstance.current = map;
      renderMarkers();
    }
  }, [viewMode]);

  useEffect(() => {
    if (viewMode === 'map') renderMarkers();
  }, [filteredData, viewMode]);

  const resetForm = () => {
    setFormData({
      school_name: '', region: Region.SEOUL, address: '', lat: '', lng: '', amount_sum: '', status: 'EXISTING', proposal_range: '', industry: '반도체', proposal_types: []
    });
    setEditingId(null);
  };

  const handleAddOrUpdateData = (e: React.FormEvent) => {
    e.preventDefault();
    const payload: UniversityData = {
      school_id: editingId || `S${Date.now()}`,
      school_name: formData.school_name,
      region: formData.region,
      address: formData.address,
      lat: parseFloat(formData.lat) || 0,
      lng: parseFloat(formData.lng) || 0,
      amount_sum: parseInt(formData.amount_sum) || 0,
      status: formData.status,
      proposal_range: formData.proposal_range,
      industry: formData.industry,
      proposal_types: formData.proposal_types
    };

    if (editingId) {
      setData(prev => prev.map(item => item.school_id === editingId ? payload : item));
    } else {
      setData(prev => [...prev, payload]);
    }

    resetForm();
    setIsAdminOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('정말로 이 학교의 제안 데이터를 삭제하시겠습니까?')) {
      setData(prev => prev.filter(item => item.school_id !== id));
    }
  };

  const startEdit = (univ: UniversityData) => {
    setEditingId(univ.school_id);
    setFormData({
      school_name: univ.school_name,
      region: univ.region as Region,
      address: univ.address,
      lat: univ.lat.toString(),
      lng: univ.lng.toString(),
      amount_sum: univ.amount_sum.toString(),
      status: univ.status,
      proposal_range: univ.proposal_range,
      industry: univ.industry,
      proposal_types: [...univ.proposal_types]
    });
    setIsAdminOpen(true);
  };

  const totalAmount = filteredData.reduce((acc, cur) => acc + cur.amount_sum, 0);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden text-slate-900">
      {/* Header */}
      <header className="h-20 flex items-center justify-between px-8 bg-white border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-6">
          <div className="flex items-center">
            {/* 모두의연구소 로고 섹션 */}
            <div className="flex items-center gap-3 pr-6 border-r border-slate-200">
                <img 
                  src="https://modulabs.co.kr/wp-content/uploads/2023/10/logo_red_vertical.png" 
                  alt="모두의연구소" 
                  className="h-10 object-contain"
                  onError={(e) => {
                    // 이미지 로드 실패 시 텍스트 로고 대체
                    (e.target as HTMLImageElement).style.display = 'none';
                    const parent = (e.target as HTMLElement).parentElement;
                    if(parent) {
                        const textLogo = document.createElement('div');
                        textLogo.className = 'text-red-500 font-black text-lg tracking-tighter';
                        textLogo.innerText = '모두의연구소';
                        parent.appendChild(textLogo);
                    }
                  }}
                />
            </div>
            <div className="pl-6">
                <h1 className="text-lg font-black text-slate-800 tracking-tight leading-none mb-1">2026 부트캠프 전략 현황판</h1>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em]">National High-Tech Bootcamp Dashboard</p>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {/* Filters Group */}
          <div className="flex items-center gap-2 bg-slate-50 p-1.5 rounded-2xl border border-slate-200 shadow-inner">
            <div className="flex flex-col px-3">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Industry</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={industryFilter}
                    onChange={(e) => setIndustryFilter(e.target.value)}
                >
                    {industries.map(ind => <option key={ind} value={ind}>{ind}</option>)}
                </select>
            </div>
            <div className="w-px h-6 bg-slate-200 mx-1"></div>
            <div className="flex flex-col px-3">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Filter Type</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={typeFilter}
                    onChange={(e) => setTypeFilter(e.target.value)}
                >
                    <option value="전체">전체 보기</option>
                    <option value="교육 제안">교육 제안 포함</option>
                    <option value="세미나 제안">세미나 제안 포함</option>
                </select>
            </div>
          </div>

          <div className="bg-slate-100 p-1 rounded-2xl flex items-center">
            <button onClick={() => setViewMode('map')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'map' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>Map</button>
            <button onClick={() => setViewMode('list')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'list' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>List</button>
          </div>

          <button 
            onClick={() => {
              if (isAdminOpen) resetForm();
              setIsAdminOpen(!isAdminOpen);
            }} 
            className={`px-6 py-2.5 rounded-2xl text-xs font-black transition-all ${isAdminOpen ? 'bg-slate-800 text-white shadow-lg' : 'bg-red-500 text-white hover:bg-red-600 shadow-lg shadow-red-100'}`}
          >
            {isAdminOpen ? '닫기' : '신규 등록'}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 relative overflow-hidden">
        {/* Map View */}
        <div className={`absolute inset-0 transition-opacity duration-500 ${viewMode === 'map' ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}>
          <div ref={mapContainerRef} id="map" />
        </div>

        {/* List View */}
        <div className={`absolute inset-0 bg-slate-50 overflow-auto p-12 transition-opacity duration-500 ${viewMode === 'list' ? 'opacity-100 z-20' : 'opacity-0 z-0'}`}>
          <div className="max-w-7xl mx-auto">
            <div className="flex items-end justify-between mb-12">
              <div>
                <div className="flex items-center gap-3 mb-3">
                   <span className="bg-red-500 text-white text-[10px] font-black px-2.5 py-1 rounded-lg shadow-md tracking-widest uppercase">Overview</span>
                   <h2 className="text-4xl font-black text-slate-800 tracking-tighter">제안 리스트 마스터</h2>
                </div>
                <p className="text-sm text-slate-400 font-bold uppercase tracking-widest">
                  {industryFilter} 카테고리 / {typeFilter} / {filteredData.length}개 기관 분석 중
                </p>
              </div>

              <div className="flex gap-4">
                <div className="bg-white p-7 rounded-[2.5rem] shadow-xl shadow-slate-200/50 border border-slate-100 text-right min-w-[280px]">
                  <span className="text-[10px] text-slate-400 font-black block uppercase tracking-[0.3em] mb-2">Aggregate Total</span>
                  <div className="flex items-baseline justify-end gap-1">
                    <span className="text-sm font-black text-red-400">₩</span>
                    <span className="text-4xl font-black text-slate-800 tracking-tighter">{new Intl.NumberFormat('ko-KR').format(totalAmount)}</span>
                  </div>
                </div>
              </div>
            </div>

            <div className="bg-white rounded-[3.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50/50 border-b border-slate-100 text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">
                  <tr>
                    <th className="px-10 py-7">제안 유형</th>
                    <th className="px-6 py-7">산업분야</th>
                    <th className="px-6 py-7">권역</th>
                    <th className="px-6 py-7">학교명</th>
                    <th className="px-6 py-7">참여 기업</th>
                    <th className="px-6 py-7 text-right">예상 금액</th>
                    <th className="px-10 py-7 text-center">관리</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredData.map((univ) => (
                    <tr key={univ.school_id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-10 py-7">
                        <div className="flex flex-wrap gap-1.5">
                          {univ.proposal_types && univ.proposal_types.length > 0 ? (
                            univ.proposal_types.map(t => (
                              <span key={t} className={`text-[9px] font-black px-2.5 py-1 rounded-lg shadow-sm border ${
                                  t === '교육 제안' 
                                  ? 'bg-blue-50 text-blue-600 border-blue-100' 
                                  : 'bg-purple-50 text-purple-600 border-purple-100'
                              }`}>
                                  {t}
                              </span>
                            ))
                          ) : (
                            <span className="text-[9px] font-black px-2.5 py-1 rounded-lg shadow-sm border bg-slate-100 text-slate-400 border-slate-200 italic">미정</span>
                          )}
                        </div>
                      </td>
                      <td className="px-6 py-7">
                        <span className="text-[10px] font-black text-slate-500 bg-white border border-slate-200 px-2.5 py-1.5 rounded-xl shadow-sm">{univ.industry}</span>
                      </td>
                      <td className="px-6 py-7">
                        <div className="flex items-center gap-3">
                          <span className="w-3.5 h-3.5 rounded-full shadow-inner ring-4 ring-white" style={{backgroundColor: REGION_COLORS[univ.region] || '#cbd5e1'}}></span>
                          <span className="text-xs font-black text-slate-600">{univ.region}</span>
                        </div>
                      </td>
                      <td className="px-6 py-7">
                        <div className="text-sm font-black text-slate-800 flex items-center gap-2">
                          {univ.school_name}
                          {univ.status === 'NEW' && (
                            <div className="flex h-2 w-2 relative">
                                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                                <span className="relative inline-flex rounded-full h-2 w-2 bg-red-500"></span>
                            </div>
                          )}
                        </div>
                        <div className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">{univ.address}</div>
                      </td>
                      <td className="px-6 py-7 text-xs font-bold text-slate-500 max-w-[200px] truncate leading-relaxed">{univ.proposal_range}</td>
                      <td className="px-6 py-7 text-right">
                         <div className={`text-sm font-black ${univ.amount_sum === 0 ? 'text-slate-300 italic' : 'text-slate-800'}`}>
                           {formatCurrency(univ.amount_sum)}
                         </div>
                      </td>
                      <td className="px-10 py-7 text-center">
                        <div className="flex items-center justify-center gap-3 opacity-0 group-hover:opacity-100 transition-all">
                          <button 
                            onClick={() => startEdit(univ)}
                            className="p-2.5 bg-slate-100 text-slate-600 rounded-xl hover:bg-slate-800 hover:text-white transition-all shadow-sm"
                            title="수정"
                          >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                            </svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Admin Panel Overlay */}
        {isAdminOpen && (
          <div className="absolute inset-0 z-[2000] flex items-center justify-center p-6 bg-slate-900/10 backdrop-blur-md pointer-events-none">
            <div className="glass p-12 rounded-[3.5rem] shadow-2xl border border-white/80 w-[520px] pointer-events-auto animate-in fade-in zoom-in-95 duration-300">
              <div className="flex items-center justify-between mb-10">
                <div className="flex flex-col">
                    <span className="text-[10px] font-black text-red-500 uppercase tracking-widest mb-1">Proposal Form</span>
                    <h3 className="text-3xl font-black text-slate-800 flex items-center gap-3">
                        {editingId ? '제안 수정' : '신규 학교 등록'}
                    </h3>
                </div>
                <button onClick={() => { resetForm(); setIsAdminOpen(false); }} className="p-3 bg-slate-100 rounded-2xl text-slate-400 hover:text-slate-600 hover:bg-slate-200 transition-all">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>

              <form onSubmit={handleAddOrUpdateData} className="space-y-7">
                <div className="space-y-5">
                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase ml-3 tracking-widest">기관명</label>
                        <input 
                            required 
                            placeholder="학교 또는 기관명을 입력하세요" 
                            className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] focus:ring-8 focus:ring-red-500/5 focus:border-red-500 outline-none transition-all shadow-sm" 
                            value={formData.school_name} 
                            onChange={e => handleSchoolNameChange(e.target.value)} 
                        />
                    </div>

                    <div className="grid grid-cols-2 gap-5">
                        <div className="space-y-2">
                            <label className="text-[11px] font-black text-slate-400 uppercase ml-3 tracking-widest">산업 분야</label>
                            <select className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none focus:ring-8 focus:ring-red-500/5 shadow-sm appearance-none" value={formData.industry} onChange={e => setFormData({...formData, industry: e.target.value})}>
                                {industries.filter(i => i !== '전체').map(i => <option key={i} value={i}>{i}</option>)}
                            </select>
                        </div>
                        <div className="space-y-2">
                            <label className="text-[11px] font-black text-slate-400 uppercase ml-3 tracking-widest">권역</label>
                            <select className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none focus:ring-8 focus:ring-red-500/5 shadow-sm appearance-none" value={formData.region} onChange={e => setFormData({...formData, region: e.target.value as Region})}>
                                {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                            </select>
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase ml-3 tracking-widest">제안 유형</label>
                        <div className="flex gap-3 pt-1">
                          {proposalTypesOptions.map(t => (
                            <button
                              key={t}
                              type="button"
                              onClick={() => toggleProposalType(t)}
                              className={`flex-1 py-4 rounded-2xl text-xs font-black border transition-all ${
                                formData.proposal_types.includes(t)
                                ? 'bg-slate-800 text-white border-slate-800 shadow-lg'
                                : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50 hover:border-slate-200'
                              }`}
                            >
                              {t}
                            </button>
                          ))}
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase ml-3 tracking-widest">참여 기업 및 범위</label>
                        <input required placeholder="기업명 또는 제안 상세 내용을 입력하세요" className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none focus:ring-8 focus:ring-red-500/5 shadow-sm" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
                    </div>

                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase ml-3 tracking-widest">예상 금액 (₩)</label>
                        <input required type="number" placeholder="금액 입력 (미정일 경우 0)" className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none focus:ring-8 focus:ring-red-500/5 shadow-sm" value={formData.amount_sum} onChange={e => setFormData({...formData, amount_sum: e.target.value})} />
                    </div>
                </div>

                <div className="pt-8 flex gap-4">
                  <button type="button" onClick={() => { resetForm(); setIsAdminOpen(false); }} className="flex-1 bg-slate-100 text-slate-600 py-5 rounded-[1.75rem] text-sm font-black hover:bg-slate-200 transition-all">취소</button>
                  <button type="submit" className="flex-[2] bg-red-500 text-white py-5 rounded-[1.75rem] text-sm font-black shadow-2xl shadow-red-200 hover:bg-red-600 transition-all">
                    {editingId ? '데이터 업데이트' : '제안 등록 완료'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}

        {/* Legend */}
        {viewMode === 'map' && (
          <div className="absolute bottom-12 right-12 z-[1000] flex flex-col gap-5">
            <div className="glass p-8 rounded-[3rem] shadow-2xl w-64 border border-white/80">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-6 border-b border-slate-100 pb-4">Region Legend</h3>
              <div className="grid grid-cols-1 gap-4">
                {Object.entries(REGION_COLORS).map(([name, color]) => (
                  <div key={name} className="flex items-center gap-4 group cursor-default">
                    <span className="w-4 h-4 rounded-full shadow-inner ring-4 ring-white group-hover:scale-125 transition-transform" style={{ backgroundColor: color }}></span>
                    <span className="text-[11px] font-black text-slate-600 group-hover:text-red-500 transition-colors">{name}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS, UNIVERSITY_PRESETS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  const [data, setData] = useState<UniversityData[]>(MOCK_DATA);
  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [industryFilter, setIndustryFilter] = useState<string>('전체');
  const [typeFilter, setTypeFilter] = useState<string>('전체');

  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SEOUL,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'EXISTING' as 'NEW' | 'EXISTING',
    proposal_range: '',
    industry: '반도체',
    proposal_types: [] as ('교육 제안' | '세미나 제안')[]
  });

  const industries = ['전체', '반도체', '이차전지', '바이오', '디스플레이', '항공우주', '미래차', '인공지능'];
  const proposalTypesOptions = ['교육 제안', '세미나 제안'] as const;

  const logoUrl = "https://modulabs.co.kr/wp-content/uploads/2023/10/logo_red_vertical.png";

  const handleSchoolNameChange = (name: string) => {
    setFormData(prev => ({ ...prev, school_name: name }));
    const preset = UNIVERSITY_PRESETS[name];
    if (preset) {
      setFormData(prev => ({
        ...prev,
        school_name: name,
        region: preset.region,
        lat: preset.lat.toString(),
        lng: preset.lng.toString(),
        address: preset.address
      }));
    }
  };

  const toggleProposalType = (type: '교육 제안' | '세미나 제안') => {
    setFormData(prev => {
      const isExist = prev.proposal_types.includes(type);
      if (isExist) {
        return { ...prev, proposal_types: prev.proposal_types.filter(t => t !== type) };
      } else {
        return { ...prev, proposal_types: [...prev.proposal_types, type] };
      }
    });
  };

  const formatCurrency = (amount: number) => {
    if (amount === 0) return "금액 미정";
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const filteredData = data.filter(item => 
    (industryFilter === '전체' || item.industry === industryFilter) &&
    (typeFilter === '전체' || (item.proposal_types && item.proposal_types.includes(typeFilter as any)))
  );

  const calculateRadius = (amount: number) => {
    if (amount === 0) return 12;
    const logValue = Math.log10(amount || 1);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const renderMarkers = () => {
    if (!mapInstance.current || !markersLayer.current || viewMode !== 'map') return;

    markersLayer.current.clearLayers();

    filteredData.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS[Region.ETC];
      const radius = calculateRadius(univ.amount_sum);
      const isNew = univ.status === 'NEW';
      const isModu = univ.proposal_range.includes('모두의연구소');

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: isModu ? '#ef4444' : (isNew ? '#ffffff' : color),
        weight: isModu ? 4 : (isNew ? 3 : 1.5),
        dashArray: isNew ? '5, 5' : null,
        opacity: 1,
        fillOpacity: 0.6
      });

      const typeBadges = univ.proposal_types && univ.proposal_types.length > 0 
        ? univ.proposal_types.map(t => 
            `<span style="font-size: 8px; font-weight: 800; background: ${t === '교육 제안' ? '#2563EB' : '#7C3AED'}; color: white; padding: 1px 4px; border-radius: 4px; margin-left: 2px;">${t}</span>`
          ).join('')
        : `<span style="font-size: 8px; font-weight: 800; background: #94a3b8; color: white; padding: 1px 4px; border-radius: 4px;">유형 미정</span>`;

      const moduBadge = isModu ? `<img src="${logoUrl}" style="height: 10px; margin-left: 4px; display: inline-block; vertical-align: middle;" />` : '';

      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
            <span style="font-size: 9px; color: ${color}; font-weight: 800; border: 1px solid ${color}; padding: 1px 4px; border-radius: 4px;">${univ.industry}</span>
            <div style="display: flex; align-items: center;">${typeBadges}${moduBadge}</div>
          </div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 2px;">${univ.school_name}</div>
          <div style="font-size: 10px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
          <div style="background: #f8fafc; padding: 8px; border-radius: 6px; margin-bottom: 8px;">
            <div style="font-size: 8px; color: #94a3b8; font-weight: 800; text-transform: uppercase;">참여 기업 / 범위</div>
            <div style="font-size: 11px; color: #334155; font-weight: 600;">${univ.proposal_range}</div>
          </div>
          <div style="border-top: 1px solid #f1f5f9; padding-top: 6px;">
            <div style="font-size: 14px; font-weight: 800; color: ${univ.amount_sum === 0 ? '#94a3b8' : color};">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, { closeButton: false }).addTo(markersLayer.current);
    });
  };

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current && !mapInstance.current) {
      const map = L.map(mapContainerRef.current, {
        center: [36.2, 127.8],
        zoom: 7.5,
        zoomControl: false
      });

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; CARTO'
      }).addTo(map);

      L.control.zoom({ position: 'bottomright' }).addTo(map);

      markersLayer.current = L.layerGroup().addTo(map);
      mapInstance.current = map;
      renderMarkers();
    }
  }, [viewMode]);

  useEffect(() => {
    if (viewMode === 'map') renderMarkers();
  }, [filteredData, viewMode]);

  const resetForm = () => {
    setFormData({
      school_name: '', region: Region.SEOUL, address: '', lat: '', lng: '', amount_sum: '', status: 'EXISTING', proposal_range: '', industry: '반도체', proposal_types: []
    });
    setEditingId(null);
  };

  const handleAddOrUpdateData = (e: React.FormEvent) => {
    e.preventDefault();
    const payload: UniversityData = {
      school_id: editingId || `S${Date.now()}`,
      school_name: formData.school_name,
      region: formData.region,
      address: formData.address,
      lat: parseFloat(formData.lat) || 0,
      lng: parseFloat(formData.lng) || 0,
      amount_sum: parseInt(formData.amount_sum) || 0,
      status: formData.status,
      proposal_range: formData.proposal_range,
      industry: formData.industry,
      proposal_types: formData.proposal_types
    };

    if (editingId) {
      setData(prev => prev.map(item => item.school_id === editingId ? payload : item));
    } else {
      setData(prev => [...prev, payload]);
    }

    resetForm();
    setIsAdminOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('정말로 이 학교의 제안 데이터를 삭제하시겠습니까?')) {
      setData(prev => prev.filter(item => item.school_id !== id));
    }
  };

  const startEdit = (univ: UniversityData) => {
    setEditingId(univ.school_id);
    setFormData({
      school_name: univ.school_name,
      region: univ.region as Region,
      address: univ.address,
      lat: univ.lat.toString(),
      lng: univ.lng.toString(),
      amount_sum: univ.amount_sum.toString(),
      status: univ.status,
      proposal_range: univ.proposal_range,
      industry: univ.industry,
      proposal_types: [...univ.proposal_types]
    });
    setIsAdminOpen(true);
  };

  const totalAmount = filteredData.reduce((acc, cur) => acc + cur.amount_sum, 0);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden text-slate-900">
      {/* Header */}
      <header className="h-20 flex items-center justify-between px-8 bg-white border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-6">
          <div className="flex items-center">
            {/* 모두의연구소 로고 섹션 */}
            <div className="flex items-center gap-3 pr-6 border-r border-slate-200">
                <img 
                  src={logoUrl} 
                  alt="모두의연구소" 
                  className="h-10 object-contain"
                  onError={(e) => {
                    (e.target as HTMLImageElement).style.display = 'none';
                    const parent = (e.target as HTMLElement).parentElement;
                    if(parent) {
                        const textLogo = document.createElement('div');
                        textLogo.className = 'text-red-500 font-black text-lg tracking-tighter';
                        textLogo.innerText = '모두의연구소';
                        parent.appendChild(textLogo);
                    }
                  }}
                />
            </div>
            <div className="pl-6">
                <h1 className="text-lg font-black text-slate-800 tracking-tight leading-none mb-1">2026 부트캠프 전략 현황판</h1>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em]">National High-Tech Bootcamp Dashboard</p>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {/* Filters Group */}
          <div className="flex items-center gap-2 bg-slate-50 p-1.5 rounded-2xl border border-slate-200 shadow-inner">
            <div className="flex flex-col px-3">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Industry</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={industryFilter}
                    onChange={(e) => setIndustryFilter(e.target.value)}
                >
                    {industries.map(ind => <option key={ind} value={ind}>{ind}</option>)}
                </select>
            </div>
            <div className="w-px h-6 bg-slate-200 mx-1"></div>
            <div className="flex flex-col px-3">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Filter Type</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={typeFilter}
                    onChange={(e) => setTypeFilter(e.target.value)}
                >
                    <option value="전체">전체 보기</option>
                    <option value="교육 제안">교육 제안 포함</option>
                    <option value="세미나 제안">세미나 제안 포함</option>
                </select>
            </div>
          </div>

          <div className="bg-slate-100 p-1 rounded-2xl flex items-center">
            <button onClick={() => setViewMode('map')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'map' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>Map</button>
            <button onClick={() => setViewMode('list')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'list' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>List</button>
          </div>

          <button 
            onClick={() => {
              if (isAdminOpen) resetForm();
              setIsAdminOpen(!isAdminOpen);
            }} 
            className={`px-6 py-2.5 rounded-2xl text-xs font-black transition-all ${isAdminOpen ? 'bg-slate-800 text-white shadow-lg' : 'bg-red-500 text-white hover:bg-red-600 shadow-lg shadow-red-100'}`}
          >
            {isAdminOpen ? '닫기' : '신규 등록'}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 relative overflow-hidden">
        {/* Map View */}
        <div className={`absolute inset-0 transition-opacity duration-500 ${viewMode === 'map' ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}>
          <div ref={mapContainerRef} id="map" />
        </div>

        {/* List View */}
        <div className={`absolute inset-0 bg-slate-50 overflow-auto p-12 transition-opacity duration-500 ${viewMode === 'list' ? 'opacity-100 z-20' : 'opacity-0 z-0'}`}>
          <div className="max-w-7xl mx-auto">
            <div className="flex items-end justify-between mb-12">
              <div>
                <div className="flex items-center gap-3 mb-3">
                   <span className="bg-red-500 text-white text-[10px] font-black px-2.5 py-1 rounded-lg shadow-md tracking-widest uppercase">Overview</span>
                   <h2 className="text-4xl font-black text-slate-800 tracking-tighter">제안 리스트 마스터</h2>
                </div>
                <p className="text-sm text-slate-400 font-bold uppercase tracking-widest">
                  {industryFilter} 카테고리 / {typeFilter} / {filteredData.length}개 기관 분석 중
                </p>
              </div>

              <div className="flex gap-4">
                <div className="bg-white p-7 rounded-[2.5rem] shadow-xl shadow-slate-200/50 border border-slate-100 text-right min-w-[280px]">
                  <span className="text-[10px] text-slate-400 font-black block uppercase tracking-[0.3em] mb-2">Aggregate Total</span>
                  <div className="flex items-baseline justify-end gap-1">
                    <span className="text-sm font-black text-red-400">₩</span>
                    <span className="text-4xl font-black text-slate-800 tracking-tighter">{new Intl.NumberFormat('ko-KR').format(totalAmount)}</span>
                  </div>
                </div>
              </div>
            </div>

            <div className="bg-white rounded-[3.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50/50 border-b border-slate-100 text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">
                  <tr>
                    <th className="px-10 py-7">제안 유형</th>
                    <th className="px-6 py-7">산업분야</th>
                    <th className="px-6 py-7">권역</th>
                    <th className="px-6 py-7">학교명</th>
                    <th className="px-6 py-7">참여 기업</th>
                    <th className="px-6 py-7 text-right">예상 금액</th>
                    <th className="px-10 py-7 text-center">관리</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredData.map((univ) => (
                    <tr key={univ.school_id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-10 py-7">
                        <div className="flex flex-wrap gap-1.5">
                          {univ.proposal_types && univ.proposal_types.length > 0 ? (
                            univ.proposal_types.map(t => (
                              <span key={t} className={`text-[9px] font-black px-2.5 py-1 rounded-lg shadow-sm border ${
                                  t === '교육 제안' 
                                  ? 'bg-blue-50 text-blue-600 border-blue-100' 
                                  : 'bg-purple-50 text-purple-600 border-purple-100'
                              }`}>
                                  {t}
                              </span>
                            ))
                          ) : (
                            <span className="text-[9px] font-black px-2.5 py-1 rounded-lg shadow-sm border bg-slate-100 text-slate-400 border-slate-200 italic">미정</span>
                          )}
                        </div>
                      </td>
                      <td className="px-6 py-7">
                        <span className="text-[10px] font-black text-slate-500 bg-white border border-slate-200 px-2.5 py-1.5 rounded-xl shadow-sm">{univ.industry}</span>
                      </td>
                      <td className="px-6 py-7">
                        <div className="flex items-center gap-3">
                          <span className="w-3.5 h-3.5 rounded-full shadow-inner ring-4 ring-white" style={{backgroundColor: REGION_COLORS[univ.region] || '#cbd5e1'}}></span>
                          <span className="text-xs font-black text-slate-600">{univ.region}</span>
                        </div>
                      </td>
                      <td className="px-6 py-7">
                        <div className="text-sm font-black text-slate-800 flex items-center gap-2">
                          {univ.school_name}
                          {univ.status === 'NEW' && (
                            <div className="flex h-2 w-2 relative">
                                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                                <span className="relative inline-flex rounded-full h-2 w-2 bg-red-500"></span>
                            </div>
                          )}
                        </div>
                        <div className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">{univ.address}</div>
                      </td>
                      <td className="px-6 py-7">
                        <div className="flex items-center gap-2">
                          <span className="text-xs font-bold text-slate-500 max-w-[160px] truncate leading-relaxed">
                            {univ.proposal_range}
                          </span>
                          {univ.proposal_range.includes('모두의연구소') && (
                             <img src={logoUrl} alt="Modu" className="h-3 object-contain flex-shrink-0" />
                          )}
                        </div>
                      </td>
                      <td className="px-6 py-7 text-right">
                         <div className={`text-sm font-black ${univ.amount_sum === 0 ? 'text-slate-300 italic' : 'text-slate-800'}`}>
                           {formatCurrency(univ.amount_sum)}
                         </div>
                      </td>
                      <td className="px-10 py-7 text-center">
                        <div className="flex items-center justify-center gap-3 opacity-0 group-hover:opacity-100 transition-all">
                          <button 
                            onClick={() => startEdit(univ)}
                            className="p-2.5 bg-slate-100 text-slate-600 rounded-xl hover:bg-slate-800 hover:text-white transition-all shadow-sm"
                            title="수정"
                          >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                            </svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Admin Panel Overlay */}
        {isAdminOpen && (
          <div className="absolute inset-0 z-[2000] flex items-center justify-center p-6 bg-slate-900/10 backdrop-blur-md pointer-events-none">
            <div className="glass p-12 rounded-[3.5rem] shadow-2xl border border-white/80 w-[520px] pointer-events-auto animate-in fade-in zoom-in-95 duration-300">
              <div className="flex items-center justify-between mb-10">
                <div className="flex flex-col">
                    <span className="text-[10px] font-black text-red-500 uppercase tracking-widest mb-1">Proposal Form</span>
                    <h3 className="text-3xl font-black text-slate-800 flex items-center gap-3">
                        {editingId ? '제안 수정' : '신규 학교 등록'}
                    </h3>
                </div>
                <button onClick={() => { resetForm(); setIsAdminOpen(false); }} className="p-3 bg-slate-100 rounded-2xl text-slate-400 hover:text-slate-600 hover:bg-slate-200 transition-all">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>

              <form onSubmit={handleAddOrUpdateData} className="space-y-7">
                <div className="space-y-5">
                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase ml-3 tracking-widest">기관명</label>
                        <input 
                            required 
                            placeholder="학교 또는 기관명을 입력하세요" 
                            className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] focus:ring-8 focus:ring-red-500/5 focus:border-red-500 outline-none transition-all shadow-sm" 
                            value={formData.school_name} 
                            onChange={e => handleSchoolNameChange(e.target.value)} 
                        />
                    </div>

                    <div className="grid grid-cols-2 gap-5">
                        <div className="space-y-2">
                            <label className="text-[11px] font-black text-slate-400 uppercase ml-3 tracking-widest">산업 분야</label>
                            <select className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none focus:ring-8 focus:ring-red-500/5 shadow-sm appearance-none" value={formData.industry} onChange={e => setFormData({...formData, industry: e.target.value})}>
                                {industries.filter(i => i !== '전체').map(i => <option key={i} value={i}>{i}</option>)}
                            </select>
                        </div>
                        <div className="space-y-2">
                            <label className="text-[11px] font-black text-slate-400 uppercase ml-3 tracking-widest">권역</label>
                            <select className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none focus:ring-8 focus:ring-red-500/5 shadow-sm appearance-none" value={formData.region} onChange={e => setFormData({...formData, region: e.target.value as Region})}>
                                {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                            </select>
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase ml-3 tracking-widest">제안 유형</label>
                        <div className="flex gap-3 pt-1">
                          {proposalTypesOptions.map(t => (
                            <button
                              key={t}
                              type="button"
                              onClick={() => toggleProposalType(t)}
                              className={`flex-1 py-4 rounded-2xl text-xs font-black border transition-all ${
                                formData.proposal_types.includes(t)
                                ? 'bg-slate-800 text-white border-slate-800 shadow-lg'
                                : 'bg-white text-slate-400 border-slate-100 hover:bg-slate-50 hover:border-slate-200'
                              }`}
                            >
                              {t}
                            </button>
                          ))}
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase ml-3 tracking-widest">참여 기업 및 범위</label>
                        <input required placeholder="기업명 또는 제안 상세 내용을 입력하세요" className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none focus:ring-8 focus:ring-red-500/5 shadow-sm" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
                    </div>

                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase ml-3 tracking-widest">예상 금액 (₩)</label>
                        <input required type="number" placeholder="금액 입력 (미정일 경우 0)" className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none focus:ring-8 focus:ring-red-500/5 shadow-sm" value={formData.amount_sum} onChange={e => setFormData({...formData, amount_sum: e.target.value})} />
                    </div>
                </div>

                <div className="pt-8 flex gap-4">
                  <button type="button" onClick={() => { resetForm(); setIsAdminOpen(false); }} className="flex-1 bg-slate-100 text-slate-600 py-5 rounded-[1.75rem] text-sm font-black hover:bg-slate-200 transition-all">취소</button>
                  <button type="submit" className="flex-[2] bg-red-500 text-white py-5 rounded-[1.75rem] text-sm font-black shadow-2xl shadow-red-200 hover:bg-red-600 transition-all">
                    {editingId ? '데이터 업데이트' : '제안 등록 완료'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}

        {/* Legend */}
        {viewMode === 'map' && (
          <div className="absolute bottom-12 right-12 z-[1000] flex flex-col gap-5">
            <div className="glass p-8 rounded-[3rem] shadow-2xl w-64 border border-white/80">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-6 border-b border-slate-100 pb-4">Region Legend</h3>
              <div className="grid grid-cols-1 gap-4">
                {Object.entries(REGION_COLORS).map(([name, color]) => (
                  <div key={name} className="flex items-center gap-4 group cursor-default">
                    <span className="w-4 h-4 rounded-full shadow-inner ring-4 ring-white group-hover:scale-125 transition-transform" style={{ backgroundColor: color }}></span>
                    <span className="text-[11px] font-black text-slate-600 group-hover:text-red-500 transition-colors">{name}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS, UNIVERSITY_PRESETS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  // 로컬 스토리지에서 데이터 로드 또는 기본값 사용
  const [data, setData] = useState<UniversityData[]>(() => {
    const saved = localStorage.getItem('univ_dashboard_data');
    return saved ? JSON.parse(saved) : MOCK_DATA;
  });

  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [industryFilter, setIndustryFilter] = useState<string>('전체');
  const [typeFilter, setTypeFilter] = useState<string>('전체');

  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SEOUL,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'EXISTING' as 'NEW' | 'EXISTING',
    proposal_range: '',
    industry: '반도체',
    proposal_types: [] as ('교육 제안' | '세미나 제안')[]
  });

  const industries = ['전체', '반도체', '이차전지', '바이오', '디스플레이', '항공우주', '미래차', '인공지능'];
  const proposalTypesOptions = ['교육 제안', '세미나 제안'] as const;
  const logoUrl = "https://modulabs.co.kr/wp-content/uploads/2023/10/logo_red_vertical.png";

  // 데이터 변경 시 로컬 스토리지에 자동 저장
  useEffect(() => {
    localStorage.setItem('univ_dashboard_data', JSON.stringify(data));
  }, [data]);

  const handleSchoolNameChange = (name: string) => {
    setFormData(prev => ({ ...prev, school_name: name }));
    const preset = UNIVERSITY_PRESETS[name];
    if (preset) {
      setFormData(prev => ({
        ...prev,
        school_name: name,
        region: preset.region,
        lat: preset.lat.toString(),
        lng: preset.lng.toString(),
        address: preset.address
      }));
    }
  };

  const toggleProposalType = (type: '교육 제안' | '세미나 제안') => {
    setFormData(prev => {
      const isExist = prev.proposal_types.includes(type);
      if (isExist) {
        return { ...prev, proposal_types: prev.proposal_types.filter(t => t !== type) };
      } else {
        return { ...prev, proposal_types: [...prev.proposal_types, type] };
      }
    });
  };

  const formatCurrency = (amount: number) => {
    if (amount === 0) return "금액 미정";
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const filteredData = data.filter(item => 
    (industryFilter === '전체' || item.industry === industryFilter) &&
    (typeFilter === '전체' || (item.proposal_types && item.proposal_types.includes(typeFilter as any)))
  );

  const calculateRadius = (amount: number) => {
    if (amount === 0) return 12;
    const logValue = Math.log10(amount || 1);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const renderMarkers = () => {
    if (!mapInstance.current || !markersLayer.current || viewMode !== 'map') return;

    markersLayer.current.clearLayers();

    filteredData.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS[Region.ETC];
      const radius = calculateRadius(univ.amount_sum);
      const isNew = univ.status === 'NEW';
      const isModu = univ.proposal_range.includes('모두의연구소');

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: isModu ? '#ef4444' : (isNew ? '#ffffff' : color),
        weight: isModu ? 4 : (isNew ? 3 : 1.5),
        dashArray: isNew ? '5, 5' : null,
        opacity: 1,
        fillOpacity: 0.6
      });

      const typeBadges = univ.proposal_types && univ.proposal_types.length > 0 
        ? univ.proposal_types.map(t => 
            `<span style="font-size: 8px; font-weight: 800; background: ${t === '교육 제안' ? '#2563EB' : '#7C3AED'}; color: white; padding: 1px 4px; border-radius: 4px; margin-left: 2px;">${t}</span>`
          ).join('')
        : `<span style="font-size: 8px; font-weight: 800; background: #94a3b8; color: white; padding: 1px 4px; border-radius: 4px;">유형 미정</span>`;

      // 마커 팝업 내 모두의연구소 별도 표기
      const moduTextBadge = isModu ? `<span style="font-size: 8px; font-weight: 800; background: #ef4444; color: white; padding: 1px 4px; border-radius: 4px; margin-left: 4px;">MODU</span>` : '';

      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
            <span style="font-size: 9px; color: ${color}; font-weight: 800; border: 1px solid ${color}; padding: 1px 4px; border-radius: 4px;">${univ.industry}</span>
            <div style="display: flex; align-items: center;">${typeBadges}${moduTextBadge}</div>
          </div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 2px;">${univ.school_name}</div>
          <div style="font-size: 10px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
          <div style="background: #f8fafc; padding: 8px; border-radius: 6px; margin-bottom: 8px;">
            <div style="font-size: 8px; color: #94a3b8; font-weight: 800; text-transform: uppercase;">참여 기업 / 범위</div>
            <div style="font-size: 11px; color: #334155; font-weight: 600;">${univ.proposal_range}</div>
          </div>
          <div style="border-top: 1px solid #f1f5f9; padding-top: 6px;">
            <div style="font-size: 14px; font-weight: 800; color: ${univ.amount_sum === 0 ? '#94a3b8' : color};">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, { closeButton: false }).addTo(markersLayer.current);
    });
  };

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current && !mapInstance.current) {
      const map = L.map(mapContainerRef.current, {
        center: [36.2, 127.8],
        zoom: 7.5,
        zoomControl: false
      });

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; CARTO'
      }).addTo(map);

      L.control.zoom({ position: 'bottomright' }).addTo(map);

      markersLayer.current = L.layerGroup().addTo(map);
      mapInstance.current = map;
      renderMarkers();
    }
  }, [viewMode]);

  useEffect(() => {
    if (viewMode === 'map') renderMarkers();
  }, [filteredData, viewMode]);

  const resetForm = () => {
    setFormData({
      school_name: '', region: Region.SEOUL, address: '', lat: '', lng: '', amount_sum: '', status: 'EXISTING', proposal_range: '', industry: '반도체', proposal_types: []
    });
    setEditingId(null);
  };

  const handleAddOrUpdateData = (e: React.FormEvent) => {
    e.preventDefault();
    const payload: UniversityData = {
      school_id: editingId || `S${Date.now()}`,
      school_name: formData.school_name,
      region: formData.region,
      address: formData.address,
      lat: parseFloat(formData.lat) || 0,
      lng: parseFloat(formData.lng) || 0,
      amount_sum: parseInt(formData.amount_sum) || 0,
      status: formData.status,
      proposal_range: formData.proposal_range,
      industry: formData.industry,
      proposal_types: formData.proposal_types
    };

    if (editingId) {
      setData(prev => prev.map(item => item.school_id === editingId ? payload : item));
    } else {
      setData(prev => [...prev, payload]);
    }

    resetForm();
    setIsAdminOpen(false);
    // 맵 뷰라면 마커 즉시 업데이트 유도 (useEffect가 처리하지만 명시적 호출 가능)
    if(viewMode === 'map') renderMarkers();
  };

  const handleDelete = (id: string) => {
    if (confirm('정말로 이 학교의 제안 데이터를 삭제하시겠습니까?')) {
      setData(prev => prev.filter(item => item.school_id !== id));
    }
  };

  const startEdit = (univ: UniversityData) => {
    setEditingId(univ.school_id);
    setFormData({
      school_name: univ.school_name,
      region: univ.region as Region,
      address: univ.address,
      lat: univ.lat.toString(),
      lng: univ.lng.toString(),
      amount_sum: univ.amount_sum.toString(),
      status: univ.status,
      proposal_range: univ.proposal_range,
      industry: univ.industry,
      proposal_types: [...univ.proposal_types]
    });
    setIsAdminOpen(true);
  };

  const totalAmount = filteredData.reduce((acc, cur) => acc + cur.amount_sum, 0);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden text-slate-900">
      <header className="h-20 flex items-center justify-between px-8 bg-white border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-6">
          <div className="flex items-center">
            <div className="flex items-center gap-3 pr-6 border-r border-slate-200">
                <img 
                  src={logoUrl} 
                  alt="모두의연구소" 
                  className="h-10 object-contain"
                  onError={(e) => {
                    (e.target as HTMLImageElement).style.display = 'none';
                  }}
                />
            </div>
            <div className="pl-6">
                <h1 className="text-lg font-black text-slate-800 tracking-tight leading-none mb-1">2026 부트캠프 전략 현황판</h1>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em]">National High-Tech Bootcamp Dashboard</p>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 bg-slate-50 p-1.5 rounded-2xl border border-slate-200 shadow-inner">
            <div className="flex flex-col px-3">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Industry</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={industryFilter}
                    onChange={(e) => setIndustryFilter(e.target.value)}
                >
                    {industries.map(ind => <option key={ind} value={ind}>{ind}</option>)}
                </select>
            </div>
            <div className="w-px h-6 bg-slate-200 mx-1"></div>
            <div className="flex flex-col px-3">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Filter Type</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={typeFilter}
                    onChange={(e) => setTypeFilter(e.target.value)}
                >
                    <option value="전체">전체 보기</option>
                    <option value="교육 제안">교육 제안 포함</option>
                    <option value="세미나 제안">세미나 제안 포함</option>
                </select>
            </div>
          </div>

          <div className="bg-slate-100 p-1 rounded-2xl flex items-center">
            <button onClick={() => setViewMode('map')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'map' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>Map</button>
            <button onClick={() => setViewMode('list')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'list' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>List</button>
          </div>

          <button 
            onClick={() => {
              if (isAdminOpen) resetForm();
              setIsAdminOpen(!isAdminOpen);
            }} 
            className={`px-6 py-2.5 rounded-2xl text-xs font-black transition-all ${isAdminOpen ? 'bg-slate-800 text-white shadow-lg' : 'bg-red-500 text-white hover:bg-red-600 shadow-lg shadow-red-100'}`}
          >
            {isAdminOpen ? '닫기' : '신규 등록'}
          </button>
        </div>
      </header>

      <main className="flex-1 relative overflow-hidden">
        <div className={`absolute inset-0 transition-opacity duration-500 ${viewMode === 'map' ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}>
          <div ref={mapContainerRef} id="map" />
        </div>

        <div className={`absolute inset-0 bg-slate-50 overflow-auto p-12 transition-opacity duration-500 ${viewMode === 'list' ? 'opacity-100 z-20' : 'opacity-0 z-0'}`}>
          <div className="max-w-7xl mx-auto">
            <div className="flex items-end justify-between mb-12">
              <div>
                <div className="flex items-center gap-3 mb-3">
                   <span className="bg-red-500 text-white text-[10px] font-black px-2.5 py-1 rounded-lg shadow-md tracking-widest uppercase">Overview</span>
                   <h2 className="text-4xl font-black text-slate-800 tracking-tighter">제안 리스트 마스터</h2>
                </div>
                <p className="text-sm text-slate-400 font-bold uppercase tracking-widest">
                  {industryFilter} 카테고리 / {typeFilter} / {filteredData.length}개 기관 분석 중
                </p>
              </div>
              <div className="bg-white p-7 rounded-[2.5rem] shadow-xl shadow-slate-200/50 border border-slate-100 text-right min-w-[280px]">
                <span className="text-[10px] text-slate-400 font-black block uppercase tracking-[0.3em] mb-2">Aggregate Total</span>
                <div className="flex items-baseline justify-end gap-1">
                  <span className="text-sm font-black text-red-400">₩</span>
                  <span className="text-4xl font-black text-slate-800 tracking-tighter">{new Intl.NumberFormat('ko-KR').format(totalAmount)}</span>
                </div>
              </div>
            </div>

            <div className="bg-white rounded-[3.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50/50 border-b border-slate-100 text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">
                  <tr>
                    <th className="px-10 py-7">제안 유형</th>
                    <th className="px-6 py-7">산업분야</th>
                    <th className="px-6 py-7">권역</th>
                    <th className="px-6 py-7">학교명</th>
                    <th className="px-6 py-7">참여 기업</th>
                    <th className="px-6 py-7 text-right">예상 금액</th>
                    <th className="px-10 py-7 text-center">관리</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredData.map((univ) => (
                    <tr key={univ.school_id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-10 py-7">
                        <div className="flex flex-wrap gap-1.5">
                          {univ.proposal_types?.map(t => (
                            <span key={t} className={`text-[9px] font-black px-2.5 py-1 rounded-lg shadow-sm border ${
                                t === '교육 제안' 
                                ? 'bg-blue-50 text-blue-600 border-blue-100' 
                                : 'bg-purple-50 text-purple-600 border-purple-100'
                            }`}>
                                {t}
                            </span>
                          ))}
                        </div>
                      </td>
                      <td className="px-6 py-7">
                        <span className="text-[10px] font-black text-slate-500 bg-white border border-slate-200 px-2.5 py-1.5 rounded-xl shadow-sm">{univ.industry}</span>
                      </td>
                      <td className="px-6 py-7">
                        <div className="flex items-center gap-3">
                          <span className="w-3.5 h-3.5 rounded-full shadow-inner ring-4 ring-white" style={{backgroundColor: REGION_COLORS[univ.region] || '#cbd5e1'}}></span>
                          <span className="text-xs font-black text-slate-600">{univ.region}</span>
                        </div>
                      </td>
                      <td className="px-6 py-7">
                        <div className="text-sm font-black text-slate-800 flex items-center gap-2">
                          {univ.school_name}
                          {univ.status === 'NEW' && <span className="h-2 w-2 rounded-full bg-red-500 animate-pulse"></span>}
                        </div>
                      </td>
                      <td className="px-6 py-7">
                        <div className="flex items-center gap-2">
                          <span className="text-xs font-bold text-slate-500 truncate max-w-[160px]">{univ.proposal_range}</span>
                          {univ.proposal_range.includes('모두의연구소') && <img src={logoUrl} className="h-3 object-contain" alt="Modu" />}
                        </div>
                      </td>
                      <td className="px-6 py-7 text-right font-black text-sm">{formatCurrency(univ.amount_sum)}</td>
                      <td className="px-10 py-7 text-center">
                        <div className="flex gap-2 justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => startEdit(univ)} className="p-2 bg-slate-100 rounded-lg hover:bg-slate-200"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg></button>
                          <button onClick={() => handleDelete(univ.school_id)} className="p-2 bg-red-50 text-red-500 rounded-lg hover:bg-red-100"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {isAdminOpen && (
          <div className="absolute inset-0 z-[2000] flex items-center justify-center p-6 bg-slate-900/10 backdrop-blur-md pointer-events-none">
            <div className="glass p-12 rounded-[3.5rem] shadow-2xl border border-white/80 w-[520px] pointer-events-auto animate-in zoom-in-95 duration-300">
              <div className="flex items-center justify-between mb-10">
                <h3 className="text-3xl font-black text-slate-800">{editingId ? '제안 수정' : '신규 학교 등록'}</h3>
                <button onClick={() => { resetForm(); setIsAdminOpen(false); }} className="p-3 bg-slate-100 rounded-2xl text-slate-400 hover:text-slate-600 transition-all"><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg></button>
              </div>

              <form onSubmit={handleAddOrUpdateData} className="space-y-7">
                <div className="space-y-5">
                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">기관명</label>
                        <input required placeholder="학교명을 입력하세요" className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none focus:ring-4 focus:ring-red-500/10" value={formData.school_name} onChange={e => handleSchoolNameChange(e.target.value)} />
                    </div>
                    <div className="grid grid-cols-2 gap-5">
                        <div className="space-y-2">
                            <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">산업 분야</label>
                            <select className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none" value={formData.industry} onChange={e => setFormData({...formData, industry: e.target.value})}>
                                {industries.filter(i => i !== '전체').map(i => <option key={i} value={i}>{i}</option>)}
                            </select>
                        </div>
                        <div className="space-y-2">
                            <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">권역</label>
                            <select className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none" value={formData.region} onChange={e => setFormData({...formData, region: e.target.value as Region})}>
                                {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                            </select>
                        </div>
                    </div>
                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">제안 유형</label>
                        <div className="flex gap-3">
                          {proposalTypesOptions.map(t => (
                            <button key={t} type="button" onClick={() => toggleProposalType(t)} className={`flex-1 py-4 rounded-2xl text-xs font-black border transition-all ${formData.proposal_types.includes(t) ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-400 border-slate-100'}`}>{t}</button>
                          ))}
                        </div>
                    </div>
                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">참여 기업 및 범위</label>
                        <input required placeholder="예: 모두의연구소 협력 제안" className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
                    </div>
                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">예상 금액 (₩)</label>
                        <input required type="number" placeholder="금액 입력" className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none" value={formData.amount_sum} onChange={e => setFormData({...formData, amount_sum: e.target.value})} />
                    </div>
                </div>
                <div className="pt-8 flex gap-4">
                  <button type="button" onClick={() => { resetForm(); setIsAdminOpen(false); }} className="flex-1 bg-slate-100 text-slate-600 py-5 rounded-[1.75rem] text-sm font-black">취소</button>
                  <button type="submit" className="flex-[2] bg-red-500 text-white py-5 rounded-[1.75rem] text-sm font-black shadow-lg">저장 및 업데이트</button>
                </div>
              </form>
            </div>
          </div>
        )}

        {viewMode === 'map' && (
          <div className="absolute bottom-12 right-12 z-[1000]">
            <div className="glass p-8 rounded-[3rem] shadow-2xl w-64 border border-white/80">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-6 border-b border-slate-100 pb-4">Region Legend</h3>
              <div className="grid grid-cols-1 gap-4">
                {Object.entries(REGION_COLORS).map(([name, color]) => (
                  <div key={name} className="flex items-center gap-4">
                    <span className="w-4 h-4 rounded-full shadow-inner ring-4 ring-white" style={{ backgroundColor: color }}></span>
                    <span className="text-[11px] font-black text-slate-600">{name}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS, UNIVERSITY_PRESETS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  // 로컬 스토리지에서 데이터 로드 또는 기본값 사용
  const [data, setData] = useState<UniversityData[]>(() => {
    const saved = localStorage.getItem('univ_dashboard_data');
    return saved ? JSON.parse(saved) : MOCK_DATA;
  });

  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [industryFilter, setIndustryFilter] = useState<string>('전체');
  const [typeFilter, setTypeFilter] = useState<string>('전체');

  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SEOUL,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'EXISTING' as 'NEW' | 'EXISTING',
    proposal_range: '',
    industry: '반도체',
    proposal_types: [] as ('교육 제안' | '세미나 제안')[]
  });

  const industries = ['전체', '반도체', '이차전지', '바이오', '디스플레이', '항공우주', '미래차', '인공지능'];
  const proposalTypesOptions = ['교육 제안', '세미나 제안'] as const;
  const logoUrl = "https://modulabs.co.kr/wp-content/uploads/2023/10/logo_red_vertical.png";

  // 데이터 변경 시 로컬 스토리지에 자동 저장
  useEffect(() => {
    localStorage.setItem('univ_dashboard_data', JSON.stringify(data));
  }, [data]);

  const handleSchoolNameChange = (name: string) => {
    setFormData(prev => ({ ...prev, school_name: name }));
    const preset = UNIVERSITY_PRESETS[name];
    if (preset) {
      setFormData(prev => ({
        ...prev,
        school_name: name,
        region: preset.region,
        lat: preset.lat.toString(),
        lng: preset.lng.toString(),
        address: preset.address
      }));
    }
  };

  const toggleProposalType = (type: '교육 제안' | '세미나 제안') => {
    setFormData(prev => {
      const isExist = prev.proposal_types.includes(type);
      if (isExist) {
        return { ...prev, proposal_types: prev.proposal_types.filter(t => t !== type) };
      } else {
        return { ...prev, proposal_types: [...prev.proposal_types, type] };
      }
    });
  };

  const formatCurrency = (amount: number) => {
    if (amount === 0) return "금액 미정";
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const filteredData = data.filter(item => 
    (industryFilter === '전체' || item.industry === industryFilter) &&
    (typeFilter === '전체' || (item.proposal_types && item.proposal_types.includes(typeFilter as any)))
  );

  const calculateRadius = (amount: number) => {
    if (amount === 0) return 12;
    const logValue = Math.log10(amount || 1);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const renderMarkers = () => {
    if (!mapInstance.current || !markersLayer.current || viewMode !== 'map') return;

    markersLayer.current.clearLayers();

    filteredData.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS[Region.ETC];
      const radius = calculateRadius(univ.amount_sum);
      const isNew = univ.status === 'NEW';
      const isModu = univ.proposal_range.includes('모두의연구소');

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: isModu ? '#ef4444' : (isNew ? '#ffffff' : color),
        weight: isModu ? 4 : (isNew ? 3 : 1.5),
        dashArray: isNew ? '5, 5' : null,
        opacity: 1,
        fillOpacity: 0.6
      });

      const typeBadges = univ.proposal_types && univ.proposal_types.length > 0 
        ? univ.proposal_types.map(t => 
            `<span style="font-size: 8px; font-weight: 800; background: ${t === '교육 제안' ? '#2563EB' : '#7C3AED'}; color: white; padding: 1px 4px; border-radius: 4px; margin-left: 2px;">${t}</span>`
          ).join('')
        : `<span style="font-size: 8px; font-weight: 800; background: #94a3b8; color: white; padding: 1px 4px; border-radius: 4px;">유형 미정</span>`;

      // 마커 팝업 내 모두의연구소 별도 표기
      const moduTextBadge = isModu ? `<span style="font-size: 8px; font-weight: 800; background: #ef4444; color: white; padding: 1px 4px; border-radius: 4px; margin-left: 4px;">MODU</span>` : '';

      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
            <span style="font-size: 9px; color: ${color}; font-weight: 800; border: 1px solid ${color}; padding: 1px 4px; border-radius: 4px;">${univ.industry}</span>
            <div style="display: flex; align-items: center;">${typeBadges}${moduTextBadge}</div>
          </div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 2px;">${univ.school_name}</div>
          <div style="font-size: 10px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
          <div style="background: #f8fafc; padding: 8px; border-radius: 6px; margin-bottom: 8px;">
            <div style="font-size: 8px; color: #94a3b8; font-weight: 800; text-transform: uppercase;">참여 기업 / 범위</div>
            <div style="font-size: 11px; color: #334155; font-weight: 600;">${univ.proposal_range}</div>
          </div>
          <div style="border-top: 1px solid #f1f5f9; padding-top: 6px;">
            <div style="font-size: 14px; font-weight: 800; color: ${univ.amount_sum === 0 ? '#94a3b8' : color};">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, { closeButton: false }).addTo(markersLayer.current);
    });
  };

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current && !mapInstance.current) {
      const map = L.map(mapContainerRef.current, {
        center: [36.2, 127.8],
        zoom: 7.5,
        zoomControl: false
      });

      // 구글 지도 한글 타일 레이어 적용
      L.tileLayer('https://mt1.google.com/vt/lyrs=m&hl=ko&gl=kr&x={x}&y={y}&z={z}', {
        attribution: '&copy; Google Maps'
      }).addTo(map);

      L.control.zoom({ position: 'bottomright' }).addTo(map);

      markersLayer.current = L.layerGroup().addTo(map);
      mapInstance.current = map;
      renderMarkers();
    }
  }, [viewMode]);

  useEffect(() => {
    if (viewMode === 'map') renderMarkers();
  }, [filteredData, viewMode]);

  const resetForm = () => {
    setFormData({
      school_name: '', region: Region.SEOUL, address: '', lat: '', lng: '', amount_sum: '', status: 'EXISTING', proposal_range: '', industry: '반도체', proposal_types: []
    });
    setEditingId(null);
  };

  const handleAddOrUpdateData = (e: React.FormEvent) => {
    e.preventDefault();
    const payload: UniversityData = {
      school_id: editingId || `S${Date.now()}`,
      school_name: formData.school_name,
      region: formData.region,
      address: formData.address,
      lat: parseFloat(formData.lat) || 0,
      lng: parseFloat(formData.lng) || 0,
      amount_sum: parseInt(formData.amount_sum) || 0,
      status: formData.status,
      proposal_range: formData.proposal_range,
      industry: formData.industry,
      proposal_types: formData.proposal_types
    };

    if (editingId) {
      setData(prev => prev.map(item => item.school_id === editingId ? payload : item));
    } else {
      setData(prev => [...prev, payload]);
    }

    resetForm();
    setIsAdminOpen(false);
    if(viewMode === 'map') renderMarkers();
  };

  const handleDelete = (id: string) => {
    if (confirm('정말로 이 학교의 제안 데이터를 삭제하시겠습니까?')) {
      setData(prev => prev.filter(item => item.school_id !== id));
    }
  };

  const startEdit = (univ: UniversityData) => {
    setEditingId(univ.school_id);
    setFormData({
      school_name: univ.school_name,
      region: univ.region as Region,
      address: univ.address,
      lat: univ.lat.toString(),
      lng: univ.lng.toString(),
      amount_sum: univ.amount_sum.toString(),
      status: univ.status,
      proposal_range: univ.proposal_range,
      industry: univ.industry,
      proposal_types: [...univ.proposal_types]
    });
    setIsAdminOpen(true);
  };

  const totalAmount = filteredData.reduce((acc, cur) => acc + cur.amount_sum, 0);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden text-slate-900">
      <header className="h-20 flex items-center justify-between px-8 bg-white border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-6">
          <div className="flex items-center">
            <div className="flex items-center gap-3 pr-6 border-r border-slate-200">
                <img 
                  src={logoUrl} 
                  alt="모두의연구소" 
                  className="h-10 object-contain"
                  onError={(e) => {
                    (e.target as HTMLImageElement).style.display = 'none';
                  }}
                />
            </div>
            <div className="pl-6">
                <h1 className="text-lg font-black text-slate-800 tracking-tight leading-none mb-1">2026 부트캠프 전략 현황판</h1>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em]">National High-Tech Bootcamp Dashboard</p>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 bg-slate-50 p-1.5 rounded-2xl border border-slate-200 shadow-inner">
            <div className="flex flex-col px-3">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Industry</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={industryFilter}
                    onChange={(e) => setIndustryFilter(e.target.value)}
                >
                    {industries.map(ind => <option key={ind} value={ind}>{ind}</option>)}
                </select>
            </div>
            <div className="w-px h-6 bg-slate-200 mx-1"></div>
            <div className="flex flex-col px-3">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Filter Type</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={typeFilter}
                    onChange={(e) => setTypeFilter(e.target.value)}
                >
                    <option value="전체">전체 보기</option>
                    <option value="교육 제안">교육 제안 포함</option>
                    <option value="세미나 제안">세미나 제안 포함</option>
                </select>
            </div>
          </div>

          <div className="bg-slate-100 p-1 rounded-2xl flex items-center">
            <button onClick={() => setViewMode('map')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'map' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>Map</button>
            <button onClick={() => setViewMode('list')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'list' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>List</button>
          </div>

          <button 
            onClick={() => {
              if (isAdminOpen) resetForm();
              setIsAdminOpen(!isAdminOpen);
            }} 
            className={`px-6 py-2.5 rounded-2xl text-xs font-black transition-all ${isAdminOpen ? 'bg-slate-800 text-white shadow-lg' : 'bg-red-500 text-white hover:bg-red-600 shadow-lg shadow-red-100'}`}
          >
            {isAdminOpen ? '닫기' : '신규 등록'}
          </button>
        </div>
      </header>

      <main className="flex-1 relative overflow-hidden">
        <div className={`absolute inset-0 transition-opacity duration-500 ${viewMode === 'map' ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}>
          <div ref={mapContainerRef} id="map" />
        </div>

        <div className={`absolute inset-0 bg-slate-50 overflow-auto p-12 transition-opacity duration-500 ${viewMode === 'list' ? 'opacity-100 z-20' : 'opacity-0 z-0'}`}>
          <div className="max-w-7xl mx-auto">
            <div className="flex items-end justify-between mb-12">
              <div>
                <div className="flex items-center gap-3 mb-3">
                   <span className="bg-red-500 text-white text-[10px] font-black px-2.5 py-1 rounded-lg shadow-md tracking-widest uppercase">Overview</span>
                   <h2 className="text-4xl font-black text-slate-800 tracking-tighter">제안 리스트 마스터</h2>
                </div>
                <p className="text-sm text-slate-400 font-bold uppercase tracking-widest">
                  {industryFilter} 카테고리 / {typeFilter} / {filteredData.length}개 기관 분석 중
                </p>
              </div>
              <div className="bg-white p-7 rounded-[2.5rem] shadow-xl shadow-slate-200/50 border border-slate-100 text-right min-w-[280px]">
                <span className="text-[10px] text-slate-400 font-black block uppercase tracking-[0.3em] mb-2">Aggregate Total</span>
                <div className="flex items-baseline justify-end gap-1">
                  <span className="text-sm font-black text-red-400">₩</span>
                  <span className="text-4xl font-black text-slate-800 tracking-tighter">{new Intl.NumberFormat('ko-KR').format(totalAmount)}</span>
                </div>
              </div>
            </div>

            <div className="bg-white rounded-[3.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50/50 border-b border-slate-100 text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">
                  <tr>
                    <th className="px-10 py-7">제안 유형</th>
                    <th className="px-6 py-7">산업분야</th>
                    <th className="px-6 py-7">권역</th>
                    <th className="px-6 py-7">학교명</th>
                    <th className="px-6 py-7">참여 기업</th>
                    <th className="px-6 py-7 text-right">예상 금액</th>
                    <th className="px-10 py-7 text-center">관리</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredData.map((univ) => (
                    <tr key={univ.school_id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-10 py-7">
                        <div className="flex flex-wrap gap-1.5">
                          {univ.proposal_types?.map(t => (
                            <span key={t} className={`text-[9px] font-black px-2.5 py-1 rounded-lg shadow-sm border ${
                                t === '교육 제안' 
                                ? 'bg-blue-50 text-blue-600 border-blue-100' 
                                : 'bg-purple-50 text-purple-600 border-purple-100'
                            }`}>
                                {t}
                            </span>
                          ))}
                        </div>
                      </td>
                      <td className="px-6 py-7">
                        <span className="text-[10px] font-black text-slate-500 bg-white border border-slate-200 px-2.5 py-1.5 rounded-xl shadow-sm">{univ.industry}</span>
                      </td>
                      <td className="px-6 py-7">
                        <div className="flex items-center gap-3">
                          <span className="w-3.5 h-3.5 rounded-full shadow-inner ring-4 ring-white" style={{backgroundColor: REGION_COLORS[univ.region] || '#cbd5e1'}}></span>
                          <span className="text-xs font-black text-slate-600">{univ.region}</span>
                        </div>
                      </td>
                      <td className="px-6 py-7">
                        <div className="text-sm font-black text-slate-800 flex items-center gap-2">
                          {univ.school_name}
                          {univ.status === 'NEW' && <span className="h-2 w-2 rounded-full bg-red-500 animate-pulse"></span>}
                        </div>
                      </td>
                      <td className="px-6 py-7">
                        <div className="flex items-center gap-2">
                          <span className="text-xs font-bold text-slate-500 truncate max-w-[160px]">{univ.proposal_range}</span>
                          {univ.proposal_range.includes('모두의연구소') && <img src={logoUrl} className="h-3 object-contain" alt="Modu" />}
                        </div>
                      </td>
                      <td className="px-6 py-7 text-right font-black text-sm">{formatCurrency(univ.amount_sum)}</td>
                      <td className="px-10 py-7 text-center">
                        <div className="flex gap-2 justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => startEdit(univ)} className="p-2 bg-slate-100 rounded-lg hover:bg-slate-200"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg></button>
                          <button onClick={() => handleDelete(univ.school_id)} className="p-2 bg-red-50 text-red-500 rounded-lg hover:bg-red-100"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {isAdminOpen && (
          <div className="absolute inset-0 z-[2000] flex items-center justify-center p-6 bg-slate-900/10 backdrop-blur-md pointer-events-none">
            <div className="glass p-12 rounded-[3.5rem] shadow-2xl border border-white/80 w-[520px] pointer-events-auto animate-in zoom-in-95 duration-300">
              <div className="flex items-center justify-between mb-10">
                <h3 className="text-3xl font-black text-slate-800">{editingId ? '제안 수정' : '신규 학교 등록'}</h3>
                <button onClick={() => { resetForm(); setIsAdminOpen(false); }} className="p-3 bg-slate-100 rounded-2xl text-slate-400 hover:text-slate-600 transition-all"><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg></button>
              </div>

              <form onSubmit={handleAddOrUpdateData} className="space-y-7">
                <div className="space-y-5">
                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">기관명</label>
                        <input required placeholder="학교명을 입력하세요" className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none focus:ring-4 focus:ring-red-500/10" value={formData.school_name} onChange={e => handleSchoolNameChange(e.target.value)} />
                    </div>
                    <div className="grid grid-cols-2 gap-5">
                        <div className="space-y-2">
                            <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">산업 분야</label>
                            <select className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none" value={formData.industry} onChange={e => setFormData({...formData, industry: e.target.value})}>
                                {industries.filter(i => i !== '전체').map(i => <option key={i} value={i}>{i}</option>)}
                            </select>
                        </div>
                        <div className="space-y-2">
                            <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">권역</label>
                            <select className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none" value={formData.region} onChange={e => setFormData({...formData, region: e.target.value as Region})}>
                                {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                            </select>
                        </div>
                    </div>
                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">제안 유형</label>
                        <div className="flex gap-3">
                          {proposalTypesOptions.map(t => (
                            <button key={t} type="button" onClick={() => toggleProposalType(t)} className={`flex-1 py-4 rounded-2xl text-xs font-black border transition-all ${formData.proposal_types.includes(t) ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-400 border-slate-100'}`}>{t}</button>
                          ))}
                        </div>
                    </div>
                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">참여 기업 및 범위</label>
                        <input required placeholder="예: 모두의연구소 협력 제안" className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
                    </div>
                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">예상 금액 (₩)</label>
                        <input required type="number" placeholder="금액 입력" className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none" value={formData.amount_sum} onChange={e => setFormData({...formData, amount_sum: e.target.value})} />
                    </div>
                </div>
                <div className="pt-8 flex gap-4">
                  <button type="button" onClick={() => { resetForm(); setIsAdminOpen(false); }} className="flex-1 bg-slate-100 text-slate-600 py-5 rounded-[1.75rem] text-sm font-black">취소</button>
                  <button type="submit" className="flex-[2] bg-red-500 text-white py-5 rounded-[1.75rem] text-sm font-black shadow-lg">저장 및 업데이트</button>
                </div>
              </form>
            </div>
          </div>
        )}

        {viewMode === 'map' && (
          <div className="absolute bottom-12 right-12 z-[1000]">
            <div className="glass p-8 rounded-[3rem] shadow-2xl w-64 border border-white/80">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-6 border-b border-slate-100 pb-4">Region Legend</h3>
              <div className="grid grid-cols-1 gap-4">
                {Object.entries(REGION_COLORS).map(([name, color]) => (
                  <div key={name} className="flex items-center gap-4">
                    <span className="w-4 h-4 rounded-full shadow-inner ring-4 ring-white" style={{ backgroundColor: color }}></span>
                    <span className="text-[11px] font-black text-slate-600">{name}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS, UNIVERSITY_PRESETS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  // 로컬 스토리지에서 데이터 로드 또는 기본값 사용
  const [data, setData] = useState<UniversityData[]>(() => {
    const saved = localStorage.getItem('univ_dashboard_data');
    return saved ? JSON.parse(saved) : MOCK_DATA;
  });

  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [industryFilter, setIndustryFilter] = useState<string>('전체');
  const [typeFilter, setTypeFilter] = useState<string>('전체');

  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SEOUL,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'EXISTING' as 'NEW' | 'EXISTING',
    proposal_range: '',
    industry: '반도체',
    proposal_types: [] as ('교육 제안' | '세미나 제안')[]
  });

  const industries = ['전체', '반도체', '이차전지', '바이오', '디스플레이', '항공우주', '미래차', '인공지능'];
  const proposalTypesOptions = ['교육 제안', '세미나 제안'] as const;
  const logoUrl = "https://modulabs.co.kr/wp-content/uploads/2023/10/logo_red_vertical.png";

  // 데이터 변경 시 로컬 스토리지에 자동 저장
  useEffect(() => {
    localStorage.setItem('univ_dashboard_data', JSON.stringify(data));
  }, [data]);

  const handleSchoolNameChange = (name: string) => {
    setFormData(prev => ({ ...prev, school_name: name }));
    const preset = UNIVERSITY_PRESETS[name];
    if (preset) {
      setFormData(prev => ({
        ...prev,
        school_name: name,
        region: preset.region,
        lat: preset.lat.toString(),
        lng: preset.lng.toString(),
        address: preset.address
      }));
    }
  };

  const toggleProposalType = (type: '교육 제안' | '세미나 제안') => {
    setFormData(prev => {
      const isExist = prev.proposal_types.includes(type);
      if (isExist) {
        return { ...prev, proposal_types: prev.proposal_types.filter(t => t !== type) };
      } else {
        return { ...prev, proposal_types: [...prev.proposal_types, type] };
      }
    });
  };

  const formatCurrency = (amount: number) => {
    if (amount === 0) return "금액 미정";
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const filteredData = data.filter(item => 
    (industryFilter === '전체' || item.industry === industryFilter) &&
    (typeFilter === '전체' || (item.proposal_types && item.proposal_types.includes(typeFilter as any)))
  );

  const calculateRadius = (amount: number) => {
    if (amount === 0) return 12;
    const logValue = Math.log10(amount || 1);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const renderMarkers = () => {
    if (!mapInstance.current || !markersLayer.current || viewMode !== 'map') return;

    markersLayer.current.clearLayers();

    filteredData.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS[Region.ETC];
      const radius = calculateRadius(univ.amount_sum);
      const isNew = univ.status === 'NEW';
      const isModu = univ.proposal_range.includes('모두의연구소');

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: isModu ? '#ef4444' : (isNew ? '#ffffff' : color),
        weight: isModu ? 4 : (isNew ? 3 : 1.5),
        dashArray: isNew ? '5, 5' : null,
        opacity: 1,
        fillOpacity: 0.6
      });

      const typeBadges = univ.proposal_types && univ.proposal_types.length > 0 
        ? univ.proposal_types.map(t => 
            `<span style="font-size: 8px; font-weight: 800; background: ${t === '교육 제안' ? '#2563EB' : '#7C3AED'}; color: white; padding: 1px 4px; border-radius: 4px; margin-left: 2px;">${t}</span>`
          ).join('')
        : `<span style="font-size: 8px; font-weight: 800; background: #94a3b8; color: white; padding: 1px 4px; border-radius: 4px;">유형 미정</span>`;

      const moduTextBadge = isModu ? `<span style="font-size: 8px; font-weight: 800; background: #ef4444; color: white; padding: 1px 4px; border-radius: 4px; margin-left: 4px;">MODU</span>` : '';

      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
            <span style="font-size: 9px; color: ${color}; font-weight: 800; border: 1px solid ${color}; padding: 1px 4px; border-radius: 4px;">${univ.industry}</span>
            <div style="display: flex; align-items: center;">${typeBadges}${moduTextBadge}</div>
          </div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 2px;">${univ.school_name}</div>
          <div style="font-size: 10px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
          <div style="background: #f8fafc; padding: 8px; border-radius: 6px; margin-bottom: 8px;">
            <div style="font-size: 8px; color: #94a3b8; font-weight: 800; text-transform: uppercase;">참여 기업 / 범위</div>
            <div style="font-size: 11px; color: #334155; font-weight: 600;">${univ.proposal_range}</div>
          </div>
          <div style="border-top: 1px solid #f1f5f9; padding-top: 6px;">
            <div style="font-size: 14px; font-weight: 800; color: ${univ.amount_sum === 0 ? '#94a3b8' : color};">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, { closeButton: false }).addTo(markersLayer.current);
    });
  };

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current && !mapInstance.current) {
      const map = L.map(mapContainerRef.current, {
        center: [36.2, 127.8],
        zoom: 7.5,
        zoomControl: false
      });

      // 구글 한글 지도 + 모노톤 스타일링 적용 (apistyle 파라미터 활용)
      // s=Galileo는 구글의 모노톤 계열 렌더링을 유도합니다.
      L.tileLayer('https://mt1.google.com/vt/lyrs=m&hl=ko&gl=kr&x={x}&y={y}&z={z}&apistyle=s.t:1|s.e:l|p.v:on,s.t:131073|p.v:off,s.t:2|p.v:off,s.t:4|p.v:off,s.t:3|p.v:off,s.t:6|p.v:off,s.t:5|p.v:off', {
        attribution: '&copy; Google Maps'
      }).addTo(map);

      L.control.zoom({ position: 'bottomright' }).addTo(map);

      markersLayer.current = L.layerGroup().addTo(map);
      mapInstance.current = map;
      renderMarkers();
    }
  }, [viewMode]);

  useEffect(() => {
    if (viewMode === 'map') renderMarkers();
  }, [filteredData, viewMode]);

  const resetForm = () => {
    setFormData({
      school_name: '', region: Region.SEOUL, address: '', lat: '', lng: '', amount_sum: '', status: 'EXISTING', proposal_range: '', industry: '반도체', proposal_types: []
    });
    setEditingId(null);
  };

  const handleAddOrUpdateData = (e: React.FormEvent) => {
    e.preventDefault();
    const payload: UniversityData = {
      school_id: editingId || `S${Date.now()}`,
      school_name: formData.school_name,
      region: formData.region,
      address: formData.address,
      lat: parseFloat(formData.lat) || 0,
      lng: parseFloat(formData.lng) || 0,
      amount_sum: parseInt(formData.amount_sum) || 0,
      status: formData.status,
      proposal_range: formData.proposal_range,
      industry: formData.industry,
      proposal_types: formData.proposal_types
    };

    if (editingId) {
      setData(prev => prev.map(item => item.school_id === editingId ? payload : item));
    } else {
      setData(prev => [...prev, payload]);
    }

    resetForm();
    setIsAdminOpen(false);
    if(viewMode === 'map') renderMarkers();
  };

  const handleDelete = (id: string) => {
    if (confirm('정말로 이 학교의 제안 데이터를 삭제하시겠습니까?')) {
      setData(prev => prev.filter(item => item.school_id !== id));
    }
  };

  const startEdit = (univ: UniversityData) => {
    setEditingId(univ.school_id);
    setFormData({
      school_name: univ.school_name,
      region: univ.region as Region,
      address: univ.address,
      lat: univ.lat.toString(),
      lng: univ.lng.toString(),
      amount_sum: univ.amount_sum.toString(),
      status: univ.status,
      proposal_range: univ.proposal_range,
      industry: univ.industry,
      proposal_types: [...univ.proposal_types]
    });
    setIsAdminOpen(true);
  };

  const totalAmount = filteredData.reduce((acc, cur) => acc + cur.amount_sum, 0);

  return (
    <div className="flex flex-col h-screen w-full bg-slate-50 font-sans overflow-hidden text-slate-900">
      <header className="h-20 flex items-center justify-between px-8 bg-white border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-6">
          <div className="flex items-center">
            <div className="flex items-center gap-3 pr-6 border-r border-slate-200">
                <img 
                  src={logoUrl} 
                  alt="모두의연구소" 
                  className="h-10 object-contain"
                  onError={(e) => {
                    (e.target as HTMLImageElement).style.display = 'none';
                  }}
                />
            </div>
            <div className="pl-6">
                <h1 className="text-lg font-black text-slate-800 tracking-tight leading-none mb-1">2026 부트캠프 전략 현황판</h1>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em]">National High-Tech Bootcamp Dashboard</p>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 bg-slate-50 p-1.5 rounded-2xl border border-slate-200 shadow-inner">
            <div className="flex flex-col px-3">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Industry</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={industryFilter}
                    onChange={(e) => setIndustryFilter(e.target.value)}
                >
                    {industries.map(ind => <option key={ind} value={ind}>{ind}</option>)}
                </select>
            </div>
            <div className="w-px h-6 bg-slate-200 mx-1"></div>
            <div className="flex flex-col px-3">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Filter Type</span>
                <select 
                    className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer"
                    value={typeFilter}
                    onChange={(e) => setTypeFilter(e.target.value)}
                >
                    <option value="전체">전체 보기</option>
                    <option value="교육 제안">교육 제안 포함</option>
                    <option value="세미나 제안">세미나 제안 포함</option>
                </select>
            </div>
          </div>

          <div className="bg-slate-100 p-1 rounded-2xl flex items-center">
            <button onClick={() => setViewMode('map')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'map' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>Map</button>
            <button onClick={() => setViewMode('list')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'list' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>List</button>
          </div>

          <button 
            onClick={() => {
              if (isAdminOpen) resetForm();
              setIsAdminOpen(!isAdminOpen);
            }} 
            className={`px-6 py-2.5 rounded-2xl text-xs font-black transition-all ${isAdminOpen ? 'bg-slate-800 text-white shadow-lg' : 'bg-red-500 text-white hover:bg-red-600 shadow-lg shadow-red-100'}`}
          >
            {isAdminOpen ? '닫기' : '신규 등록'}
          </button>
        </div>
      </header>

      <main className="flex-1 relative overflow-hidden">
        <div className={`absolute inset-0 transition-opacity duration-500 ${viewMode === 'map' ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}>
          <div ref={mapContainerRef} id="map" />
        </div>

        <div className={`absolute inset-0 bg-slate-50 overflow-auto p-12 transition-opacity duration-500 ${viewMode === 'list' ? 'opacity-100 z-20' : 'opacity-0 z-0'}`}>
          <div className="max-w-7xl mx-auto">
            <div className="flex items-end justify-between mb-12">
              <div>
                <div className="flex items-center gap-3 mb-3">
                   <span className="bg-red-500 text-white text-[10px] font-black px-2.5 py-1 rounded-lg shadow-md tracking-widest uppercase">Overview</span>
                   <h2 className="text-4xl font-black text-slate-800 tracking-tighter">제안 리스트 마스터</h2>
                </div>
                <p className="text-sm text-slate-400 font-bold uppercase tracking-widest">
                  {industryFilter} 카테고리 / {typeFilter} / {filteredData.length}개 기관 분석 중
                </p>
              </div>
              <div className="bg-white p-7 rounded-[2.5rem] shadow-xl shadow-slate-200/50 border border-slate-100 text-right min-w-[280px]">
                <span className="text-[10px] text-slate-400 font-black block uppercase tracking-[0.3em] mb-2">Aggregate Total</span>
                <div className="flex items-baseline justify-end gap-1">
                  <span className="text-sm font-black text-red-400">₩</span>
                  <span className="text-4xl font-black text-slate-800 tracking-tighter">{new Intl.NumberFormat('ko-KR').format(totalAmount)}</span>
                </div>
              </div>
            </div>

            <div className="bg-white rounded-[3.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50/50 border-b border-slate-100 text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">
                  <tr>
                    <th className="px-10 py-7">제안 유형</th>
                    <th className="px-6 py-7">산업분야</th>
                    <th className="px-6 py-7">권역</th>
                    <th className="px-6 py-7">학교명</th>
                    <th className="px-6 py-7">참여 기업</th>
                    <th className="px-6 py-7 text-right">예상 금액</th>
                    <th className="px-10 py-7 text-center">관리</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredData.map((univ) => (
                    <tr key={univ.school_id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-10 py-7">
                        <div className="flex flex-wrap gap-1.5">
                          {univ.proposal_types?.map(t => (
                            <span key={t} className={`text-[9px] font-black px-2.5 py-1 rounded-lg shadow-sm border ${
                                t === '교육 제안' 
                                ? 'bg-blue-50 text-blue-600 border-blue-100' 
                                : 'bg-purple-50 text-purple-600 border-purple-100'
                            }`}>
                                {t}
                            </span>
                          ))}
                        </div>
                      </td>
                      <td className="px-6 py-7">
                        <span className="text-[10px] font-black text-slate-500 bg-white border border-slate-200 px-2.5 py-1.5 rounded-xl shadow-sm">{univ.industry}</span>
                      </td>
                      <td className="px-6 py-7">
                        <div className="flex items-center gap-3">
                          <span className="w-3.5 h-3.5 rounded-full shadow-inner ring-4 ring-white" style={{backgroundColor: REGION_COLORS[univ.region] || '#cbd5e1'}}></span>
                          <span className="text-xs font-black text-slate-600">{univ.region}</span>
                        </div>
                      </td>
                      <td className="px-6 py-7">
                        <div className="text-sm font-black text-slate-800 flex items-center gap-2">
                          {univ.school_name}
                          {univ.status === 'NEW' && <span className="h-2 w-2 rounded-full bg-red-500 animate-pulse"></span>}
                        </div>
                      </td>
                      <td className="px-6 py-7">
                        <div className="flex items-center gap-2">
                          <span className="text-xs font-bold text-slate-500 truncate max-w-[160px]">{univ.proposal_range}</span>
                          {univ.proposal_range.includes('모두의연구소') && <img src={logoUrl} className="h-3 object-contain" alt="Modu" />}
                        </div>
                      </td>
                      <td className="px-6 py-7 text-right font-black text-sm">{formatCurrency(univ.amount_sum)}</td>
                      <td className="px-10 py-7 text-center">
                        <div className="flex gap-2 justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => startEdit(univ)} className="p-2 bg-slate-100 rounded-lg hover:bg-slate-200"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg></button>
                          <button onClick={() => handleDelete(univ.school_id)} className="p-2 bg-red-50 text-red-500 rounded-lg hover:bg-red-100"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {isAdminOpen && (
          <div className="absolute inset-0 z-[2000] flex items-center justify-center p-6 bg-slate-900/10 backdrop-blur-md pointer-events-none">
            <div className="glass p-12 rounded-[3.5rem] shadow-2xl border border-white/80 w-[520px] pointer-events-auto animate-in zoom-in-95 duration-300">
              <div className="flex items-center justify-between mb-10">
                <h3 className="text-3xl font-black text-slate-800">{editingId ? '제안 수정' : '신규 학교 등록'}</h3>
                <button onClick={() => { resetForm(); setIsAdminOpen(false); }} className="p-3 bg-slate-100 rounded-2xl text-slate-400 hover:text-slate-600 transition-all"><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg></button>
              </div>

              <form onSubmit={handleAddOrUpdateData} className="space-y-7">
                <div className="space-y-5">
                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">기관명</label>
                        <input required placeholder="학교명을 입력하세요" className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none focus:ring-4 focus:ring-red-500/10" value={formData.school_name} onChange={e => handleSchoolNameChange(e.target.value)} />
                    </div>
                    <div className="grid grid-cols-2 gap-5">
                        <div className="space-y-2">
                            <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">산업 분야</label>
                            <select className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none" value={formData.industry} onChange={e => setFormData({...formData, industry: e.target.value})}>
                                {industries.filter(i => i !== '전체').map(i => <option key={i} value={i}>{i}</option>)}
                            </select>
                        </div>
                        <div className="space-y-2">
                            <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">권역</label>
                            <select className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none" value={formData.region} onChange={e => setFormData({...formData, region: e.target.value as Region})}>
                                {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                            </select>
                        </div>
                    </div>
                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">제안 유형</label>
                        <div className="flex gap-3">
                          {proposalTypesOptions.map(t => (
                            <button key={t} type="button" onClick={() => toggleProposalType(t)} className={`flex-1 py-4 rounded-2xl text-xs font-black border transition-all ${formData.proposal_types.includes(t) ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-400 border-slate-100'}`}>{t}</button>
                          ))}
                        </div>
                    </div>
                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">참여 기업 및 범위</label>
                        <input required placeholder="예: 모두의연구소 협력 제안" className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
                    </div>
                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-3">예상 금액 (₩)</label>
                        <input required type="number" placeholder="금액 입력" className="w-full p-5 text-sm font-bold bg-white border border-slate-200 rounded-[1.5rem] outline-none" value={formData.amount_sum} onChange={e => setFormData({...formData, amount_sum: e.target.value})} />
                    </div>
                </div>
                <div className="pt-8 flex gap-4">
                  <button type="button" onClick={() => { resetForm(); setIsAdminOpen(false); }} className="flex-1 bg-slate-100 text-slate-600 py-5 rounded-[1.75rem] text-sm font-black">취소</button>
                  <button type="submit" className="flex-[2] bg-red-500 text-white py-5 rounded-[1.75rem] text-sm font-black shadow-lg">저장 및 업데이트</button>
                </div>
              </form>
            </div>
          </div>
        )}

        {viewMode === 'map' && (
          <div className="absolute bottom-12 right-12 z-[1000]">
            <div className="glass p-8 rounded-[3rem] shadow-2xl w-64 border border-white/80">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-6 border-b border-slate-100 pb-4">Region Legend</h3>
              <div className="grid grid-cols-1 gap-4">
                {Object.entries(REGION_COLORS).map(([name, color]) => (
                  <div key={name} className="flex items-center gap-4">
                    <span className="w-4 h-4 rounded-full shadow-inner ring-4 ring-white" style={{ backgroundColor: color }}></span>
                    <span className="text-[11px] font-black text-slate-600">{name}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS, UNIVERSITY_PRESETS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  // 로컬 스토리지에서 데이터 로드 또는 기본값 사용
  const [data, setData] = useState<UniversityData[]>(() => {
    const saved = localStorage.getItem('univ_dashboard_data');
    return saved ? JSON.parse(saved) : MOCK_DATA;
  });

  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [industryFilter, setIndustryFilter] = useState<string>('전체');
  const [typeFilter, setTypeFilter] = useState<string>('전체');

  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SEOUL,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'EXISTING' as 'NEW' | 'EXISTING',
    proposal_range: '',
    industry: '반도체',
    proposal_types: [] as ('교육 제안' | '세미나 제안')[]
  });

  const industries = ['전체', '반도체', '이차전지', '바이오', '디스플레이', '항공우주', '미래차', '인공지능'];
  const proposalTypesOptions = ['교육 제안', '세미나 제안'] as const;
  const logoUrl = "https://modulabs.co.kr/wp-content/uploads/2023/10/logo_red_vertical.png";

  useEffect(() => {
    localStorage.setItem('univ_dashboard_data', JSON.stringify(data));
  }, [data]);

  const handleSchoolNameChange = (name: string) => {
    setFormData(prev => ({ ...prev, school_name: name }));
    const preset = UNIVERSITY_PRESETS[name];
    if (preset) {
      setFormData(prev => ({
        ...prev,
        school_name: name,
        region: preset.region,
        lat: preset.lat.toString(),
        lng: preset.lng.toString(),
        address: preset.address
      }));
    }
  };

  const toggleProposalType = (type: '교육 제안' | '세미나 제안') => {
    setFormData(prev => {
      const isExist = prev.proposal_types.includes(type);
      if (isExist) {
        return { ...prev, proposal_types: prev.proposal_types.filter(t => t !== type) };
      } else {
        return { ...prev, proposal_types: [...prev.proposal_types, type] };
      }
    });
  };

  const formatCurrency = (amount: number) => {
    if (amount === 0) return "금액 미정";
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
  };

  const filteredData = data.filter(item => 
    (industryFilter === '전체' || item.industry === industryFilter) &&
    (typeFilter === '전체' || (item.proposal_types && item.proposal_types.includes(typeFilter as any)))
  );

  const calculateRadius = (amount: number) => {
    if (amount === 0) return 12;
    const logValue = Math.log10(amount || 1);
    const radius = 8 + logValue * 6;
    return Math.min(Math.max(radius, 10), 45);
  };

  const renderMarkers = () => {
    if (!mapInstance.current || !markersLayer.current || viewMode !== 'map') return;

    markersLayer.current.clearLayers();

    filteredData.forEach((univ) => {
      const color = REGION_COLORS[univ.region] || REGION_COLORS[Region.ETC];
      const radius = calculateRadius(univ.amount_sum);
      const isNew = univ.status === 'NEW';
      const isModu = univ.proposal_range.includes('모두의연구소');

      const circle = L.circleMarker([univ.lat, univ.lng], {
        radius: radius,
        fillColor: color,
        color: isModu ? '#ef4444' : (isNew ? '#ffffff' : color),
        weight: isModu ? 4 : (isNew ? 3 : 1.5),
        dashArray: isNew ? '5, 5' : null,
        opacity: 1,
        fillOpacity: 0.7
      });

      const typeBadges = univ.proposal_types && univ.proposal_types.length > 0 
        ? univ.proposal_types.map(t => 
            `<span style="font-size: 8px; font-weight: 800; background: ${t === '교육 제안' ? '#2563EB' : '#7C3AED'}; color: white; padding: 1px 4px; border-radius: 4px; margin-left: 2px;">${t}</span>`
          ).join('')
        : `<span style="font-size: 8px; font-weight: 800; background: #94a3b8; color: white; padding: 1px 4px; border-radius: 4px;">유형 미정</span>`;

      const moduTextBadge = isModu ? `<span style="font-size: 8px; font-weight: 800; background: #ef4444; color: white; padding: 1px 4px; border-radius: 4px; margin-left: 4px;">MODU</span>` : '';

      const popupContent = `
        <div style="padding: 12px; font-family: 'Pretendard', sans-serif; min-width: 200px;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
            <span style="font-size: 9px; color: ${color}; font-weight: 800; border: 1px solid ${color}; padding: 1px 4px; border-radius: 4px;">${univ.industry}</span>
            <div style="display: flex; align-items: center;">${typeBadges}${moduTextBadge}</div>
          </div>
          <div style="font-size: 15px; font-weight: 700; color: #1e293b; margin-bottom: 2px;">${univ.school_name}</div>
          <div style="font-size: 10px; color: #64748b; margin-bottom: 8px;">${univ.address}</div>
          <div style="background: #f1f5f9; padding: 8px; border-radius: 6px; margin-bottom: 8px;">
            <div style="font-size: 8px; color: #94a3b8; font-weight: 800; text-transform: uppercase;">참여 기업 / 범위</div>
            <div style="font-size: 11px; color: #334155; font-weight: 600;">${univ.proposal_range}</div>
          </div>
          <div style="border-top: 1px solid #e2e8f0; padding-top: 6px;">
            <div style="font-size: 14px; font-weight: 800; color: ${univ.amount_sum === 0 ? '#94a3b8' : color};">${formatCurrency(univ.amount_sum)}</div>
          </div>
        </div>
      `;

      circle.bindPopup(popupContent, { closeButton: false }).addTo(markersLayer.current);
    });
  };

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current && !mapInstance.current) {
      // 대한민국(남한) 영역으로 제한
      const southKoreaBounds = L.latLngBounds(
        L.latLng(33.0, 124.0), // 남서쪽
        L.latLng(38.6, 132.0)  // 북동쪽 (휴전선 인근까지만)
      );

      const map = L.map(mapContainerRef.current, {
        center: [36.1, 127.8],
        zoom: 7.5,
        minZoom: 7,
        maxZoom: 12,
        maxBounds: southKoreaBounds,
        maxBoundsViscosity: 1.0,
        zoomControl: false
      });

      // Google Maps Korean Monotone 스타일 타일 레이어
      // apistyle 파라미터로 지형 채도를 낮추고 물 색상을 밝게 하여 모노톤 효과를 극대화
      const googleMonotoneUrl = 'https://mt1.google.com/vt/lyrs=m&hl=ko&gl=kr&x={x}&y={y}&z={z}&apistyle=s.t:1|s.e:l|p.v:on,s.t:131073|p.v:off,s.t:2|p.v:off,s.t:3|p.v:off,s.t:4|p.v:off,s.t:5|p.v:off,s.t:6|p.v:off,s.t:1|p.c:%23ffeeeeee,s.t:1|p.l:95,s.t:0|p.v:on|p.s:-100|p.l:20';

      L.tileLayer(googleMonotoneUrl, {
        attribution: '&copy; Google Maps'
      }).addTo(map);

      L.control.zoom({ position: 'bottomright' }).addTo(map);

      markersLayer.current = L.layerGroup().addTo(map);
      mapInstance.current = map;
      renderMarkers();
    }
  }, [viewMode]);

  useEffect(() => {
    if (viewMode === 'map') renderMarkers();
  }, [filteredData, viewMode]);

  const resetForm = () => {
    setFormData({
      school_name: '', region: Region.SEOUL, address: '', lat: '', lng: '', amount_sum: '', status: 'EXISTING', proposal_range: '', industry: '반도체', proposal_types: []
    });
    setEditingId(null);
  };

  const handleAddOrUpdateData = (e: React.FormEvent) => {
    e.preventDefault();
    const payload: UniversityData = {
      school_id: editingId || `S${Date.now()}`,
      school_name: formData.school_name,
      region: formData.region,
      address: formData.address,
      lat: parseFloat(formData.lat) || 0,
      lng: parseFloat(formData.lng) || 0,
      amount_sum: parseInt(formData.amount_sum) || 0,
      status: formData.status,
      proposal_range: formData.proposal_range,
      industry: formData.industry,
      proposal_types: formData.proposal_types
    };

    if (editingId) {
      setData(prev => prev.map(item => item.school_id === editingId ? payload : item));
    } else {
      setData(prev => [...prev, payload]);
    }

    resetForm();
    setIsAdminOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('정말로 이 학교의 제안 데이터를 삭제하시겠습니까?')) {
      setData(prev => prev.filter(item => item.school_id !== id));
    }
  };

  const startEdit = (univ: UniversityData) => {
    setEditingId(univ.school_id);
    setFormData({
      school_name: univ.school_name,
      region: univ.region as Region,
      address: univ.address,
      lat: univ.lat.toString(),
      lng: univ.lng.toString(),
      amount_sum: univ.amount_sum.toString(),
      status: univ.status,
      proposal_range: univ.proposal_range,
      industry: univ.industry,
      proposal_types: [...univ.proposal_types]
    });
    setIsAdminOpen(true);
  };

  const totalAmount = filteredData.reduce((acc, cur) => acc + cur.amount_sum, 0);

  return (
    <div className="flex flex-col h-screen w-full bg-[#f8fafc] font-sans overflow-hidden text-slate-900">
      <header className="h-20 flex items-center justify-between px-8 bg-white/80 backdrop-blur-md border-b border-slate-200 shadow-sm z-[1000] shrink-0">
        <div className="flex items-center gap-6">
          <div className="flex items-center">
            <div className="flex items-center gap-3 pr-6 border-r border-slate-200">
                <img src={logoUrl} alt="모두의연구소" className="h-10 object-contain" />
            </div>
            <div className="pl-6">
                <h1 className="text-lg font-black text-slate-800 tracking-tight leading-none mb-1">부트캠프 전략 현황판 <span className="text-red-500 ml-1">2026</span></h1>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em]">High-Tech Education Partnership Dashboard</p>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 bg-slate-100/50 p-1.5 rounded-2xl border border-slate-200 shadow-inner">
            <div className="flex flex-col px-3">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Industry</span>
                <select className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer" value={industryFilter} onChange={(e) => setIndustryFilter(e.target.value)}>
                    {industries.map(ind => <option key={ind} value={ind}>{ind}</option>)}
                </select>
            </div>
            <div className="w-px h-6 bg-slate-200 mx-1"></div>
            <div className="flex flex-col px-3">
                <span className="text-[8px] font-black text-slate-400 uppercase leading-none mb-1">Type</span>
                <select className="bg-transparent text-xs font-bold text-slate-700 outline-none cursor-pointer" value={typeFilter} onChange={(e) => setTypeFilter(e.target.value)}>
                    <option value="전체">전체 보기</option>
                    <option value="교육 제안">교육 제안</option>
                    <option value="세미나 제안">세미나 제안</option>
                </select>
            </div>
          </div>

          <div className="bg-slate-200/50 p-1 rounded-2xl flex items-center">
            <button onClick={() => setViewMode('map')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'map' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>Map</button>
            <button onClick={() => setViewMode('list')} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'list' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>List</button>
          </div>

          <button onClick={() => { if (isAdminOpen) resetForm(); setIsAdminOpen(!isAdminOpen); }} className={`px-6 py-2.5 rounded-2xl text-xs font-black transition-all ${isAdminOpen ? 'bg-slate-800 text-white shadow-lg' : 'bg-red-500 text-white hover:bg-red-600 shadow-lg shadow-red-100'}`}>
            {isAdminOpen ? '닫기' : '데이터 등록'}
          </button>
        </div>
      </header>

      <main className="flex-1 relative overflow-hidden bg-[#f0f2f5]">
        <div className={`absolute inset-0 transition-opacity duration-700 ${viewMode === 'map' ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}>
          <div ref={mapContainerRef} id="map" className="w-full h-full" />
        </div>

        <div className={`absolute inset-0 bg-slate-50 overflow-auto p-12 transition-opacity duration-700 ${viewMode === 'list' ? 'opacity-100 z-20' : 'opacity-0 z-0'}`}>
          <div className="max-w-7xl mx-auto">
            <div className="flex items-end justify-between mb-12">
              <div>
                <div className="flex items-center gap-3 mb-3">
                   <span className="bg-red-500 text-white text-[10px] font-black px-2.5 py-1 rounded-lg shadow-md tracking-widest uppercase">Overview</span>
                   <h2 className="text-4xl font-black text-slate-800 tracking-tighter">기관 제안 분석 리포트</h2>
                </div>
                <p className="text-sm text-slate-400 font-bold uppercase tracking-widest">{industryFilter} 부문 / {filteredData.length}개 기관</p>
              </div>
              <div className="bg-white p-7 rounded-[2.5rem] shadow-xl shadow-slate-200/50 border border-slate-100 text-right min-w-[280px]">
                <span className="text-[10px] text-slate-400 font-black block uppercase tracking-[0.3em] mb-2">Total Contract Value</span>
                <div className="flex items-baseline justify-end gap-1">
                  <span className="text-sm font-black text-red-400">₩</span>
                  <span className="text-4xl font-black text-slate-800 tracking-tighter">{new Intl.NumberFormat('ko-KR').format(totalAmount)}</span>
                </div>
              </div>
            </div>

            <div className="bg-white rounded-[3rem] shadow-2xl shadow-slate-200/40 border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50/50 border-b border-slate-100 text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">
                  <tr>
                    <th className="px-10 py-7">유형</th>
                    <th className="px-6 py-7">산업분야</th>
                    <th className="px-6 py-7">권역</th>
                    <th className="px-6 py-7">학교명</th>
                    <th className="px-6 py-7">협력 범위</th>
                    <th className="px-6 py-7 text-right">금액</th>
                    <th className="px-10 py-7 text-center">관리</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredData.map((univ) => (
                    <tr key={univ.school_id} className="hover:bg-slate-50/80 transition-all group">
                      <td className="px-10 py-7">
                        <div className="flex flex-wrap gap-1.5">
                          {univ.proposal_types?.map(t => (
                            <span key={t} className={`text-[9px] font-black px-2.5 py-1 rounded-lg shadow-sm border ${t === '교육 제안' ? 'bg-blue-50 text-blue-600 border-blue-100' : 'bg-purple-50 text-purple-600 border-purple-100'}`}>{t}</span>
                          ))}
                        </div>
                      </td>
                      <td className="px-6 py-7"><span className="text-[10px] font-black text-slate-500 bg-white border border-slate-200 px-2.5 py-1.5 rounded-xl">{univ.industry}</span></td>
                      <td className="px-6 py-7">
                        <div className="flex items-center gap-3">
                          <span className="w-3.5 h-3.5 rounded-full shadow-inner ring-4 ring-white" style={{backgroundColor: REGION_COLORS[univ.region] || '#cbd5e1'}}></span>
                          <span className="text-xs font-black text-slate-600">{univ.region}</span>
                        </div>
                      </td>
                      <td className="px-6 py-7"><div className="text-sm font-black text-slate-800">{univ.school_name}</div></td>
                      <td className="px-6 py-7">
                        <div className="flex items-center gap-2">
                          <span className="text-xs font-bold text-slate-500 truncate max-w-[160px]">{univ.proposal_range}</span>
                          {univ.proposal_range.includes('모두의연구소') && <span className="text-[9px] font-black bg-red-50 text-red-500 px-1.5 py-0.5 rounded border border-red-100">MODU</span>}
                        </div>
                      </td>
                      <td className="px-6 py-7 text-right font-black text-sm">{formatCurrency(univ.amount_sum)}</td>
                      <td className="px-10 py-7 text-center">
                        <div className="flex gap-2 justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => startEdit(univ)} className="p-2 bg-slate-100 rounded-lg text-slate-600 hover:bg-slate-200"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg></button>
                          <button onClick={() => handleDelete(univ.school_id)} className="p-2 bg-red-50 rounded-lg text-red-500 hover:bg-red-100"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {isAdminOpen && (
          <div className="absolute inset-0 z-[2000] flex items-center justify-center p-6 bg-slate-900/10 backdrop-blur-md pointer-events-auto">
            <div className="glass p-12 rounded-[3.5rem] shadow-2xl border border-white/80 w-[520px] animate-in zoom-in-95 duration-300">
              <div className="flex items-center justify-between mb-10">
                <h3 className="text-3xl font-black text-slate-800">{editingId ? '제안 수정' : '데이터 등록'}</h3>
                <button onClick={() => { resetForm(); setIsAdminOpen(false); }} className="p-3 bg-slate-100 rounded-2xl text-slate-400 hover:text-slate-600 transition-all"><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg></button>
              </div>

              <form onSubmit={handleAddOrUpdateData} className="space-y-6">
                <div className="space-y-4">
                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">기관명</label>
                        <input required placeholder="학교명을 입력하세요 (예: 한양대)" className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none focus:ring-4 focus:ring-red-500/10" value={formData.school_name} onChange={e => handleSchoolNameChange(e.target.value)} />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">산업 분야</label>
                            <select className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none" value={formData.industry} onChange={e => setFormData({...formData, industry: e.target.value})}>
                                {industries.filter(i => i !== '전체').map(i => <option key={i} value={i}>{i}</option>)}
                            </select>
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">권역</label>
                            <select className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none" value={formData.region} onChange={e => setFormData({...formData, region: e.target.value as Region})}>
                                {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                            </select>
                        </div>
                    </div>
                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">제안 유형 (복수 선택 가능)</label>
                        <div className="flex gap-3">
                          {proposalTypesOptions.map(t => (
                            <button key={t} type="button" onClick={() => toggleProposalType(t)} className={`flex-1 py-4 rounded-2xl text-xs font-black border transition-all ${formData.proposal_types.includes(t) ? 'bg-slate-800 text-white border-slate-800 shadow-md' : 'bg-white text-slate-400 border-slate-100'}`}>{t}</button>
                          ))}
                        </div>
                    </div>
                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">협력 범위</label>
                        <input required placeholder="예: 모두의연구소 협력 제안" className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
                    </div>
                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">예상 금액 (₩)</label>
                        <input required type="number" placeholder="금액 입력" className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem] outline-none" value={formData.amount_sum} onChange={e => setFormData({...formData, amount_sum: e.target.value})} />
                    </div>
                </div>
                <div className="pt-6 flex gap-3">
                  <button type="button" onClick={() => { resetForm(); setIsAdminOpen(false); }} className="flex-1 bg-slate-100 text-slate-600 py-4 rounded-[1.5rem] text-sm font-black">취소</button>
                  <button type="submit" className="flex-[2] bg-red-500 text-white py-4 rounded-[1.5rem] text-sm font-black shadow-lg shadow-red-100">데이터 저장</button>
                </div>
              </form>
            </div>
          </div>
        )}

        {viewMode === 'map' && (
          <div className="absolute bottom-10 right-10 z-[1000]">
            <div className="glass p-7 rounded-[2.5rem] shadow-2xl w-60 border border-white/90">
              <h3 className="text-[9px] font-black text-slate-400 uppercase tracking-[0.25em] mb-5 border-b border-slate-100 pb-3">Region Map</h3>
              <div className="grid grid-cols-1 gap-3.5">
                {Object.entries(REGION_COLORS).map(([name, color]) => (
                  <div key={name} className="flex items-center gap-3">
                    <span className="w-3.5 h-3.5 rounded-full shadow-md ring-2 ring-white" style={{ backgroundColor: color }}></span>
                    <span className="text-[11px] font-black text-slate-600">{name}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { MOCK_DATA, REGION_COLORS, UNIVERSITY_PRESETS } from './constants';
import { UniversityData, Region } from './types';

declare const L: any;

type ViewMode = 'map' | 'list';

const App: React.FC = () => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const markersLayer = useRef<any>(null);

  const [data, setData] = useState<UniversityData[]>(() => {
    const saved = localStorage.getItem('univ_dashboard_data');
    return saved ? JSON.parse(saved) : MOCK_DATA;
  });

  const [viewMode, setViewMode] = useState<ViewMode>('map');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [industryFilter, setIndustryFilter] = useState<string>('전체');
  const [typeFilter, setTypeFilter] = useState<string>('전체');

  const [formData, setFormData] = useState({
    school_name: '',
    region: Region.SEOUL,
    address: '',
    lat: '',
    lng: '',
    amount_sum: '',
    status: 'EXISTING' as 'NEW' | 'EXISTING',
    proposal_range: '',
    industry: '반도체',
    proposal_types: [] as ('교육 제안' | '세미나 제안')[]
  });

  const industries = ['전체', '반도체', '이차전지', '바이오', '디스플레이', '항공우주', '미래차', '인공지능'];
  const proposalTypesOptions = ['교육 제안', '세미나 제안'] as const;
  const logoUrl = "https://modulabs.co.kr/wp-content/uploads/2023/10/logo_red_vertical.png";

  useEffect(() => {
    localStorage.setItem('univ_dashboard_data', JSON.stringify(data));
  }, [data]);

  const handleSchoolNameChange = (name: string) => {
    setFormData(prev => ({ ...prev, school_name: name }));
    const preset = UNIVERSITY_PRESETS[name];
    if (preset) {
      setFormData(prev => ({
        ...prev,
        school_name: name,
        region: preset.region,
        lat: preset.lat.toString(),
        lng: preset.lng.toString(),
        address: preset.address
      }));
    }
  };

  const toggleProposalType = (type: '교육 제안' | '세미나 제안') => {
    setFormData(prev => {
      const isExist = prev.proposal_types.includes(type);
      if (isExist) {
        return { ...prev, proposal_types: prev.proposal_types.filter(t => t !== type) };
      } else {
        return { ...prev, proposal_types: [...prev.proposal_types, type] };
      }
    });
  };

  const formatCurrency = (amount: number) => {
    if (amount === 0) return "금액 미정";
    return new Intl.NumberFormat('ko-KR', {
      style: 'currency', currency: 'KRW', maximumFractionDigits: 0
    }).format(amount);
