      // lyrs=m (일반지도) + hl=ko (한글) + apistyle로 색상 채도 조절
      const monoTileUrl = 'https://mt1.google.com/vt/lyrs=m&hl=ko&gl=kr&x={x}&y={y}&z={z}&apistyle=s.t:1|p.v:on,s.t:1|p.c:%23f2f2f2,s.t:2|p.v:off,s.t:3|p.v:off,s.t:4|p.v:off,s.t:5|p.v:off,s.t:6|p.v:off,s.t:131073|p.v:off,s.t:0|p.s:-100|p.l:10';

      L.tileLayer(monoTileUrl, {
        attribution: '&copy; Google Maps'
