                    {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                  </select>
                </div>
                <input required placeholder="협력 범위" className="w-full p-4 text-sm font-bold bg-white border border-slate-200 rounded-[1.25rem]" value={formData.proposal_range} onChange={e => setFormData({...formData, proposal_range: e.target.value})} />
