        <div className={`absolute inset-0 bg-slate-50 overflow-auto p-12 transition-opacity duration-300 ${viewMode === 'list' ? 'opacity-100 z-20' : 'opacity-0 z-0'}`}>
          <div className="max-w-7xl mx-auto">
