                    <th className="px-6 py-6">학교명</th>
                    <th className="px-6 py-6">참여기업</th>
                    <th className="px-6 py-6">제안 유형</th>
                    <th className="px-6 py-6">담당자/비고</th>
                    <th className="px-6 py-6 text-right">계약금액</th>
