                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredData.map((univ) => (
                    <tr key={univ.school_id} className="hover:bg-slate-50/80 transition-colors group">
                      <td className="px-10 py-6">
                        <span className={`text-[10px] font-black px-3 py-1.5 rounded-md ${univ.status === 'NEW' ? 'bg-red-500 text-white shadow-sm' : 'bg-slate-100 text-slate-500'}`}>
