                    <span className="text-[10px] font-bold text-slate-600">{name}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>

      <style>{`
        .marker-bid-target {
          animation: bid-glow 2s infinite ease-in-out;
